/* 令和8年委員会データ（自動生成・分割ファイル） */
window.SHINAGAWA_DB.years.r08.committeeSessions.push(...[{"id":"r08-20260224-5","meetingId":"r08-1t","date":"2026年2月24日","dateIso":"2026-02-24","committee":"総務委員会","time":"午前１０時００分～午後 ４時４４分","status":"正式会議録","sourceType":"formal","overview":"総務委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を139件整理しています。","topics":[{"id":"topic-01","title":"第４０号議案、電線共同溝等工事（競馬場通り）委託契約の変更","agenda":"第４０号議案、電線共同溝等工事（競馬場通り）委託契約の変更","exchanges":[{"speaker":"西本委員","kind":"確認","question":"それと、変更金額ですけれども、それは全額は、東京都から出していただけるということなのでしょうか。確認いたします。","respondent":"森道路課長","answer":"そこを１年重複させずに、致し方あるまいということで、１年延長ということにさせていただいたところです。それは例えば２分の１だったり、１０分の５.５だったりという形になりますけれども、残りの部分については、区の負担ということになります。","id":"exchange-001"},{"speaker":"西本委員","kind":"質問・要望","question":"それと、品川区も費用を出すことになるのですか。別に品川区が要望しているわけではなくて、ないのか、そこをもう少し説明を求めました。","respondent":"森道路課長","answer":"オリンピックも１つの契機ではありますけれども、ここにつきましては、大きな目的として防災というところがあります。オリンピックも１つの契機ではありますけれども、無電柱化するための１つの大きな目的としては、区としても一定の負担が出ることになります。","id":"exchange-002"},{"speaker":"西本委員","kind":"意見","question":"ある程度の負担は必要なのかなという思いはあるものの、なんとなく、防災というのが前面に出ていない。区の負担額、どのぐらいになるのか、もう一度ご説明くださいとの意見を述べました。","respondent":"森道路課長","answer":"先ほど申しましたように、防災に寄与する路線というふうに位置づけられておりまして、当初からそういった目的があったものと認識しております。東京都と一緒に、区としても、東京都の補助を積極的に活用しながら進めているところです。","id":"exchange-003"},{"speaker":"須貝委員","kind":"意見","question":"こういうふうに平然と５割もアップしたということが数字として出てくると、非常に心配ということがあります。それだけ意見として言わせていただきましたとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"}]},{"id":"topic-02","title":"第４１号議案、（仮称）勝島人道橋上部工整備工事請負契約の変更","agenda":"第４１号議案、（仮称）勝島人道橋上部工整備工事請負契約の変更","exchanges":[{"speaker":"西本委員","kind":"質問","question":"なぜ工期が延伸になったのですか。そして、変更金額が約１億円になるので、これもなぜというところがあるので、もう少しご説明をお願いします。","respondent":"森道路課長","answer":"１つずつジャッキアップをして、実際に設置するに当たって、施工上なかなか難しいだろうというふうな想定が当初ございました。これに伴いまして、工期としても２６日延長というふうにさせていただきたいです。","id":"exchange-005"},{"speaker":"西本委員","kind":"質問","question":"後で行う工事の金額は変わらないのですか。〔「差額」と呼ぶ者あり〕。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-006"},{"speaker":"石田（ち）委員","kind":"意見","question":"この下部工事にも反対をしておりまして、まちづくりとはいえ、再開発につながるというところを危惧しておりますということで反対をしてきました。この橋をつけること自体に反対をしてきましたので、本件についても反対いたしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"}]},{"id":"topic-03","title":"第４２号議案、勝島地区雨水管整備工事請負契約の変更","agenda":"第４２号議案、勝島地区雨水管整備工事請負契約の変更","exchanges":[{"speaker":"西本委員","kind":"質問","question":"これも変更の理由というところのご説明をぜひお願いいたします。それと、契約金額がプラスになっているものについて、品川区の負担額はどうなっているかということを伺います。","respondent":"関根河川下水道課長","answer":"私から、変更の理由、それから区の負担についてご説明します。その埋設物への影響がより少ない工法に変更することといたしまして、その工法の変更に伴い、そして工事が延長となったものです。","id":"exchange-008"},{"speaker":"西本委員","kind":"質問","question":"どういうものなのかというところが分かれば、教えてほしいと思います。ただ単に工期が延びるだけですという説明でいいのか、埋設物を掘り返していくのでしょうから、それはいかがか尋ねました。","respondent":"関根河川下水道課長","answer":"そういった中で、実際に掘ったところが、やはり台帳上と位置がずれていたということが判明したものです。大井競馬場には個別にご説明をさせていただいているほか、工事の状況ですとか、そういったものは適宜ご説明をさせていただいているところです。","id":"exchange-009"},{"speaker":"西本委員","kind":"質問","question":"これはやはりずれるものなのですか。これは掘ってみないと分からないということで、そこは誤差の範囲のものなのか、そこの度合いはどのようなものか教えてほしいのですけれども。","respondent":"関根河川下水道課長","answer":"設計をさせていただいていますので、どうしても掘ってみないと分からないということは一定生じてしまうかなというふうに考えているところです。今回の工事につきましては、想定の位置から１ｍぐらい我々の造るマンホールの位置に近かったです。","id":"exchange-010"},{"speaker":"須貝委員","kind":"質問","question":"それをやったほうが安く上がるのでしょうか。では、設計変更しようという形に持っていくのか尋ねました。","respondent":"関根河川下水道課長","answer":"委員ご指摘のようなやり方もあろうかと考えていますが、一方で、工事の本数が増えていくという形になります。その結果として、一概に先にやったから必ず経済的になるかどうかというのは、なかなか断定はできないかなというふうに考えてあります。","id":"exchange-011"}]},{"id":"topic-04","title":"第４３号議案、第二戸越幹線整備工事（取水および空気抜き設備等整備）請負契約の変更","agenda":"第４３号議案、第二戸越幹線整備工事（取水および空気抜き設備等整備）請負契約の変更","exchanges":[{"speaker":"西本委員","kind":"質問","question":"申し訳ないのですけれども、変更の理由を教えてくださいということと、それと、これ、工期は変わらないのですね。開口補強ということで、新たな工事があるようになるのですけれども、このまま後期の変更なしでできるのかどうか説明を求めました。","respondent":"関根河川下水道課長","answer":"何か１つの大きなものというよりは、いろいろな項目が組み合わさっての変更と、やはり開口補強というところがあります。工期の延伸は必要ないかですが、今回の変更につきましては、工事の延長は必要ないという形で、当初の工期どおり施工ができる見込みです。","id":"exchange-012"},{"speaker":"西本委員","kind":"質問","question":"結構難しいところに下から上に上がっていくわけですから、そうなってくると、計算値と実際とかずれたりとかというようなことは生じない。結構精度が高い形でこの工法をやれているよということなのか、その辺はいかがか尋ねました。","respondent":"関根河川下水道課長","answer":"今回の変更の中でも、変更概要の３つ目の項目、変位計設置工事の追加というふうにあります。こういったいろいろな計測を活用しながら、精度よく工事を進めていくという予定にしています。","id":"exchange-013"},{"speaker":"須貝委員","kind":"質問","question":"少しお聞きしたいのですが、区としては、どのように対応しているのですか。参考までに説明を求めました。","respondent":"関根河川下水道課長","answer":"基本的に東京都下水道局のほうで積算基準というものがありますので、基本的には、それに基づいて設計を行っております。その際にも一定金額以上の材料の場合は、下水道局が行う特別調査を活用しながら、適正な発注価格になるような積算をしています。","id":"exchange-014"},{"speaker":"塚本副委員長","kind":"質問","question":"４０号議案も、４１号議案もですけれども、そういうことがあって増額になる。もう１つは、そういうことをお聞きしたいのですけれども、いかがか尋ねました。","respondent":"関根河川下水道課長","answer":"私のほうから、第４２号、第４３号の下水道関連の契約議案についてお答えさせていただければと思います。一部、事前に試験掘りを行うといったことも実施しておりますので、状況に応じて対応を検討してまいりたいというふうに考えてあります。","id":"exchange-015"},{"speaker":"塚本副委員長","kind":"質問・要望","question":"例えば、どうしても契約金額に大きな変更が起きて財源が新たに必要だとなると、場合によっては補正予算ということも手法としてはあると思うのですけれども、そういうときに充てるべき財源は、どういうところが想定されるのかということだけ最後に教えてほしいと求めました。","respondent":"加島財政課長","answer":"工事を進めている中で特殊な事情といいますか、公共施設整備基金であったり、財政調整基金のほうから一時的な財源措置を行わせていただくことになるかと思います。","id":"exchange-016"}]},{"id":"topic-05","title":"第４４号議案、鈴ケ森小学校校舎改築工事請負契約","agenda":"第４４号議案、鈴ケ森小学校校舎改築工事請負契約","exchanges":[{"speaker":"須貝委員","kind":"質問","question":"３０億円前後の予算で出来上がったと思うのですが、今はもう７６億円というような高額、こんなにかかるものなのか。応募が２者あって、１者が辞退というようなことですが、経理課としてどのようにお考えなのか尋ねました。","respondent":"荒木学校施設担当課長、佐藤経理課長","answer":"バリアフリー対応ですとか、更衣室環境の対応ですとか、以前の改築校よりも。やはり規模の面、あとは求められる性能が上がっているという面で、このように非常に大きな工事金額になっているというふうに認識しております。 その上で１者については、ここにありますけれども、配置予定技術者について配置が困難になったということで辞退いただいたという経緯だと思います。その中で辞退が出てしまうということはあり得るところだと考えておりますので…","id":"exchange-017"},{"speaker":"須貝委員","kind":"質問","question":"もう１つだけお聞きしたいのですが、空調設備工事、これは全部一緒で総額が約７６億円ということなのですか。今回は、なぜこれ一体でやったというのは、私もしばらくぶりに見るのですが、その辺についてご見解を説明を求めました。","respondent":"荒木学校施設担当課長","answer":"電気と機械の工事につきましては、これは令和８年度、来年度に、また別途、工事発注して契約する予定です。先ほども経理課長から説明があったのですけれども、業者のご要望なども鑑みて、電気と機械を後から発注して契約するという形で今回は考えてあります。","id":"exchange-018"},{"speaker":"須貝委員","kind":"質問","question":"ということは、これ、後からまた工事請負契約が、電気とか空調についても後からこれが出てくるというふうに考えていいのか尋ねました。","respondent":"荒木学校施設担当課長","answer":"委員お見込みのとおりです。令和８年度の第２回定例会での契約を目指して、今後、発注してまいります。","id":"exchange-019"},{"speaker":"須貝委員","kind":"質問・要望","question":"これは感想ですけれども、そうすると、１校当たり１００億円は超えていってしまうのでしょうね。１校当たり、１００億円を超えるのではないかと予想されるような、適正な競争になるように努めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-020"},{"speaker":"西本委員","kind":"質問","question":"１つの学校規模が、どのぐらい見積もっておけばいいのでしょうかということと、現校舎を使いながら工事をしていくのかなと思うのです。これによって、近隣との影響も出てくると思うので、その辺はどう考えられているのかというところをまず説明を求めました。","respondent":"荒木学校施設担当課長","answer":"今後の予算特別委員会でもご審査いただこうと考えていますが、令和８年度予算として、約２６.８億円で予算を組ませていただいております。南側のほうは、鈴ケ森公園がありますので、南側への圧迫感といったものも、特段、民家は存在しておりませんので…","id":"exchange-021"},{"speaker":"西本委員","kind":"質問","question":"解体が入っていないのですか、解体も入れての１００億円なのか、校庭側のほうに新しい校舎を建てるという方式なのですよね。少しは工期が縮められて、経費も抑えられるということにはならないのか尋ねました。","respondent":"荒木学校施設担当課長","answer":"説明が不足しておりました。今回、本日ご説明した資料の中の建設工事の中に解体も含まれております。 ただ、仮設校舎と申し上げても、この鈴ケ森小学校の規模からして、それこそ相当広い用地が必要になってくると考えております。ですので、今回は、既存校舎と仮設校舎を同じ敷地内に併用しながら、うまくやりくりをしていくということで…","id":"exchange-022"}]},{"id":"topic-06","title":"第４５号議案、源氏前小学校改築工事請負契約の変更","agenda":"第４５号議案、源氏前小学校改築工事請負契約の変更","exchanges":[{"speaker":"西本委員","kind":"質問","question":"今、どういう感じなのでしょうか。その辺の見通しというか、分かりますか尋ねました。","respondent":"荒木学校施設担当課長","answer":"今回、２回目の変更のより詳細な説明ですが、２点あります。古い図面を確認して、位置ですとか数量を見込んで発注はしてはいたのですけれども、その差額分を増額するという事案です。","id":"exchange-023"},{"speaker":"西本委員","kind":"質問","question":"そこを教えてほしいのと、結構掘り起こしてどうのこうのとかやらなければいけないような状況なのではないかなと思うのですけれども、それは大丈夫か尋ねました。","respondent":"荒木学校施設担当課長","answer":"今後のインフレスライドの見込みですけれども、やはりまだ資材価格の高騰、今後もインフレスライド対応が発生していくというふうに見込んです。もう１点目、こちら、地盤改良の対応ですが、今回はもともと地盤改良も当初より想定はして設計に見込んで発注はしておりました。","id":"exchange-024"},{"speaker":"西本委員","kind":"質問","question":"あそこの地域は全体的にそうなのですか。特筆してそういう面があるという形での、設計段階にいろいろ調べられていると思うのですけれども、それはどういう経緯があったのか尋ねました。","respondent":"荒木学校施設担当課長","answer":"設計段階では、先ほど、土木のほうのお話でもあったのですけれども、ボーリング調査を敷地内で何か所も実施して、地盤面の強さを測っております。それほど地盤は弱くはないのですけれども、表層の地盤だけ、これまでの学校改築の経緯の中で少し上回っていたという状況です。","id":"exchange-025"},{"speaker":"須貝委員","kind":"質問","question":"これ、受注業者、建設業者というのは、本来、事前にやはり地質調査を、そのぐらいするべきではないでしょうか。少し配慮に欠けているのではないかなと思うのですが、その辺について、ご見解を説明を求めました。","respondent":"荒木学校施設担当課長","answer":"私の説明が少し不足していた点があったのですけれども、区として、六価クロムの溶出量低減型を指定して発注をしております。ですので、発注のとおりに施工者は施工しておりますので、施工者の責ではないというふうに考えてあります。","id":"exchange-026"}]},{"id":"topic-07","title":"第１０号議案、品川区公告式条例の一部を改正する条例","agenda":"第１０号議案、品川区公告式条例の一部を改正する条例","exchanges":[{"speaker":"西本委員","kind":"質問・要望","question":"それに対して、何か意見とか、そういうことも受け取れるような状況になるのでしょうか。意見交換まで求めないのか。","respondent":"藤村総務課長","answer":"議会でご議決いただいた後に掲示板に張りつけるというような対応をとっておりましたので、今後、掲載していくという形になると思います。ホームページに掲載させていただいて、より多くの方の目に触れることができれば、目的にかなうかなと思っています。","id":"exchange-027"},{"speaker":"西本委員","kind":"質問","question":"ぜひいい機会ということもあるので、こういう仕組みになっていますよということは知ってほしいなと。広報紙は見ているものですから、見てくださいみたいな、ウェブで配置しますみたいなところをぜひお願いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-028"},{"speaker":"石田（ち）委員","kind":"質問","question":"どういうことでの公示送達、何が理由で公示送達になるのか、そもそもあるのか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-029"}]},{"id":"topic-08","title":"第１１号議案、品川区行政手続条例の一部を改正する条例","agenda":"第１１号議案、品川区行政手続条例の一部を改正する条例","exchanges":[{"speaker":"石田（ち）委員","kind":"質問・要望","question":"そういうものがどういうやり取りで、聴聞の手続のことを少し教えていただきたい、どういうものなのかということ。どう見ていくのかということを伺いたいと思います。","respondent":"藤村総務課長","answer":"２点ご質問をいただきました。パソコンの設置というところですけれども、ＰＣの設置によるいつでも閲覧できる状態をどちらか選ぶこととなっておるのですけれども、例えば。","id":"exchange-030"},{"speaker":"石田（ち）委員","kind":"質問","question":"今回、これが公示送達のみの変更ということですので、ここは賛同しがたい状況です。言わせてほしいと区民が言っているので、それが届かないということがあるのかというところを伺いたいのですけれども、それは違うのか尋ねました。","respondent":"藤村総務課長","answer":"就業先が分からないということで、送達ができないという可能性は、恐らく低いのではないかなというふうには思います。２週間、法改正もございましたので、しっかり運用していきたいというふうに考えております。","id":"exchange-031"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"示されるわけですから、いいことでも、やはり名前を出してほしくない。プライバシーの保護はあると思いますので、そこは様々、自治体でも工夫ができると思いますので、そうした配慮をしていただきたいと感じました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"},{"speaker":"松本委員","kind":"質問","question":"見たらびっくりしたのが、ほかの議会で、委員会で否決されてしまっている事案があるみたいで、多分これはやはり伝わっていなかったからだと思います。公示送達は、過去、品川区でとられたことはあるのかということはどうなのか尋ねました。","respondent":"藤村総務課長","answer":"近年の実績と申し上げているのですけれども、確認できるところであれば、聴聞に係る手続で公示送達したところは、現在、発見はできなかったということです。","id":"exchange-033"},{"speaker":"松本委員","kind":"質問","question":"もうこれは質問というよりも、むしろインターネット上で公開するというのは、きちんと知ってくださいねというレベルの話だと思うのです。それだけです。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-034"},{"speaker":"西本委員","kind":"質問","question":"２週間の掲示をして、そういう書き方をされていたと思うのですけれども、それのことを言っているのですか。それも含まれるということでいいのか尋ねました。","respondent":"藤村総務課長","answer":"公示送達という手法を用いて、２週間経過後に、そこの効力が有効に生じたということで結果を得るようなシステムになっているので。公示送達という概念で言えば、今おっしゃっていただいた支払いの督促というところと、今回申し上げている聴聞のところは同一ということです。","id":"exchange-035"},{"speaker":"西本委員","kind":"質問","question":"そうすると、それも含めて、ウェブとかを使って、それをお知らせするという手法を使われるという認識でよろしいか尋ねました。","respondent":"藤村総務課長","answer":"令和７年の第２回定例会で、法に従って条例を改正して、公示送達を電子化することが可能となるという形です。","id":"exchange-036"},{"speaker":"石田（ち）委員","kind":"意見","question":"やはり先ほども言いましたけれども、公示送達を受ける側の防御権を保障するべきだと思いますし、公示送達は、行政としても最後の手段だと思います。見ようと思えば全世界から見られてしまうという状況にもなりますので、こうしたプライバシーを配慮する観点から、今回は反対しますとの意見を述べまし…","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-037"}]},{"id":"topic-09","title":"第１２号議案、品川区長等の損害賠償責任の一部免責に関する条例の一部を改正する条例","agenda":"第１２号議案、品川区長等の損害賠償責任の一部免責に関する条例の一部を改正する条例","exchanges":[{"speaker":"西本委員","kind":"意見","question":"すみません、これについて、どういう一部免責になっていたのか。変わっていないということなので別にいいのですけれども、そもそもこれがどういうものなのかだけ、簡単に説明いただけると助かりますとの意見を述べました。","respondent":"藤村総務課長","answer":"今回、長で言えば６倍というところなので、６割免責されるという形になるという形です。〔「倍じゃないですか」と呼ぶ者あり〕 基準給与年額が定まっていて、長の場合はそれの６倍。例えば、副区長等は４倍、職員は１倍という形で、その階層に応じて負担額が異なっているという形です。","id":"exchange-038"}]},{"id":"topic-10","title":"第１３号議案、品川区職員等のハラスメントの防止等に関する条例","agenda":"第１３号議案、品川区職員等のハラスメントの防止等に関する条例","exchanges":[{"speaker":"西本委員","kind":"質問","question":"どうも私は納得いかない文言がありまして、これ、他自治体ですか。〔「そういう意味か」と呼ぶ者あり〕。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-039"},{"speaker":"西本委員","kind":"質問","question":"非公開という形になったので、今それに対する手続をとっている段階なのですけれども、アンケートの結果をどう捉えてこれになったのでしょうか。それを教えていただけますか。","respondent":"川村コンプライアンス推進担当課長","answer":"職員アンケ－トにつきましては、具体的な事案を調査したものではありませんし、ハラスメントの事実が認定されたわけではございません。今回の条例は、今後、相談があった場合のハラスメントに係る体制を強化するためにということで条例を制定するものです。","id":"exchange-040"},{"speaker":"西本委員","kind":"質問","question":"そして、今、職場の環境、区の職場の環境は、どう考えてこれを決めたのかということは、はっきり説明に入れるべきではないのでしょうか。私は、そこが納得いかないのですけれども、いかがか尋ねました。","respondent":"川村コンプライアンス推進担当課長","answer":"職員アンケートにつきましては、職員の中でハラスメントに遭ったり、以前もご議論あったような個別の事案について実施したものではございません。条例化して、しっかりとした体制を組んでいくというところで、こちらは捉えております。","id":"exchange-041"},{"speaker":"西本委員","kind":"質問","question":"あまり長く何回も繰り返し言う必要はないと思っているのですが、別紙２のところに表が入っています。この中で、今までと違うところがどうなのか、少しそこを説明してもらえますか尋ねました。","respondent":"川村コンプライアンス推進担当課長","answer":"別紙２のハラスメント苦情相談に係る対応フローについてご説明いたします。左からまいりまして２番目の相談窓口から上に分岐している矢印のほうは、これまで基本方針にございました対応フローと同じでございまして。","id":"exchange-042"},{"speaker":"西本委員","kind":"質問","question":"それから、事実の公表ですが、この事実の公表というのは、どういう公表になりますか。マスコミ報道ということを言っているのか、どういう報道を想定しているのか尋ねました。","respondent":"川村コンプライアンス推進担当課長","answer":"区長等に係る部分について説明いたします。今後、検討してまいるところですけれども、真摯に行動してまいりたいと考えております。","id":"exchange-043"},{"speaker":"西本委員","kind":"質問・要望","question":"最後に、先ほど言った相談者に対する保護の観点から、どういう保護をしていただくのでしょうか。それについての区の考え方を、説明を求めました。","respondent":"川村コンプライアンス推進担当課長","answer":"調査を望むのか、それ以外の対応を望むのかなど、相談者の意向に沿った体制を今も行っているところです。今後、調査開始時には、こういう流れで事実の公表に至る場合もあるというご理解をいただいた上での対応をしてまいりたいというふうに考えております。","id":"exchange-044"},{"speaker":"須貝委員","kind":"意見","question":"しっかり区民に公表するというようなことでもない限り、上層部に対しては何も対応できないのではないかというふうに思うのですが、その点についてご見解を説明を求めました。","respondent":"川村コンプライアンス推進担当課長","answer":"こちらは附属機関として設置いたしますので、区長への答申を経て、処分の措置が必要になってくるという制度上の流れがあります。こういった対応を内外にしっかり発信していくという目的、そこは条例の目的に反することなく、しっかりと対応してまいります。","id":"exchange-045"},{"speaker":"須貝委員","kind":"意見","question":"区長が駄目なら、区長に問題があったら副区長がやりますよ。記者会見でもやるのだとか何かというものがない限り、私は有名無実の条例ではないかというふうに思うのですが、もう一度ご見解を説明を求めました。","respondent":"川村コンプライアンス推進担当課長","answer":"須貝委員の公表に対する姿勢についての質問にお答えいたします。しっかり検討してまいりますし、公表の在り方についても、ご意見をいただけるような形で調査審議を進めていければというふうに考えております。","id":"exchange-046"},{"speaker":"須貝委員","kind":"意見","question":"最後にもう１点。ところが、行政の場合には、こういうふうに途中でとまってしまっているということは、私は、何か早く検討して修正するべきだというふうに思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-047"},{"speaker":"松本委員","kind":"質問","question":"今の公表の規定なのですけれども、他自治体の条例を調べると、公表できる条例にしているところが多いのではないかと思います。「できる」ではなくて「公表する」と、絶対にするのだというところを書いておりますので、ここの趣旨を伺えればと思います。","respondent":"川村コンプライアンス推進担当課長","answer":"松本委員ご指摘のとおり、確かに、他自治体の条例におきましては、できる規定になっているところが大半かと思います。やはり区の姿勢として、しっかり公表するという姿勢を示すために、こういった文言にしています。","id":"exchange-048"},{"speaker":"松本委員","kind":"質問","question":"この趣旨を伺いたいのと、あともう１個、結構高めの日額報酬を受けているというふうな事案もあるように思える。年に１回開催されて、何かが起きたときに設置されて報酬が発生するというふうな仕組みになっているのか、この２点を伺えればと思います。","respondent":"川村コンプライアンス推進担当課長","answer":"附属機関の報酬等について説明をいたします。相談があったときに迅速に対応できるように、あらかじめ委員を選定した上で、常設というような形を今は考えているところです。","id":"exchange-049"},{"speaker":"松本委員","kind":"質問","question":"例えば、調査委員会の事務局は常設としてあって、それで何かあったときに招集がかかって来るというふうな仕組みになるというふうな理解でよろしいか尋ねました。","respondent":"川村コンプライアンス推進担当課長","answer":"その辺、おっしゃるとおり、事案があったときに集っていただいて、調査・審議していただくような形の仕組みで考えております。","id":"exchange-050"},{"speaker":"松本委員","kind":"質問・要望","question":"例えば、ほかの委員会と言われるものだと、実際に調査員が調査に当たったものに対する日額というふうに理解していいのかお伺いしたいと思います。２週間ぐらいずっと調査して、現状、どのように考えていらっしゃるか伺いたいと思います。","respondent":"川村コンプライアンス推進担当課長","answer":"報酬の考え方についてご説明いたします。ヒアリングだったら１日当たり何人で可能だろうかとか、そういったところも含めて、この日額設定をいたしました。","id":"exchange-051"},{"speaker":"石田（ち）委員","kind":"質問","question":"そういう条例ができて、さらに安心して相談してほしいのだということを示していかないと、相談につながらないとともに被害は減らない。なので、そういうことを周知していく、広げていくためには、今まで以上に何か工夫されることがあるのかどうか、少し伺いたいと思います。","respondent":"川村コンプライアンス推進担当課長","answer":"こちら、施行日の７月１日までの期間もありますので、そこでより一層の周知に努めてまいりたいと思います。やり方につきましては、皆様、いろいろなご意見をいただきながら、今後、準備をしっかり進めていきたいと考えています。","id":"exchange-052"},{"speaker":"山本委員","kind":"質問","question":"私からも質問いたします。今回、委員会の委員長や委員をどのように選出していくか、その考え方があれば説明を求めました。","respondent":"川村コンプライアンス推進担当課長","answer":"附属機関の委員の選定についてご説明いたします。第三者性を担保することが非常に重要と認識しておりますので、弁護士につきましては、弁護士会を通じた推薦を受けるですとか。","id":"exchange-053"},{"speaker":"山本委員","kind":"質問・要望","question":"他の委員からも質問がありましたけれども、今回、そのようなご答弁がなかったことは少し残念だというふうに思いました。お考えの確認になるのですけれども、そして、ハラスメント防止に取り組んでいくというお考えでよいかということを確認させてください。","respondent":"川村コンプライアンス推進担当課長","answer":"今後の条例制定後の区の姿勢についてお答えいたします。しっかり職員からの相談に対応できるような体制をつくりたいと考えて、その姿勢を区民の方に見ていただくことで、真摯に対応してまいります。","id":"exchange-054"},{"speaker":"山本委員","kind":"質問・要望","question":"ぜひお願いいたします。ほかの委員の方からもご要望がありましたけれども、私からも要望して質問を終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-055"},{"speaker":"西本委員","kind":"確認","question":"これはあくまでも職員５名ということは、部長とか、副区長とか、区長とかが入るのですか。これ、少しイメージが、誰がやるのか尋ねました。","respondent":"川村コンプライアンス推進担当課長","answer":"苦情処理委員会についてご説明いたします。外部相談窓口として弁護士がおりますので、そういったところで専門家の知見をいただきながら公正に調査審議を進めてまいる体制になっております。","id":"exchange-056"},{"speaker":"西本委員","kind":"質問・要望","question":"これ、分かったら、職員５名と書いてあるだけで、誰々ということは書いていないのですけれども、今後入ってくるのですか。「５名以内をもって組織する」と書いてあるのですけれども、その５名は誰ぞやというのは、ここに入る形になるのか尋ねました。","respondent":"川村コンプライアンス推進担当課長","answer":"事案ごとに委員が代わるというところもありますので、委員が誰だったかというところまでは、公表の対象にはしておりません。今、確定的に申し上げられることとしては、委員長が区長室長というところになります。","id":"exchange-057"},{"speaker":"松本委員","kind":"確認","question":"大事になってくるのは、公表して、情報を公開していただいた上で、あとは我々議会側がきちんと確認していく、糾弾するべきところは糾弾していく。今後、規則もこれからつくられると思うのですけれども、規則をきちんと確認していくとかということが大事になってくるのかなと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-058"}]},{"id":"topic-11","title":"第１４号議案、品川区職員定数条例の一部を改正する条例","agenda":"第１４号議案、品川区職員定数条例の一部を改正する条例","exchanges":[{"speaker":"澤田委員","kind":"質問","question":"様々な部署で職員定数が、全体に大幅に増えている、とてもいいことだなと考えています。さらに増えていってほしいなという思いでありますけれども、なぜ減になっているのかということと、経緯などがあれば説明を求めました。","respondent":"宮尾人事課長","answer":"区では、職員が退職をした際に、その退職で生じました欠員を業務委託にて対応という大きな考え方でこの間やってあります。今回たまたま退職者が重なったということで、その分も従前の考え方にのっとりまして、業務委託にて新たに対応していくというような考え方です。","id":"exchange-059"},{"speaker":"澤田委員","kind":"確認","question":"改めて確認なのですけれども、では、その用務の方が全体として数が減ったわけではなくて、職員の方が減って、その分補ってはいるから、学校の中の業務自体は別に問題ないというか、誰かに負担が寄ったりとかということも、困ったりということもないという意味というか、形でいいのか尋ねました。","respondent":"宮尾人事課長","answer":"ただ、減った分は業務委託にてそれはしっかりと業務の質は担保していますので、業務全体への影響は基本的にはないのかなというふうに捉えております。","id":"exchange-060"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"今の澤田委員の質問に関連してですけれども、用務職が退職不補充ということで、業務委託で対応と。むしろ増やしてほしいし、委託はやめて直営にというのが共産党はずっと求めてきているところなのですけれども、やはり職員を増やしてほしい。","respondent":"宮尾人事課長","answer":"業務量が一定程度増えてきて、それが年間を通してずっと業務量の増大が見込まれるところには、しっかりと増員をさせていただいているところです。そういったところも視点もしっかりと併せ持ちながら、職員の定数については考えてまいりたいと考えています。","id":"exchange-061"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"そこが分かれば伺いたいのと、いろいろな職員増の要請等も来ると思うのですけれども、そういったことも積極的にぜひ応えていただきたいなと思います。用務のところをお願いします。","respondent":"宮尾人事課長","answer":"繰り返しになりますが、退職をしているところを不補充とさせていただいていますので、絶対数としては減るようになっていきます。担保、学校の数、園の数はしっかり担保されているものと認識しております。","id":"exchange-062"},{"speaker":"西本委員","kind":"質問","question":"主務教諭というのは何でしょうかということと、４９名ということなのですけれども、これから増やしますよという人数なのですか。４９名アップするということになると、職員費も結構になるのではないかと思うのですけれども、それがどのぐらいのレベルを考えておられるか尋ねました。","respondent":"宮尾人事課長","answer":"それから、定数外を１２０人を限度に年度内にという考え方ですが、一番分かりやすい例で言うと、育休です。ただ、最低でもやはり１人８００万円、７００万円から８００万円ぐらいは見ておく必要があるのではないかというふうにとらえております。","id":"exchange-063"},{"speaker":"西本委員","kind":"質問","question":"今は、それに当たる課長職であったり、職員の数を増やしていかないとできませんよというふうになってはいないのですか。逆に、分散化することによって人数が必要になってしまっているという現象は起きていないのか、その辺はいかがか尋ねました。","respondent":"宮尾人事課長","answer":"この定数は、職員をどのぐらい増やすかというようなことを最終的に決めるに当たっては、各部署と、人事課でヒアリングを行います。場合によっては、全てのご要望にはお答えはしていない、できていないというところもあります。","id":"exchange-064"},{"speaker":"西本委員","kind":"質問","question":"なので、これ、一番後ろの定数条例関係ということでまとめている表があるのですけれども、平成２７年度までは、マイナス５人とマイナスですよね。まだまだこれを増やしていかなければいけないということなのか、今後、どういう構造的に考えていくのか尋ねました。","respondent":"宮尾人事課長","answer":"いろいろ採用形態もありますので、そういったものをトータルで判断させていただいて、この定数を考えているところです。少なくとも急激に減っていくというような見込みは少し立てにくいのではないかなというのは、感じているところです。","id":"exchange-065"},{"speaker":"須貝委員","kind":"質問","question":"それは、そういうことに対して、今回、増員するということもあるのでしょうか。こういう方たち、業務遂行に対して不十分な方たち、区の現在の職員の中で、どれほどの人数がいらっしゃるのか、それを分かる範囲で説明を求めました。","respondent":"宮尾人事課長","answer":"こういった職員が長期に渡って休むというようなことが見込まれる場合には、例えば、別の手段を提示したりとかということもあります。指導育成はもちろんですけれども、そういった職員が１か所に偏ったりしないような、そういったものも人事異動などでも対応しています。","id":"exchange-066"},{"speaker":"須貝委員","kind":"質問","question":"１つだけ追加でお聞きしたいのは、約３０名という話ですが、これは入らないということですよね。要は、学校の先生はあくまで東京都の管轄というか、管理なので、そこはこれに入っていないということでよろしいか尋ねました。","respondent":"宮尾人事課長","answer":"先ほど私が申し上げた約３０名という数字の中には、あくまでも任命権者が区長ということなので、学校の先生、東京都の関係になってまいりますので、含まれていないというところです。","id":"exchange-067"},{"speaker":"須貝委員","kind":"質問","question":"やはり東京都の職員であろうと、やはり数字として、参考として載せるべきだと思うのです。品川区の子どもたちのために働いていらっしゃる、指導しているのですから、そういう方たちの数字も載せていただけるとありがたいなと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-068"},{"speaker":"塚本副委員長","kind":"質問","question":"４９人、２３区で一括採用して、区としてこれだけ必要なのでということが通るのかどうかということです。そこはどのような状況なのか尋ねました。","respondent":"宮尾人事課長","answer":"委員のお見込みのとおり、基本的には２３区で人事委員会を持っておりますので、そこで共通して動いていくような形になります。基本的には、職種によっては、おおむね区が採用したいという人数は採用できているという状況です。","id":"exchange-069"},{"speaker":"塚本副委員長","kind":"質問","question":"そうなのですかと、おおむね２３区全体として見ても、採用選考への応募状況について説明を求めました。","respondent":"宮尾人事課長","answer":"いろいろな対策をとって、少しでも品川区に、将来の就職の選択肢として品川区を挙げてほしいという取組をやらせていただいております。そういったことがやはり功を奏しているのではないかということは実感として持っているところです。","id":"exchange-070"},{"speaker":"山本委員","kind":"質問・要望","question":"各部署で、これで十分というか、回るというご理解で進めていらっしゃるということでいいかということを確認させていただきたいというところです。予算ベースでいうと１５億円ぐらいは減らすということで言われていて、この辺りは、どういうふうに考えられているのかということを説明を求めました。","respondent":"宮尾人事課長","answer":"今回、この人数で令和８年度しっかりと事業を遂行して、区民の皆様にご満足をいただける体制で臨んでいけるのではないかと考えております。それから、役目が終わったところからは引き揚げる、減ずるというようなことを両方しっかりと対応していきたいと考えています。","id":"exchange-071"},{"speaker":"山本委員","kind":"質問・要望","question":"塚本副委員長からも質問がありましたけれども、今、主要な業務のところは順調に対応できそうな見通しだということで安心いたしました。保育士などとおっしゃっていたのですけれども、その辺り、業種についてどういうものがあるのかを確認させていただきたいのと。","respondent":"宮尾人事課長","answer":"２３区全体のテーマなのですが、２３区全体で、こういった取組を進めているところです。","id":"exchange-072"},{"speaker":"山本委員","kind":"質問・要望","question":"そのような工夫を進めて、採用が進むことを願っております。新任の方が増えると、そういったところも考慮して組織運営を円滑に回るように進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-073"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"用務職のこともお聞きしたのですけれども、退職不補充ではなくて、直営で採用すべきと求め続けております。その用務職を減らしていくという議案には反対です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-074"}]},{"id":"topic-12","title":"第１５号議案、公益的法人等への職員の派遣等に関する条例の一部を改正する条例","agenda":"第１５号議案、公益的法人等への職員の派遣等に関する条例の一部を改正する条例","exchanges":[{"speaker":"西本委員","kind":"質問","question":"地方税共同機構へ派遣するのは、なぜなのか尋ねました。","respondent":"宮尾人事課長","answer":"地方税に関する電子手続のポータルシステムでｅＬＴＡＸというシステムがあるのですが、そのシステムを開発・運用している、そういう組織です。２３区が順番に職員を派遣しておりまして、この４月から品川区の番が来たということで、条例の改正をご提案させていただいたです。","id":"exchange-075"}]},{"id":"topic-13","title":"第１６号議案、非常勤職員の報酬および費用弁償に関する条例の一部を改正する条例","agenda":"第１６号議案、非常勤職員の報酬および費用弁償に関する条例の一部を改正する条例","exchanges":[{"speaker":"西本委員","kind":"質問","question":"報酬額が高くなるのは別にいいのですけれども、これは人事委員会勧告を踏まえということは、何かこの計算とかがあるのですか。このベースを考えるに当たって、どういうところからこれを持ってくるというものはあるのか尋ねました。","respondent":"宮尾人事課長","answer":"ばらばらにしてしまいますと、低いところになかなか人が集まりにくくなってしまうというようなことも趣旨の１つとしてはあります。ですので、今回は、これ、昨年秋の東京都の人事委員会勧告の給与改定率、これをベースに改正の額を算出しているです。","id":"exchange-076"},{"speaker":"須貝委員","kind":"意見","question":"一般の人が見たら、随分高い金額だなと思ったので、意見だけ。〔「医者だよ、医者」と呼ぶ者あり〕との意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-077"}]},{"id":"topic-14","title":"第１７号議案、職員の給与に関する条例の一部を改正する条例","agenda":"第１７号議案、職員の給与に関する条例の一部を改正する条例","exchanges":[{"speaker":"石田（ち）委員","kind":"質問・要望","question":"政令市の平均が、管理職が１０.０なのに対して、特別区は３.９しかないのです。区としては、労働組合からも求められていると思うのですけれども、そこら辺についていかがかなとお聞きしたいと思います。","respondent":"宮尾人事課長","answer":"ゆくゆく管理職をどうかと考えているような職員のところにも情報を届けて、より管理職の魅力をしっかりと伝えていきたいというふうに思っております。どんどん、きちんと連動していくような仕組みもありますし…","id":"exchange-078"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"そうすると、そちらまで昇給したくないというような職員も出てきかねないですから、そこら辺をさらに充実させるということを私も求めたいと思います。そして、その差額分は、もう出ないのか、何か対策は打たれるのかをお伺いしたいと思います。","respondent":"宮尾人事課長","answer":"この３月いっぱいで、今年度、特例の昇任選考を実施しております。本人の申込みによって昇任選考を実施するということで、今、特例の昇任をやらせていただいているところです。","id":"exchange-079"},{"speaker":"石田（ち）委員","kind":"質問","question":"分かりました。１３人ということで、自分の申請によってということだったので、それはどうなのか伺いたいと思います。","respondent":"宮尾人事課長","answer":"当然、この１３人の方たちは全て対象になります。当然ですが、選考の対象には乗ってこないという、そういう仕組みになってあります。","id":"exchange-080"},{"speaker":"西本委員","kind":"確認","question":"確認したいのですが、改正内容の（１）1)のところに、「成績優秀者に一層大きな給与上昇を確保する」と書いてある。優秀な方はやはり採用してほしいなという思いはあるのですけれども、その現状としてどうなのか、いかがか尋ねました。","respondent":"宮尾人事課長","answer":"９段階しかありませんので、普通の方ですと、昇給はしない仕組みになります。やはり優秀な人材をしっかり確保できるようにということで、それを給与面からしっかり担保しようというのが今回の改正の狙いの１つでもあります。","id":"exchange-081"},{"speaker":"西本委員","kind":"質問","question":"逆に、部下の評価を制度でやっているところがあるではないですか、民間で。部下が評価をして、評価が高いというのであれば、成績優秀とかは別にしてという評価対象にしてもいいのではないかなと思うのですが、いかがか尋ねました。","respondent":"宮尾人事課長","answer":"特別区全体で取り組むこと、その評価をつけるための訓練、こういった取組は今後もしっかりと進めてまいりたいと思います。部下の声を上司に伝えるというような取組も進めていたりしますので、しっかりと職員のやる気の醸成、今後もしっかりと進めていければと考えています。","id":"exchange-082"},{"speaker":"西本委員","kind":"質問・要望","question":"下の人たちがどう評価しているのかということは、でも、それも１つの評価になると思うのです。すごく大切な関係だと思いますので、ぜひそういう形で評価をしていただきたいとお願いして、終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-083"},{"speaker":"須貝委員","kind":"質問・要望","question":"それをＫ字型というのでしょうが、ぜひそういう一般の区民の困っている方々のことも考えて、こういう職員給与改定をしてほしいと求めました。今回のこの管理職の給与改定については、私は賛成できません。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-084"},{"speaker":"松本委員","kind":"質問","question":"４級の方で、５級の方よりも給料が高い方がどのくらいいるのかということは、データとしてありますでしょうか。お願いします。","respondent":"宮尾人事課長","answer":"今回の改正前ですと、４級と５級の重なりが、約８割あったものが、今回の改正で、それが約３割にまで減少するという改正内容になってあります。こういったところを踏まえますと、今回、少しでもこの改正によって処遇面で管理職の魅力の向上につながってくれればです。","id":"exchange-085"},{"speaker":"松本委員","kind":"質問","question":"重なりが３割になるということだと思うのですけれども、今、実際に特別区で重なっている人数がどのくらいとかというデータは出ているのでしょうか。５０歳とか６０歳ぐらいまで管理職にならないで、それはどうなのだろうというふうなことが分かっていくので、そのことだけ。","respondent":"宮尾人事課長","answer":"特別区のほうからも、そのような詳細なデータは示されていないのですが、区議会のほうから、そのようなご意見をいただいたということは、機会を捉えて発信できればと考えています。","id":"exchange-086"}]},{"id":"topic-15","title":"令和８年２月８日執行 衆議院議員選挙の結果","agenda":"令和８年２月８日執行 衆議院議員選挙の結果","exchanges":[{"speaker":"須貝委員","kind":"質問","question":"これ、経費なのですが、通常よりプレミアムがついて、多くくれるようになったのでしょうか。お金も、予算もそうですけれども、上から来ているのか尋ねました。","respondent":"今井選挙管理委員会事務局長","answer":"２３区、それはございませんでしたので、文書で執行をよろしくお願いしますというふうな通知があります。東京都が国のほうに予算要求をするのが６月頃になる予定ですので、至急検討、算出しています。","id":"exchange-087"},{"speaker":"西本委員","kind":"質問","question":"これは取締りできないのでしょうか。撤去してもらうという、それぞれの選挙事務所のほうに依頼してもいいのではないかなと思うのですけれども、それはできないのか尋ねました。","respondent":"今井選挙管理委員会事務局長","answer":"大分影響が出ましたので、こういう状況を踏まえて、国のほうでまた議論されるべきものだというふうに考えております。私どももそういう注意喚起も含めて、区民の皆様からのお声があれば、対応していくという形になろうかと思います。","id":"exchange-088"},{"speaker":"西本委員","kind":"意見","question":"投票率が高くなったので、それもすごいなと思ったのですけれども、ぜひアトレの協力はこれからも引き続きお願いしたいなと思っています。〔「俺も全部剥がしたよ」と呼ぶ者あり〕との意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-089"},{"speaker":"澤田委員","kind":"質問","question":"１点目というか、お聞きしたいのは、それを周知されているのでしょうか。〔「しているよ」と呼ぶ者あり〕。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-090"},{"speaker":"澤田委員","kind":"質問・要望","question":"していますか。看護師さんとか、いろいろな病院内の方に聞いてくださいといった案内みたいなものをしているのかということを教えていただきたいなと考えています。","respondent":"今井選挙管理委員会事務局長","answer":"説明会を開いて、いつでも投票ができるという形になっておりますので、病院の入院の方には必ず周知するように徹底しております。例えば、そういうところにつきましては、私たちも期日前期間は不在者投票指定施設にできますということの説明を徹底して。","id":"exchange-091"},{"speaker":"澤田委員","kind":"質問","question":"ポスターとかそういうものはあるのでしょうか。「この病院、やっているんだ」と分かるような、何かがあればと思うのですが。","respondent":"今井選挙管理委員会事務局長","answer":"どのように取り組まれているか、説明会などでもきちんとお話を聞いた上で、漏れがないように対応していきたいと思います。","id":"exchange-092"},{"speaker":"石田（ち）委員","kind":"質問","question":"天気も悪い中ですけれども、これだけ投票率も上がっていたなと思うところですが、本当に職員の皆さんはご苦労があっただろうなと思っています。投票入場券というのですか、１４日前になりますということで、これまで以上に多かったという印象はあるのでしょうかということと。","respondent":"今井選挙管理委員会事務局長","answer":"配布を開始していただきまして、１月２９日からの段階で配布していただきまして、とにかくお知らせしようという体制で臨んだところです。今後は、最初の声かけのときに、「少しお待たせしますけれども」というふうな声かけも含めて丁寧に当初から対応していきたいと考えています。","id":"exchange-093"}]},{"id":"topic-16","title":"第４７号議案、遺贈の放棄","agenda":"第４７号議案、遺贈の放棄","exchanges":[{"speaker":"西本委員","kind":"質問","question":"それで、現在、２階に借家人が住まわれているということですから、品川区がいただきましょうと言った場合に、この借家人はどうなるのですか。これも遺贈なので、遺贈という状況ですから、そういうことの件数はどれぐらいあるのか尋ねました。","respondent":"佐藤経理課長","answer":"１点目の、こちらの資料の３番目のところ、丁寧に説明した上で通知をお渡ししたいというふうに考えております。こちらとして、制度について説明をして、場合によってはお断りする場合もありますよということでご案内するような形です。","id":"exchange-094"},{"speaker":"西本委員","kind":"質問","question":"この遺贈という形では、相談だけで、今、何件抱えているか、何件いただくことになっているというのは、秀だけですか。どうか尋ねました。","respondent":"佐藤経理課長","answer":"経理課で把握しているところについては、特にございません。〔「今はない」と呼ぶ者あり〕 〔「ただの話だけだもの、聞いていない」と呼ぶ者あり〕","id":"exchange-095"},{"speaker":"西本委員","kind":"質問","question":"ということであるならば、今までの前例は、では、あってないようなものですか。〔「勝手にやっていることではない」と呼ぶ者あり〕。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-096"},{"speaker":"西本委員","kind":"質問","question":"だから、そういうものを含めて、私は何件あるのですかと聞いているので、もうありませんと言うのだったら、では、ないのねという理解でいますけれども、よろしいのか尋ねました。","respondent":"佐藤経理課長","answer":"もちろんこの間の議会でのやり取り等を把握しておりますので、そういった意味では、委員のおっしゃったところについては把握していますというお答えになろうかと思います。","id":"exchange-097"}]},{"id":"topic-17","title":"令和８年請願第２号、インボイス制度の見直しの意見書提出を要望する請願","agenda":"令和８年請願第２号、インボイス制度の見直しの意見書提出を要望する請願","exchanges":[{"speaker":"石田（ち）委員","kind":"質問","question":"公明党の名前が出されているということで、インボイスへの立ち位置というか、考え方は変わったということなのかということをまず教えていただけますか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-098"},{"speaker":"石田（ち）委員","kind":"質問","question":"請願の中では、「制度導入に賛成してきた政党自身が見直しの必要性に言及している」というふうに書かれているので、そこはどうなのですか。国の話かもしれないのですけれども、ご見解を伺いたいということ。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-099"},{"speaker":"塚本副委員長","kind":"意見","question":"そもそも中道改革連合が１月１６日に結党されて、この政策を、インボイスに対する政策を発表したのが１月２７日。その間に我々としての政策協議とかをしてきた経緯もないので、これは少し、公明党が考えを翻したというような認識は少し違うと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-100"},{"speaker":"石田（ち）委員","kind":"意見","question":"本当にどう理解していいのか私も分からなかったので、聞かせていただきました。公明党としては、立ち位置というか、考え方は変わっていないということでしたとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-101"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"それを３割特例にしていくような話もありますけれども、負担増にやはりなるわけですよね。見直しを求めるこの請願を採択していくべきだと思いますけれども、皆さん、いかがか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-102"},{"speaker":"澤田委員","kind":"意見","question":"本日結論を出す、不採択でお願いいたします。登録して課税事業者になれば、取得できますので、必要ないと考えますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-103"},{"speaker":"山本委員","kind":"質問・要望","question":"で、その声が政府決定に適切に反映されるよう求めていく必要があると考えております。支援制度を利用してもらうための周知や、制度の利用のしやすさも含めて、引き続き要望してまいりたいと考えております。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-104"},{"speaker":"塚本副委員長","kind":"意見","question":"基本的には、まず、原則として適切ではないと考えます。なかなか、本来のあるべき姿を損なわないでというところを十分担保した上でやらないといけないのかなと思いますので、不採択でお願いしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-105"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"このインボイス制度についての意見書を提出してほしいという請願は、本当に恥ずべき状況だなというふうに私は感じます。これにも消費税減税やインボイス廃止などを求める意見書が可決された自治体ということで、２５か所もあるということでした。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-106"},{"speaker":"須貝委員","kind":"質問・要望","question":"私も、今回、インボイス制度見直しの意見書提出を要望する請願に対しては、今回は不採択でお願いしたいと思います。皆さんの団体ではっきりと要望するほうがいいと思うし、この区議会で、こういう意見書を要望する請願を認めてくれと言われても。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-107"},{"speaker":"西本委員","kind":"意見","question":"ただ、私は以前から言っているように、品川区の現状はどうなのだということなのです。その中で、今の段階で国のほうに意見書を申し上げるまでの品川区内でのデータがないということは感想なので、今回は不採択でお願いしたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-108"}]},{"id":"topic-18","title":"令和８年陳情第２号、災害が起きても大惨事にならないために、公共施設の既存不適格を是正するよう、区に計画的に改修することを求める陳情","agenda":"令和８年陳情第２号、災害が起きても大惨事にならないために、公共施設の既存不適格を是正するよう、区に計画的に改修することを求める陳情","exchanges":[{"speaker":"石田（ち）委員","kind":"質問・要望","question":"もしこの５１基が全て完了したら、完了した率を教えていただきたいのと、大体どれくらいの期間を見ているのか伺いたいと思います。","respondent":"長尾施設整備課長","answer":"５１基を、今年度中に改修が完了する予定となっております。エレベーターの更新の年数としましては、目安としては２５年から３０年程度となっております。","id":"exchange-109"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"エレベーターの戸開走行保護装置と、２００９年以降に設置されたエレベーターは、この戸開走行保護装置の設置が義務づけられていると思うのです。区有施設のエレベーターで、この戸開走行保護装置と、地震時管制運転装置がついたものはどれぐらいあるのかということが分かれば教えていただきたい。","respondent":"長尾施設整備課長","answer":"その義務付けられた後に新しくつくられたエレベーターについては、６０基から７０基程度あります。ですので、そちらのエレベーターにつきましては、現行法にきちんと合った形で設置はされております。","id":"exchange-110"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"平成１８年６月の港区シティハイツ竹芝のシンドラー社製のエレベーターの戸開走行事故ですけれども、既存不適格だったのですよね。まず、区有施設への設置を早急に検討していただきたいと思うのですけれども、いかがか尋ねました。","respondent":"長尾施設整備課長","answer":"区有施設に設置されているエレベーターについては、順次改修を進めていくように、今後も進めていきたいと考えております。","id":"exchange-111"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"市区町村においては、速やかに制度の整備を進めることというふうにもあるのですが、国がこういうふうに言っていることは把握されているでしょうか。伺います。","respondent":"長尾施設整備課長","answer":"既存不適格の解消に対する国の補助制度については、把握しております。品川区の中では、そういった補助制度が今はないというところも確認しております。","id":"exchange-112"},{"speaker":"石田（ち）委員","kind":"質問","question":"ぜひ、この補助制度をつくっていくべきだと思うのです。国も支援するから補助制度をつくりましょうということが言われているのですけれども、なぜ品川区ではやられていないのか伺いたいと思います。","respondent":"長尾施設整備課長","answer":"施設整備課の立場でお答えしますけれども、まずは区有施設のエレベーターの改修を今後も進めていければと、区民の皆さんが使われている施設もありますので、そちらのエレベーターの安全性確保というところをさらに進めていければと考えております。","id":"exchange-113"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"国も設置するように進めているのに、それをやってこないで事故が起きたとなれば重大問題だと思いますので、ぜひそこは早急に進めるべきだと思います。区として補助制度もつくって、区有施設のエレベーター……。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-114"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"なので、戸開走行保護装置と地震時管制運転装置を設置すべきだと思います。そして、早急に、障害者施設や高齢者施設、保育施設にという思いも分かりますので、ぜひ進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-115"},{"speaker":"西本委員","kind":"意見","question":"それで、今、５１基、完了ということなのですけれども……。〔「今年やる」と呼ぶ者あり〕 〔「これから」と呼ぶ者あり〕との意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-116"},{"speaker":"西本委員","kind":"意見","question":"もう終わっています、これからやります、これからはいつまでにできますかという数字で挙げられますか。それがよく分からなくなってしまったとの意見を述べました。","respondent":"長尾施設整備課長","answer":"ですので、既存不適格が残っているものが１２０基から１３０基ぐらいの状況となっています。そのうち５０基程度が、今年度までの工事の中で改修が完了するという状況になっております。","id":"exchange-117"},{"speaker":"西本委員","kind":"質問","question":"その８０基の予定は、いつぐらい、めどが立っているのですか。どこからこれを引っ張ってきたのかなということがお分かりになっていれば教えてほしいのですけれども。","respondent":"長尾施設整備課長","answer":"既存不適格が残っているエレベーターの改修予定につきましては、具体的に何年度までに何基というような計画は、まだ今はございません。どういった工事が進められるかというようなところの調整もありますので、現状、難しい状態があります。","id":"exchange-118"},{"speaker":"西本委員","kind":"質問・要望","question":"定期検査をやっているわけですから、そこで安全性も常に確認をしている中でのことなので、そこは最低限やっていただきたいと思っています。とにかく安全に使えるようにお願いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-119"},{"speaker":"須貝委員","kind":"質問・要望","question":"いざどういうことが起きるか、今後とも、できるだけ早く進めてほしいと求めました。頑張ってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-120"},{"speaker":"山本委員","kind":"質問・要望","question":"大体１台当たりどれぐらいの金額がかかるものなのかというとことと、今、教えていただきたいというところです。当然、緊急度、早急に修繕しなければいけないというようなところまで至っているのかどうなのかというところの区の見解を確認させてください。","respondent":"長尾施設整備課長","answer":"直近で更新工事を行ったものですと、やはり数千万円かかるというところがあります。これは冒頭でご説明したように、必要な改修工事を実施して安全を確保するというところは、今後も行っていきます。","id":"exchange-121"},{"speaker":"澤田委員","kind":"確認","question":"本日結論を出す、不採択でお願いします。定期的な安全確認もされていますし、安全確保のほか、これからも区民の安全のために進めていってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-122"},{"speaker":"山本委員","kind":"質問・要望","question":"それぞれは安全体制が確認できた上でやっていらっしゃるということで、それらを考えると、区の計画に従って進めていただくのがよいのかなと思います。理事者の方の説明もありましたように、そういった意味からも、古いものから順番に適切に修繕をしていただくことを求めます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-123"},{"speaker":"塚本副委員長","kind":"意見","question":"不採択でお願いします。すべからく修繕してほしいというのは、そのとおりに進めていってもらいたいと思いますので、本陳情については不採択でお願いしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-124"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"事故を防ぐための装置の設置を国も支援しますと言っていますので、まずは区有施設のエレベーターに設置をしていくべきだと思います。そこは随時進めていただきたいと思うのですけれども、安心して利用するために、採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-125"},{"speaker":"松本委員","kind":"意見","question":"改修の必要性が高い１つの要素になり得ることは否定しませんが、実際には、安全の観点から見ていかないといけないと思います。区として適切に、順次改修を進めていただくことをお願いしつつ、本件については不採択というふうな意見を述べしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-126"},{"speaker":"須貝委員","kind":"意見","question":"本日結論を出すということと、不採択でお願いします。そういう考えていらっしゃるということで、私は、この陳情に対しては不採択でお願いしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-127"},{"speaker":"西本委員","kind":"意見","question":"先ほど質疑の中で申し上げました。とにかく安全を確保していただくという対処をぜひお願いしたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-128"}]},{"id":"topic-19","title":"令和８年陳情第１０号、シナモロール投票済証が衆議院選挙で配布されなかった説明と補填を求める陳情","agenda":"令和８年陳情第１０号、シナモロール投票済証が衆議院選挙で配布されなかった説明と補填を求める陳情","exchanges":[{"speaker":"澤田委員","kind":"質問・要望","question":"もう一度確認だけさせていただきたいのですけれども、投票済証自体は、今回、シナモロールではないですけれども、くださいという方については、いただけたのか尋ねました。","respondent":"今井選挙管理委員会事務局長","answer":"そちらの投票済証につきましては、今回、イラスト入りではないのですけれども、東京都選管がデザインをしております投票済証を活用して、ご希望の方には１人１枚交付するという形で対応しています。","id":"exchange-129"},{"speaker":"西本委員","kind":"質問","question":"認識不足で申し訳ないのですが、投票済証は、期日前投票だけですか。当日も配布か尋ねました。","respondent":"今井選挙管理委員会事務局長","answer":"こちらにつきましては、投票済証は、投票が済んだ請求があったときに交付することとしまして、期日前投票だけではなく、当日投票でも交付しているものです。","id":"exchange-130"},{"speaker":"西本委員","kind":"質問","question":"よく期日前投票ではそういうものがあるという感じがあるけれども、当日は結構あるものなのでしょうか。区としては、直接的な投票率を上げるというところまでには至っていないというものなのか、それはいかがか尋ねました。","respondent":"今井選挙管理委員会事務局長","answer":"期日前投票期間の今回の配布枚数は約９,５００枚、また、当日投票所４３か所におきましては１万８,０００枚が交付されたところです。令和４年から７回にわたりシナモロールなどを活用してきましたけれども、何らかの工夫で投票済証は作成していきたいと考えています。","id":"exchange-131"},{"speaker":"石田（ち）委員","kind":"質問","question":"私も認識不足なのですけれども、他区にも誇れる特色ある取組とおっしゃられているのですけれども、これ、他区ではあまりやられていない、キャラクターがついてということはやられていないことなのでしょうか、伺いたいと思います。","respondent":"今井選挙管理委員会事務局長","answer":"２３区の中で、大田区もキャラクターを使っていると認識しておりますが、そういう自治体は全部で１８区。全て確認しているわけではないのですけれども、そのような状況だというふうな認識をしております。","id":"exchange-132"},{"speaker":"澤田委員","kind":"意見","question":"ホームページでも周知しているということもあります。区として検討の上、デザインを決定されていると思うので、そちらもご理解ほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-133"},{"speaker":"山本委員","kind":"質問・要望","question":"投票を促進するだったり、今回の陳情者の要望である投票が終わった今、今からやるというのは合理性に欠けるのかなというところです。今後の投票済証へのご要望のところについては、ひとつのご意見として、ご要望として受け止めるということだと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-134"},{"speaker":"塚本副委員長","kind":"質問・要望","question":"不採択です。説明と補填を求めるということなのですけれども、必要性は認められないので、私としては不採択でお願いします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-135"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"なので、そこに理由を説明することは、少しやり過ぎかなというか、そこまで求めますかという感じが私はしました。なので、様々あっていいと思いますので、そこはぜひ検討しながら進めていただけたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-136"},{"speaker":"松本委員","kind":"質問・要望","question":"権利があって求めるというふうな論理構造になっていると思うのですけれども、そこまで言われてしまうのは、少し残念だというふうに思います。なので、本件については不採択というふうな意見を述べします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-137"},{"speaker":"須貝委員","kind":"意見","question":"短期間の中での選挙準備をしていました。その中において、投票済証の問題をここで言うのではなく、無事に投票が終了したこと私は称賛したいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-138"},{"speaker":"西本委員","kind":"質問・要望","question":"ここまで求められてもということがあります。ここまでは言われるほどのものではないのではないかと、少し残念な気持ちでいます。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-139"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/237549?Template=document&Id=7321#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=5&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":98720,"voices":514}},{"id":"r08-20260225-6","meetingId":"r08-1t","date":"2026年2月25日","dateIso":"2026-02-25","committee":"区民委員会","time":"午前１０時００分～午後 ２時５０分","status":"正式会議録","sourceType":"formal","overview":"区民委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を29件整理しています。","topics":[{"id":"topic-01","title":"しながわ生活応援事業の進捗報告","agenda":"しながわ生活応援事業の進捗報告","exchanges":[{"speaker":"おぎの委員","kind":"質問","question":"とにかく生活支援、基準日が令和８年１月１日になっておりまして、これは全国統一なのでしょうか。この後に品川区から出られてしまう、引っ越しをされた方も対象にされるのか尋ねました。","respondent":"今井しながわ生活応援担当課長","answer":"品川区としては令和９年１月３１日を設定しておりますし、設定しているところについては１月３１日以外の期限を設定している自治体もあります。設定の理由といたしましては、３月３１日から２か月程度の精算期間を持たせて…","id":"exchange-001"},{"speaker":"おぎの委員","kind":"質問","question":"お引っ越しされた方にも送付はされるのか尋ねました。","respondent":"今井しながわ生活応援担当課長","answer":"失礼いたしました。転居された方におきましては、転居先にギフトカードが送られることになります。","id":"exchange-002"},{"speaker":"おぎの委員","kind":"提案","question":"多言語に対応したということですが、相手先からの提案ですので何言語くらいというのは分からないとは思いますけれども。この辺、いかがか尋ねました。","respondent":"今井しながわ生活応援担当課長","answer":"今回の契約の形式ですけれども、基本的には２つに契約が分かれる予定です。２点目の多言語対応の部分ですけれども、現在プロポーザル選定作業の中で最低限の公募条件として設定しているのは、日本語プラス３言語です。","id":"exchange-003"},{"speaker":"こんの委員","kind":"質問・要望","question":"このカードを頂いて買物をしたときに、最後に端数が残ってしまうということがあるではないですか。その辺についても、配ったときに使い切り方みたいなものの周知が必要だろうと思うのですが、その辺はどういうふうにご用意をされていくのか尋ねました。","respondent":"今井しながわ生活応援担当課長","answer":"ただ、転入手続の猶予期間と言いますか、その辺は少しバッファーを持たせて対応するということも今検討していますけれども。今お話しいただいたようなＱ＆Ａの部分についても案内状に入れする予定でおります。","id":"exchange-004"},{"speaker":"こんの委員","kind":"質問・要望","question":"使用期限が翌年の１月３１日だったので、そうではないというところを確認いたしました。より詳しくお話ししていただきたいというところではあるのですが、ちなみにコールセンターは何台設置する予定か尋ねました。","respondent":"今井しながわ生活応援担当課長","answer":"カードの使用方法について、高齢者の方にも分かりやすく伝わるように案内等を工夫させていただければと思います。コールセンターの部分につきましては、事業者が決定して以降どのような体制になるのかということを改めてお示しできると思います。","id":"exchange-005"},{"speaker":"こんの委員","kind":"提案","question":"事業者の提案を待つということは理解するのですけれども、品川区としてこういう体制ですよねというのは持ち合わせていらっしゃるのではないですか。その上で、事業者の案を選定するのかと想像するのですが、その辺はそうではないということか尋ねました。","respondent":"今井しながわ生活応援担当課長","answer":"過去のしながわ活力応援給付金事業の中でコールセンターには１万６,０００件の問合せが入ったというところも事業者には説明をさせていただいて、そういった同規模の事業をやるに当たって十分な体制を取るようにということは説明会の中でお話しをさせていただいているところです。","id":"exchange-006"},{"speaker":"こんの委員","kind":"確認","question":"人数の配置もそうですが、より精度を上げたコールセンターを設置することが大事かと思ったので、まずは人数だけを確認させていただきました。区としてどう課題を捉えていて、精度を上げたコールセンターにしていこうと思っていらっしゃるのか、お考えだけ確認させてください。","respondent":"今井しながわ生活応援担当課長","answer":"現在事業者に最低限の条件としてお願いしているところは、受付時間については基本的に年末年始を除きまして対応するというところ。業務フローにつきましては、その中で最も確実な体制を組んでいただいた事業者を選定するというところで予定しています。","id":"exchange-007"},{"speaker":"こんの委員","kind":"質問・要望","question":"ぜひプロポーザルの中で、どういうふうにそれを対応されるのかというところをしっかりお聞きしながら進めてほしいと求めました。お願いいたします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-008"},{"speaker":"高橋（伸）委員","kind":"意見","question":"これからは事業者選定段階になっていきますけれども、今品川区のホームページ上で生活応援事業の周知、告知をしていますよね。しながわ生活応援担当が担当になっていて、現時点で問合せがあると思うのですけれども、今はどういう感じなのか最初にお尋ねしますとの意見を述べました。","respondent":"今井しながわ生活応援担当課長","answer":"基本的に問合せについてはコールセンター設置前ということで、しながわ生活応援担当の職員のほうで受けさせていただいているような状況です。多い質問としては春以降配布開始ということでお伝えしておりますので…","id":"exchange-009"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"事業者が決まったら、当然ホームページも更新しなければいけないではないですか。事業者が決定してからだと思うのですけれども、区としてはどういう方向性でいるのかお尋ねしたいと思います。","respondent":"今井しながわ生活応援担当課長","answer":"事業者が決まってスケジュールが確定次第、速やかに区民の方にホームページ等を通じて周知をさせていただきたいと思います。コールセンターの設置場所につきましては、基本的には事業者の用意した場所で設置していただくことになります。","id":"exchange-010"},{"speaker":"高橋（伸）委員","kind":"提案","question":"４番の簡易型プロポーザル方式により提案を受ける業務の概要の中で、誤封入は一番あってはいけないけれども、人がやることだからあり得る話です。これはお願いですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"},{"speaker":"おぎの委員","kind":"質問・要望","question":"お店の売上げにもつながりますので、お店の売上げもそうですし高齢者もしっかり使い切れるみたいなそういった形にしていただきたいです。要望です。","respondent":"今井しながわ生活応援担当課長","answer":"今回の事業を実施するに当たって、使用される方には店舗でも対応していただくようにということで所管からご説明をさせていただいているところです。発送時期が近づきましたら、改めて各商店の担当者の方や代表者の方にはご説明をさせていただきたいと考えています。","id":"exchange-012"}]},{"id":"topic-02","title":"臨海斎場増築計画の進捗","agenda":"臨海斎場増築計画の進捗","exchanges":[{"speaker":"こんの委員","kind":"質問・要望","question":"いわゆる火葬炉の機能向上というところは、どうなっているのか確認させていただきたいです。２階の平面図で、こちらは待合室のみになっていますが、新たにできるところに売店はつくらないのか尋ねました。","respondent":"築山戸籍住民課長","answer":"しかしながら、基本的には近隣への説明という形ではないのですが、大田区にある大森スポーツセンターで実施することとしたものです。もし、臨海斎場にお問合せいただければ対応するということで確認を取っているところです。","id":"exchange-013"},{"speaker":"こんの委員","kind":"確認","question":"両方、紙媒体もホームページでもより多くの方がこうした内容が分かるようにお知らせしてさしあげたらどうですかということがあります。その辺の様子を伺いたいと思います。","respondent":"築山戸籍住民課長","answer":"住民説明会の資料等につきましては、臨海斎場のホームページで掲載される予定となっておりますので。軽食の対応についてですが、火葬待合室を利用される場合はここで葬儀会社が手配をする。","id":"exchange-014"},{"speaker":"こんの委員","kind":"確認","question":"いろいろと確認させていただきました。より今ある既存のものよりも機能を強化したものがつくられていくということが必要かと思ったので細かい点を何点か確認させていただきましたが。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"おぎの委員","kind":"確認","question":"１点だけ確認させてください。今、今後は増築棟と既存棟を交互に改修して交互にお休みしてという形を取られていくという認識でよろしいか尋ねました。","respondent":"築山戸籍住民課長","answer":"既存棟につきましては、既に火葬事業を行っておりますのでこれを止めるわけにはいかないので、引き続き止めることなく運営はしていくです。増築棟に接する部分の階段の改修が必要になると聞いておりますので、接合する段階でそういった改修工事が入ってくるものだと聞いておりま…","id":"exchange-016"},{"speaker":"おぎの委員","kind":"質問","question":"接合する部分で改修工事は入ると思います。前にお聞きしたときに、それぞれの機能が独立しているので今後１０年、２０年計画で改修工事というものはそれぞれにということか尋ねました。","respondent":"築山戸籍住民課長","answer":"委員のおっしゃるとおり、増築棟と既存棟の機能をそれぞれ独立させることによって今後将来的に大規模改修が必要になった場合にどちらかを止めてどちらかを運営して、いずれにしても火葬事業は継続できるような形にすると聞いております。","id":"exchange-017"},{"speaker":"こしば委員","kind":"質問・要望","question":"意外に臨海斎場の存在が知られていない、知らないという方もいらっしゃって、まずはそこら辺の周知をぜひお願いしたいと思います。その辺の影響についてどう見込んでいるのか、教えてほしいと求めました。","respondent":"築山戸籍住民課長","answer":"なぎさ会館につきましては利用率も低下しているというところで、現在利用率が１０％台まで落ち込んでおります。増やした式場の中で十分に式はできるというところで、式場利用という面において、影響ははないと考えております。","id":"exchange-018"},{"speaker":"こしば委員","kind":"質問・要望","question":"区のほうでも、なかなかしづらいこともあるかもしれませんけれども、ぜひその辺の周知はお願いしたいと思います。告別式をやってだびに付して収骨室からご自宅に持ち帰るけれども、それが例えば午後になってくるとかそういうような捉え方でよろしいか尋ねました。","respondent":"築山戸籍住民課長","answer":"火葬の時間は、朝の早い時間帯から夕方までの時間帯、どの時間帯でも対応できるようにというふうには考えられるかと考えています。家族だけでするというケースも増えてきておりますので、今後は式を執り行う時間帯というのはもう少し変わってくるのではないかと考えております。","id":"exchange-019"},{"speaker":"こしば委員","kind":"質問","question":"こちらのほうは、料金は特にかからないというようなイメージでよろしいでしょうか。それはまた、葬祭業者との兼ね合いもあるので、違ってくるのかもしれませんけれども、その辺りを教えてほしいと求めました。","respondent":"築山戸籍住民課長","answer":"火葬待合室ですが、現在品川区民の場合ですと使う場合は２万円の使用料金を頂いております。そこはまた臨海斎場のほうで検討して、決まりましたら委員会でもご報告をさせていただきたいと考えております。","id":"exchange-020"},{"speaker":"こしば委員","kind":"意見","question":"品川区はこの臨海斎場の運営に携わってはいますが、品川区だけでは決定することはできないかもしれませんけれども、利用される方の負担を減らしていくようにお願いしたいですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-021"},{"speaker":"高橋（伸）委員","kind":"質問","question":"民間の火葬場だと超大型炉というのはどのくらいあるのですか。私は把握していないのだけれども、数がどのくらいあるのか教えてほしいです。","respondent":"築山戸籍住民課長","answer":"２３区でいきますと、町屋斎場にあると聞いております。１２０kgを超えるような大きな体型の方がお亡くなりになった場合は、町屋斎場で火葬していると聞いております。","id":"exchange-022"},{"speaker":"高橋（伸）委員","kind":"質問・要望","question":"では、今度臨海斎場にできるというのはやはり需要があるから、１か所しかないわけだから、やはり絶対に必要になってくると思います。なので、また分かり次第教えてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-023"}]},{"id":"topic-03","title":"区民葬儀における助成制度","agenda":"区民葬儀における助成制度","exchanges":[{"speaker":"こんの委員","kind":"質問・要望","question":"支給要件のところを確認させてほしいと求めました。１番は、要するに火葬券が使えないから、祭壇券あるいは霊柩車券を活用した方には火葬料金の補助をしますという理解でいいでしょうかという確認です。","respondent":"築山戸籍住民課長","answer":"次に、最も低廉という部分ですが、現在東京博善の火葬が９万円になっております。この８万７,０００円が最も低廉な火葬料金ということで考えております。","id":"exchange-024"},{"speaker":"こんの委員","kind":"確認","question":"その人たちも対象になるのかということをもう一度確認させてください。だから、一番低い火葬炉を使用された場合の金額に対してという理解でいいでしょうかということをいま一度確認させてください。","respondent":"築山戸籍住民課長","answer":"８万７,０００円が一番安い火葬料金となっておりますので、ここを利用された方ということで考えております。豪華な火葬炉を使った方ではなくやはり最低限と言いますか、一般的な火葬炉を使った方を対象とさせていただいているです。","id":"exchange-025"},{"speaker":"こんの委員","kind":"確認","question":"直葬も対象になるといったところも確認させていただきましたので、きちんと弔われるというこの体制は非常に大事なことだと思います。どうぞ。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-026"},{"speaker":"おぎの委員","kind":"質問・要望","question":"やはり公費が結果的に特定の事業者に流れるということがどうかという部分と、そういった可能性などは議論の中で言及等があったのか。もし、そういった情報等があれば教えてほしいと求めました。","respondent":"築山戸籍住民課長","answer":"理由といたしましては、そういった経済的負担を軽減する必要があるだろうという判断の下、この制度を開始するということとなりました。今回区民葬儀を脱退することによって、９万円の火葬料金を８万７,０００円に下げるということで、全体に還元をするという考えを示しています。","id":"exchange-027"},{"speaker":"おぎの委員","kind":"質問・要望","question":"助成金制度をつくりますというのは、当面の対応としては仕方がないかとは思いますが、今後さらにどうしていくのか。東京博善がまた値上げしていく部分ももちろんあるとは思いますので、引き続き色々な方法で模索してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-028"},{"speaker":"こしば委員","kind":"質問・要望","question":"例えばホームページにうちで火葬する場合にこの助成の制度を使えますといったメッセージが発信されていくのではないかということをすごく懸念してい…この辺は品川区からも自治体の権限というものが法律上ありますので、ぜひその辺はくぎを刺してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-029"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/612978?Template=document&Id=7329#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=6&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":22082,"voices":80}},{"id":"r08-20260225-7","meetingId":"r08-1t","date":"2026年2月25日","dateIso":"2026-02-25","committee":"厚生委員会","time":"午前１０時００分～午前１１時１３分","status":"正式会議録","sourceType":"formal","overview":"厚生委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を19件整理しています。","topics":[{"id":"topic-01","title":"品川区障害福祉計画・障害児福祉計画策定のための基礎調査結果報告","agenda":"品川区障害福祉計画・障害児福祉計画策定のための基礎調査結果報告","exchanges":[{"speaker":"鈴木委員","kind":"質問","question":"それから、このデータをそのまま全て委員会の資料として出していただけないかなというふうに思ったのですけれども、いかがでしょうかということです。８月のときの厚生委員会のときにはそれをまとめているところなので、その点について伺いたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-001"},{"speaker":"鈴木委員","kind":"質問・要望","question":"皆の共有、ぜひそういうご報告もいただけたらなというふうに思うのですけれども、その点も伺いたいと思います。何て言うのですか、どう区としては考えられていて、その点も伺いたいと思います。","respondent":"田中委員長、佐藤障害者施策推進課長","answer":"今回はそれを報告することができるかどうかという視点で、要はまとまっているかどうかという視点でお答えを。今のご質問に対してはこの医療的ケア児者アンケートのまとめが出せる状況にあるのかどうかという視点でのご回答とそれ以外の… 医療的ケアに関する……。","id":"exchange-002"},{"speaker":"鈴木委員","kind":"質問・要望","question":"それから、策定委員会はまだつくられていないという状況なのですか。これからつくるのか、あと、団体ヒアリングのまとめというふうなことで資料として出されてくるということになるのか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"予定では４回、１０月、それから２月ぐらいを目途に策定委員会のほうをつくっていく予定で準備をしています。１１月から１２月にかけて実施したところで、まとめているところで、これに関しても策定委員会のほうでまた報告等はする予定です。","id":"exchange-003"},{"speaker":"鈴木委員","kind":"質問・要望","question":"医療的ケア児者は全員にアンケートで聞くということでぜひしていただきたいということで、これは要望をさせていただいておきたいと思います。策定委員会にはもちろん、障害者の団体の代表の方々というのは入るということで確認させていただきたいのですけれども、その点もお願いします。","respondent":"佐藤障害者施策推進課長","answer":"資料、なるべく完全な資料、こういった状況が出ているというようなところの説明も踏まえてお出しできるような形で準備を進めてまいりたいと思います。それから、前回と同様のところを想定しておりますので…","id":"exchange-004"},{"speaker":"鈴木委員","kind":"質問","question":"私たちも団体との懇談をやるたびに、またいろいろとお話を伺うたびに、切実な要求があふれているという状況だと思うのです。何と言うのですか、今後、そういうふうなところでの分析というのもしっかりとやっていただくようにお願いをしておきたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-005"},{"speaker":"吉田委員","kind":"質問・要望","question":"それから、さらっと障害者団体の方も参加してというふうになっていましたけれども、今の障害者７団体に限るということでしょうか。それから、公募委員については、応募があって区のほうで選定されると思うのですけれども、その選定の視点があったら、教えてほしいと求めました。","respondent":"佐藤障害者施策推進課長","answer":"それから、策定委員会への部分ですけれども、まず、団体につきましては現時点では前回と同じ、こちら７団体というところは今回も予定しています。策定委員会、そのメンバー構成、それから拡充につきましては検討というところでさせていただきたいというところではあります。","id":"exchange-006"},{"speaker":"吉田委員","kind":"質問・要望","question":"そういう、もしご要望があったら受け止めていただきたいなというふうに思っております。一歩踏み込んで、やはりその方たちに影響がある計画を策定するわけですから、より広く参加を募っていただきたいというふうに思います。","respondent":"佐藤障害者施策推進課長","answer":"当事者団体のお声ですけれども、委員おっしゃるとおり、当事者の方、親の会、種別によっても様々あるかと思います。それから、先ほどの繰り返しになりますけれども、策定委員会の拡充につきましても検討というようなところではさせていただきたいと思います。","id":"exchange-007"},{"speaker":"やなぎさわ委員","kind":"質問","question":"お伺いしたいことがありまして、アンケートの８ページです。どのように認識されていらっしゃいますか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"回答者数が６４９というところで、こちら、それで介助を受けている場合には介助している方についてお答えいただくというようなところです。お母様が１人で介助されているというようなところになるのかなというようなところでこちらのほうとしては今のところ…","id":"exchange-008"},{"speaker":"やなぎさわ委員","kind":"質問","question":"私が認識できなかった。第１、第２介助者がいるという前提での回答で、特に何か把握していることはないということか尋ねました。","respondent":"佐藤障害者施策推進課長","answer":"すみません。介助されている方が６割の方、４割の方はお一人、こちらの結果については認識をしています。","id":"exchange-009"},{"speaker":"やなぎさわ委員","kind":"質問","question":"ちょっと次の質問に移るのですけれども、ある程度は、今の段階でも分析はしているということでよろしいですか。ちょっとそれを踏まえてお伺いしたいことがあるので、お伺いします。","respondent":"佐藤障害者施策推進課長","answer":"社会情勢的にこういった、例えば、施設が増えてきているのでこういう結果が減っているのかなというようなところは考えているところではあります。","id":"exchange-010"},{"speaker":"やなぎさわ委員","kind":"意見","question":"いわゆる１８歳から６４歳、もっと高くて、６０％ぐらいの方が実は働きたいなというふうに思っているというふうにこのデータだと見てとれます。現時点での区としての受け止めと言いますか、私の認識との整合性でどうかなと思うのですけれども、いかがでしょうとの意見を述べました。","respondent":"佐藤障害者施策推進課長","answer":"働くために必要なことというようなところで回答いただいたところでは、そういったところが様々ご用意できるというようなところではそういったご意向を反映させる形にできる方法なのかなというところでは認識としてはほとんどのところを持っているですので、そういった説明も今後。","id":"exchange-011"},{"speaker":"やなぎさわ委員","kind":"質問","question":"ぜひこういったところのニーズというのをしっかり捉えていっていただければというふうに思います。要は３割ぐらいの方が利用できないという困りごとがあるというか、これに対して区としての受け止めというか、何かあればお伺いしたいのですけれども。","respondent":"佐藤障害者施策推進課長","answer":"障害児というところで考えると、放課後等デイサービスの開設の助成等も行いましたけれども、サービスのリソースです。それから事業者の誘致等も踏まえてサービスの利用リソースを事業所等を増やしていくというようなところで利用したいサービスが利用できないというよ…","id":"exchange-012"},{"speaker":"鈴木委員","kind":"質問","question":"これは区としてそこをどう捉えているのかということを一点伺いたいのと、それから、２２ページのところで希望する将来の暮らし方というところで。そこを割り返すと２６４人という数字が出てくるのですけれども、その必要量の出し方についてどう考えられているのかについても伺いたいと思います。","respondent":"佐藤障害者施策推進課長","answer":"施設の整備の今後の方針等につきましては必要量、これまでのサービスの実績から今後の見込み量とかを出していっていったところですけれども。具体的な出し方につきましては、そちらの検討状況につきましてはまた計画の素案等ところで報告等させていただきたいと思います。","id":"exchange-013"},{"speaker":"鈴木委員","kind":"意見","question":"その必要量をどう出していくのかというのは世田谷区の方針とか何かを見ても、かなり、もう本当に……との意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"},{"speaker":"鈴木委員","kind":"質問・要望","question":"どうこれから必要となってくるだろうかというようなところは事業所アンケートだったりとか、そういう点もぜひよろしくお願いしたいと思います。なかなかそれが思うように使えないというふうなことも伺ったのですけれども、受皿をつくっていくのかということが求められてくると思いますので。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"}]},{"id":"topic-02","title":"国保財政健全化計画","agenda":"国保財政健全化計画","exchanges":[{"speaker":"やなぎさわ委員","kind":"質問","question":"２の計画内容のところの4)の柔道整復療養費に対する二次点検の実施というところなのですが、具体的にどういったことを実施しているのかお伺いしたいのですけれども。","respondent":"山下国保医療年金課長","answer":"柔道整復療養費に対する二次点検の実施の内容というところですけれども、他部位です。そういったものを突合してご照会をしたものについて実際に施術をされていらっしゃる事業所のほうに調査のほうを実施するといった内容です。","id":"exchange-016"},{"speaker":"やなぎさわ委員","kind":"質問","question":"ちょっと今、聞き逃して。二次点検自体が２,０００件で突合が１,４００件でよろしいか尋ねました。","respondent":"山下国保医療年金課長","answer":"被保険者の方にお送りをするような照会の調査というものが２,０００件余という形です。そちら、実際に施術をしていらっしゃる方にご照会をかけているところは１,４００件余というような状況で実施をいたしたところです。","id":"exchange-017"},{"speaker":"やなぎさわ委員","kind":"確認","question":"２,０００件が照会で、１,４００件が実際治療院に送付しているとかいう、確認を行っているという件数ということでよろしいか尋ねました。","respondent":"山下国保医療年金課長","answer":"実際に送付した件数と必ずしも一致しないかも知れないのですが、アンケートを踏まえて突合の点検を実施した件数になりまして、その後、郵送した件数というのは、すみません、手元にはちょっとございません。","id":"exchange-018"},{"speaker":"やなぎさわ委員","kind":"質問・要望","question":"イメージというか、あれば教えてほしいし、どれぐらいの削減につながっているのかなというのがもしお分かりになればお伺いしたい。もしくはいわゆる違反といいますか、返戻とかにつながるようなケースはどれぐらいあったのかみたいな、もし分かれば教えていただきたい。","respondent":"山下国保医療年金課長","answer":"こちらの実施の効果額、実態として数字化は難しい中ではありますけれども、医療費適正化というところでは資すところがあるというふうな認識です。件数で返戻といったような形につながったというところの件数も、すみません、手元にはない状況です。","id":"exchange-019"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/784410?Template=document&Id=7327#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=7&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":21906,"voices":69}},{"id":"r08-20260225-8","meetingId":"r08-1t","date":"2026年2月25日","dateIso":"2026-02-25","committee":"建設委員会","time":"午前１０時００分～午後 ２時２７分","status":"正式会議録","sourceType":"formal","overview":"建設委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を52件整理しています。","topics":[{"id":"topic-01","title":"戸越公園駅交通広場事業等の都市計画事業認可取得","agenda":"戸越公園駅交通広場事業等の都市計画事業認可取得","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"連続立体交差事業のほうなのですけれども、現在は２.４ｍの高さ制限となっている中延架道函渠ですが、現在どうなったのか伺いたいと思います。それと３点目で、駅前広場なのですが、こちらは使えるのかどうか伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"現在、連続立体交差事業が令和１７年度末の完了を予定しています。基本的な考え方といたましては、そういったしつらえにどういう形が望ましいか、検討していきたいと考えているところです。","id":"exchange-001"},{"speaker":"安藤委員","kind":"質問","question":"それと、もし分かれば居住世帯数や居住の人数などを伺いたいと思います。連続立体交差事業や交通広場等の整備に伴う立ち退きに対して、どのような声が寄せられたのか、それぞれ伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"当然立会いの下、測量を実施していますが、数名の方からはやはり立会いがなかなかできないと。区といたしましては、引き続き交通広場の必要性をしっかりと丁寧に説明しながら、事業のほうを進めてまいりたいと考えているところです。","id":"exchange-002"},{"speaker":"安藤委員","kind":"質問・要望","question":"ですから、私たちは、補助２９号線と併せてなのですけれども駅前広場は必要ないのではないかという立場です。生活再建、補償への責任を果たしていただきたいと思うのですけれども、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"補償の中には譲渡によります所得税に対する優遇措置等もありますので、その辺も含めてしっかりと丁寧にご説明させていただきたいと思ってあります。事業による補償の詳細につきましては、個別に相談に応じていくような形で対応してまいりたいと考えているところです。","id":"exchange-003"},{"speaker":"安藤委員","kind":"質問・要望","question":"ですから、区には様々な事業があります。やはりその方が生活を再建するにあたって求めることに、実現していただきたいという思いで聞いてるのですが、改めて最後伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"個別の事例によりましていろいろありますので、しっかりと個別に対応していく中でできる限りのことはさせていただければと考えているところです。引き続き、しっかりと事業の必要性等を説明しながら、補償の面につきましても…","id":"exchange-004"},{"speaker":"中塚委員","kind":"質問・要望","question":"なので、踏切解消は地元の強い要望でもありますけれども、タワーマンションをどんどん造っていくことは住民は望んでいないと私は思うのです。伺いたいことは、戸越公園駅周辺再開発を進めるためのインフラ整備という位置づけでよいのか、ご説明ほしいと求めました。","respondent":"大石まちづくり立体化担当課長","answer":"連続立体交差事業につきましては、今委員からもありましたとおり、地域からの要望が事業の始まりという形で、区としても認識しています。再開発事業を誘導するような形の事業ではないです。","id":"exchange-005"},{"speaker":"中塚委員","kind":"質問","question":"これはだってどう考えても、再開発のためにやるのではないですか。そこに合わせてこの２つの事業が進んでいると私は思っているのですけれども、違いますか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"２棟以外に戸越で再開発が進められるのかというところがございましたけれども、まちづくりビジョンにおきましては。現時点で、地域からほかの再開発の事業を聞いているところではございません。","id":"exchange-006"},{"speaker":"中塚委員","kind":"質問・要望","question":"立ち退きを求める事業なわけですから、一つの事業として生活再建策のスキームをしっかり説明をするということは当然の姿勢ではないかと思うのです。説明して、質疑を保障すべきではないかと思うのですけれども、いかがか尋ねました。","respondent":"大石まちづくり立体化担当課長","answer":"先ほどの繰り返しになりますけれども、まずは用地補償説明会にて全体の説明を行った後に、各個人に対して丁寧な対応をしていくという状況です。用地補償説明会の開催概要が決まりましたら、建設委員会のほうで開催の時期だとかをお知らせする予定ですので…","id":"exchange-007"},{"speaker":"中塚委員","kind":"質問・要望","question":"生活再建策のスキームがあるわけですから、用地補償説明会の前にそのスキームを示してほしいと求めました。３つ目が、事業認可が取得されたとはいえ、土地建物は任意売却ということで良いのか、そこを伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"区といたしましてもそこはしっかりと折衝する相手のお話を聞きながら、協力できるところは協力していくという形を取っていければと考えています。任意の売買ではないです。","id":"exchange-008"},{"speaker":"中塚委員","kind":"質問・要望","question":"区が協力できるところというのは具体的にどういうところなのか伺いたいと思います。今の説明で間違いがあったら指摘してほしいのですけれども、そういう手法も検討することはできないものなのか、最後に伺いたいと思います。","respondent":"森用地担当課長、大石まちづくり立体化担当課長、溝口防災まちづくり部長","answer":"今、まちづくり立体化担当課長から説明がございましたけれども、財産価格審議会の答申に基づいて価格を決定するです。その契約の中身だとかそういったもの… 各戸別に、補償内容等は変わってまいりますので、それぞれに対する支援の内容というのもまた変わってくるものと考えています。区といたしましては… その人たちをどうするのかという検討をした中で、工場を継続してやりたいという方の生活再建をするために、再開発事業の中で別の場所に建物を建てて。…","id":"exchange-009"},{"speaker":"中塚委員","kind":"質問・要望","question":"これだけ２３区内、品川も含めて土地の値段がいわゆる不動産バブルのような状態が起きているわけですから、私は正当な主張だと思うのです。これで最後にしますが、それぞれいかがか尋ねました。","respondent":"森用地担当課長、大石まちづくり立体化担当課長","answer":"都市計画事業ですので、期限を切って事業を完了する時期を予定して、そこに向かって進めていくという必要があります。ですので、任意でしっかりと売却を行っていただいて譲っていただくために… 丁寧に対応するですけれども、例えば税務相談など、そういったところは私たちのほうもしっかりと対応していきたいと考えています。その辺も含めてしっかりとご説明いたしまして、寄り添った対応をして…","id":"exchange-010"},{"speaker":"ゆきた委員","kind":"確認","question":"この中に用地取得費と、あと移転補償費等も含まれているという認識ですけれども、改めて確認できればと思います。補償費が、総事業費のうちのどのぐらいの割合を占めているのか、現時点での規模感の内訳というものが分かれば教えてほしいと求めました。","respondent":"大石まちづくり立体化担当課長","answer":"合わせて４４億円余という状況になってあります。委員ご指摘のとおり、ほぼというか４４億円のうちの３７、８億円が、いわゆる用地取得費になっているというものです。","id":"exchange-011"},{"speaker":"ゆきた委員","kind":"確認","question":"確認できました。ここも変わらないという議論がありましたが、変動リスクへの備えについてどのように考えているのか、改めてお聞きできればと思います。","respondent":"大石まちづくり立体化担当課長","answer":"こちらにつきましては現時点での想定の金額を入れているものです。今後どのような形になるか分からないので、今現状といたしまして、現時点での価格という形で算定しているものです。","id":"exchange-012"},{"speaker":"松永委員","kind":"質問","question":"３点ほどお伺いしたいのですが、町会としてはどういった形でお話をされてるのかというのが少し気になったので、お伺いしたいと思います。以上、３点伺いたいと思います。","respondent":"大石まちづくり立体化担当課長","answer":"今後、今も準備組合と協議を進めているところなのですけれども、こちらについてはしっかりと対応してまいりたいと考えているところです。改めてご説明に行く予定ですので、そこでどういったご要望があるかというのはしっかりと区としても把握していきたいと考えているところです。","id":"exchange-013"},{"speaker":"松永委員","kind":"質問・要望","question":"その後どういった回答になるか分かりませんが、代替地というか、そういったところも含めて丁寧に相談に乗ってほしいと求めました。これは要望です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-014"}]},{"id":"topic-02","title":"ボタン電池の回収","agenda":"ボタン電池の回収","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"やはりリサイクルですよという意味でやるのかということとも関わってくるので、事業費というかその辺をお伺いします。ここに書いてあるから絶縁しなくてはいけないものなのでしょうけれども、そこら辺をお伺いします。","respondent":"篠田品川区清掃事務所長","answer":"３点ほどご質問をいただきました。現実の問題として、このボタン電池は今も実際には一緒に出ていたりもするので、それを改めて周知を図るという形で考えているところです。","id":"exchange-015"},{"speaker":"安藤委員","kind":"質問・要望","question":"原材料になるということでしたけれども、ちょっと違っていたら後で指摘していただきたいのですけれども、そういうことも含めてその周知ですね。様々行うというご説明でしたけれども、そういった区民の方々の関心に届くように、ぜひ様々工夫していってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-016"},{"speaker":"中塚委員","kind":"質問","question":"それと、ボタン電池の回収、２３区ではどのような感じなのでしょうか。２３区清掃一部事務組合での議論とか、要するに品川の状況を広げていけたらなという思いで質問したいのですけれども、それぞれいかがか尋ねました。","respondent":"篠田品川区清掃事務所長","answer":"このボタン電池も昨年の特別区制度調査会でご要望いただいたものですから、そういったところで対応を考えているということがあります。区民の方からそういったご意見をいただければ、その都度検討してまいりたいと思っています。","id":"exchange-017"},{"speaker":"ゆきた委員","kind":"質問","question":"今回ボタン電池を週１回、資源の日に回収するということです。電池の種類ごとの排出量一覧で分かるようにする周知の工夫についてはどう考えているのか、それについて説明を求めました。","respondent":"篠田品川区清掃事務所長","answer":"中身を確認しながら、運搬もほかの資源と混じらないように分けて、安全性を確保しながらやっている状況があります。まとめて収集しながら、分け方等もあまり細かくならないような形でできるように、今後は対応していきたいと考えているところです。","id":"exchange-018"},{"speaker":"ゆきた委員","kind":"確認","question":"現在あるものの一覧表は私も確認させていただきました。事前に写真等で比較のイラストを用いた具体的な注意点といったものが、周知にも今後必要になると思いますけれども、改めてお聞きできればと思います。","respondent":"篠田品川区清掃事務所長","answer":"先ほどの私の説明がちょっと行き届かなかった部分があるかもしれません。透明な袋が一番良いのですけれども、そういったものでも全然問題なく収集をしていきたいと思いますので、混在していても問題ない状況であるです。","id":"exchange-019"}]},{"id":"topic-03","title":"電線共同溝等工事（競馬場通り）の委託変更","agenda":"電線共同溝等工事（競馬場通り）の委託変更","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"２番の1)の（２）なのですけれども、働き方改革というのは、具体的にはどういう改革になっているのかというのを伺いたいと思います。","respondent":"森道路課長","answer":"例えば今までは土曜日も工事としては実施をしておりました。ですのでその分、施工可能な日数が短くなりますので、実際に後ろ倒しになってしまったというようなところです。","id":"exchange-020"}]},{"id":"topic-04","title":"第二戸越幹線整備工事（取水および空気抜き設備等整備）","agenda":"第二戸越幹線整備工事（取水および空気抜き設備等整備）","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"下流のほうの取水３ですとか取水４ですとか、西品川公園付近の豪雨対応というのも向上するということになるのか伺いたいと思います。と言いますのは、今回の昨年の集中豪雨ではかなりやはり三ツ木通りですとか、新幹線の向こうの一丁目のほうもかなり水が出たものですから。","respondent":"関根河川下水道課長","answer":"２、合わせてこの４か所から水を取り込む計画になってありますので、浸水被害の軽減が見込まれると認識をしています。","id":"exchange-021"},{"speaker":"安藤委員","kind":"意見","question":"大変な工事がこれからも続くと思うのですけれども、安全に気をつけて迅速に工事を完了させることをよろしくお願いしたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-022"},{"speaker":"ゆきた委員","kind":"質問","question":"今回の工事は当初から令和１０年３月に完了予定ということで、当初の工事期間は延長されないのか、延長されないのであれば無理な工事にならないのか。この辺についてお聞きできればと思います。","respondent":"関根河川下水道課長","answer":"その補強をする材料の構造は一部変更というか追加になりましたけれども、それによって新たに日程が大きく必要になったというところはございません。大きなものが発生した際には、可能な限り現工期の中で完了できるように…","id":"exchange-023"},{"speaker":"ゆきた委員","kind":"確認","question":"確認できました。１点だけ確認ですけれども、大規模工事というのは、あらかじめ工期は余裕を持って設定されているという理解でよろしいか尋ねました。","respondent":"関根河川下水道課長","answer":"基本的に工期の設定に当たりましては、そうした余裕を大きく見込むということは想定してございません。例えば天候不順による日数を一定の係数をかけて見込むということはありますが、余裕を見て、基本的にはございません。","id":"exchange-024"}]},{"id":"topic-05","title":"しながわ防災区民憲章の制定","agenda":"しながわ防災区民憲章の制定","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"パブリックコメントなのですけれども、３６件ということですが、こちらの人数は何人だったのかというのをお伺いしたいです。３月５日には品川区防災会議があると思うのですけれども、そして決定するということで流れとしてはよろしいのか伺いたいと思います。","respondent":"羽鳥防災課長","answer":"パブリックコメントの人数というか、件数は１２件になります。同じ方が回答されている可能性もありますので、１２件ということでお伝えします。","id":"exchange-025"},{"speaker":"安藤委員","kind":"質問・要望","question":"前文の「自助および共助」を「自助・共助および公助」としてはいかがでしょうかという意見も寄せられています。例えば本会議での答弁を基にするのであれば、やはりそういった修正というのはぜひしていただきたいのですけれども、どうか尋ねました。","respondent":"羽鳥防災課長","answer":"公助につきましては、減災を進める上で重要であると認識をしています。自助・共助の取組も進めるということで、今、調整を行っているところです。","id":"exchange-026"},{"speaker":"安藤委員","kind":"質問","question":"今まだ案の段階だということなので、そういったことも踏まえて、ぜひ何とか公助の要素を入れていただけないでしょうか。改めて最後に伺います。","respondent":"羽鳥防災課長","answer":"自助・共助が全てであるというような誤った捉え方にならないように、区としましましても丁寧に情報の発信をしてまいりたいと思います。それぞれを高める必要があるということは区としても認識していますので、それぞれ力を高められるように…","id":"exchange-027"},{"speaker":"中塚委員","kind":"質問・要望","question":"もちろんどの災害も大事ですけれども、要するにここで言う災害とは何を指しているのか、主要な災害とは何か、そこを伺いたいと思います。議会の議決を求めないのはなぜなのかなと思ったのです。","respondent":"羽鳥防災課長","answer":"一定、丁寧な対応はさせていただいてきたという認識ではあります。多くの方の意見を聞いて、それを組み立てて防災会議へ諮るということで進めさせていただいていますので、ご理解いただければと思います。","id":"exchange-028"},{"speaker":"中塚委員","kind":"質問・要望","question":"風水害、しながわ防災区民憲章における災害は何を指しているのかが一つひとつ大事なことですから、そこを改めて伺いたいと思います。もっと時間をかけてやるべきだとは思っていますけれども、そこは改めて求めたいと思いますが、いかがか尋ねました。","respondent":"羽鳥防災課長","answer":"ここで言う災害は、その後の「伝える」というところの過去の災害というところで、私が説明したような過去の災害という表現をしています。やはり区民の皆様が作る憲章ですので、そういったところは表現できたのかなとは考えておりますので、ご理解いただければと思います。","id":"exchange-029"},{"speaker":"中塚委員","kind":"質問・要望","question":"施政方針ですからボリューム的にはこれぐらいかなとは思いますけれども、区長はどのような話を聞いて共感したのか。施政方針ですからぎゅっと縮めて整理されるのは必要なことだと思いますけれども、中身を伺いたいと思います。","respondent":"羽鳥防災課長","answer":"ですので、津波に対する公助のところの対応というのは、ある程度進んでいたです。まさに防災ガイドの方がおっしゃっている自助・共助の意識向上、次世代への継承というところは、今回のしながわ防災区民憲章の理念と合致するです。","id":"exchange-030"},{"speaker":"中塚委員","kind":"質問・要望","question":"やはり津波は必須なのですか。要するに海面から離れろということですから、違わないと思うのであれば、そこをご説明ほしいと求めました。","respondent":"羽鳥防災課長","answer":"災害対応に必要な自助・共助・公助というのも、災害対応に応じて様々です。今回はその一つの新たな取組として、こういったしながわ防災区民憲章というの作らせていただいたです。","id":"exchange-031"},{"speaker":"中塚委員","kind":"質問","question":"津波は地震の後ですから、やはり３０メートルの防潮堤ではなくて、そのための計画や訓練をすると。つまり、具体的に品川で起きる被害を念頭にしながわ防災区民憲章を組み立てるということが必要だと思いますが、最後にいかがか尋ねました。","respondent":"羽鳥防災課長","answer":"ここが品川区ならではなのかなと考えています。ですので、区民の皆様がそのように意識されているところを、今回、行動指針も併せて表現をしていくということで取り組んでいるところです。","id":"exchange-032"},{"speaker":"中塚委員","kind":"質問・要望","question":"ぜひその行動指針を作るにあたっては、案の状態のときに一回建設委員会や議会に報告を入れてほしい。要するに区が意思決定するにあたって、案の状態で建設委員会に報告して質疑を保証してほしいと求めましたが、いかがか尋ねました。","respondent":"羽鳥防災課長","answer":"行動指針につきましては日程の関係もありますので、どういった形にするかは調整が必要ですけれど、議会の皆様にご報告するように調整をいたします。","id":"exchange-033"},{"speaker":"ゆきた委員","kind":"確認","question":"変更点の説明については、今ありましたので、私からは１点のみ確認でお聞きしたいと思います。しながわ防災区民憲章の今後の活用方法について、どういったところで活用されていくのか、この１点だけお願いします。","respondent":"羽鳥防災課長","answer":"今回、安否確認タオルというものにしながわ防災区民憲章もプリントしまして、そちらを活用していきたいと考えています。その安否確認タオルをこちらから提供するというようなことを考えて、具体的な共助の取組までつながるようなものが描ければ良いかなと考えています。","id":"exchange-034"}]},{"id":"topic-06","title":"所管事務調査","agenda":"所管事務調査","exchanges":[{"speaker":"安藤委員","kind":"質問・要望","question":"これはどういうことなのか伺いたいのですけれども、そうではないですよという答弁でしたので、どういうことなのか伺いたいと思います。そちらを区のほうから都のほうに求めていくというお考えについてはどうなのか伺いたいと思います。","respondent":"遠藤防災体制整備担当課長、関根河川下水道課長","answer":"こちらについては、来年度ＬＩＮＥ登録による受付も運用する予定ですので、そちらとの連携も計画しています。こちらについても、東京都と連携した形で一定の方向性が示されたところで… 直ちに１００％を求めることは考えてございませんが、水道でも下水道でも、それぞれ東京都では対象を拡大をして実施をしてきているところです。そういったものを注視しながら、早期の耐震化を区としては求めていく…","id":"exchange-035"},{"speaker":"安藤委員","kind":"質問・要望","question":"避難所の負担も減るということで、こちらについては注視しつつ、ぜひ１００％の耐震化を求めていってほしいと求めました。そのうちの下水道直結型というのはどれぐらいなのかというのを、急な質問で申し訳ないのですが、分かれば伺いたいと思います。","respondent":"遠藤防災体制整備担当課長、大友公園課長","answer":"まずは現地を確認して安全を確認、人命救助の必要性を確認した後、３時間以内に開設をするというところで進めているものであります。まずは防災区民組織を中心として… それにあわせて必要な井戸であったり、電気であったりというのも併せて整備する予定です。現在のマンホールトイレの設置件数なのですけれども、公園内に今現在２１０基設置しています。","id":"exchange-036"},{"speaker":"安藤委員","kind":"質問","question":"現在それを実現する上での障害になっているものというか課題になっているものは何なのかというのを伺ったので、もう一度お願いしたいと思います。全ての区民避難所に配置を目指しているのかを伺うのと、体制の具体化に向けて、現在課題となっている点は何なのか伺いたいと思います。","respondent":"遠藤防災体制整備担当課長","answer":"品川区だけに支援が集まればあるいは５２か所可能かなとも考えますが、発災時は区内周辺、２３区一帯で被害があると。その流れ、フローに従って展開することによって、災害時でも速やかな運用ができるということを両者で共通認識を持っているところです。","id":"exchange-037"},{"speaker":"安藤委員","kind":"質問・要望","question":"これはどういう規模の数なのか今ひとつぴんとこないので、避難所に来る避難者の数に照らしてどうなのかという感じで伺いたいのが１つです。ですから、あるいは廃業してしまってはもうなくなってしまうわけですから、そちらについてはいかがか尋ねました。","respondent":"遠藤防災体制整備担当課長、羽鳥防災課長","answer":"こちらについても今後どのような形で、今後運用をどのようにしていくかということを検討していこうと考えています。ちょっと今答えを持ち合わせていないのですけれども、上下水道を整備してほしい施設のうち… １点目が、井戸や貯水槽を活用させていただいて、区民に対して給水を行うこと。もう一点が浴場を開放していただいて、罹災者への入浴支援を行うことの２点が協定内容になってあります。","id":"exchange-038"},{"speaker":"安藤委員","kind":"提案","question":"これは部署によっては確認しているかもしれないので、横断的に各部署で連携をしてぜひここは確認してほしいと求めました。ぜひ確認をしていただいて、必要な施策を今後打っていただきたいと要望いたしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-039"},{"speaker":"中塚委員","kind":"確認","question":"私は食事の質の確保、キッチンカー、そこに絞って伺いたいと思います。今時点で業者に確認できているもの、具体的にどういう状況なのか、そこを伺いたいと思います。","respondent":"遠藤防災体制整備担当課長","answer":"発災時の対応フローを作成しまして、品川区、キッチンカー団体、それと実動部隊となるキッチンカーの３者がどのように動けばよいのか。その後、状況を再度把握して、そういったところを協議しながら対応していくところを対応フローのほうには記載していると。","id":"exchange-040"},{"speaker":"中塚委員","kind":"質問・要望","question":"それが、その３者それぞれ手元にあって、日常的にも確認・訓練しているのかということを伺いたいと思います。１時間にどういうベースで食事を提供していくのか、ここも具体的に落とし込んでいく必要があるかと思いますけれども、それぞれいかがか尋ねました。","respondent":"遠藤防災体制整備担当課長","answer":"能登半島地震の事例でいきますと、区としては一番日数がかかるところで３日ということで検討はしております。食事を提供できるベースや食数については、各避難所でふさわしいキッチンカーを展開していただくといったことを考えております。","id":"exchange-041"},{"speaker":"中塚委員","kind":"質問・要望","question":"どこまで完売できるかというお話は伺いますけれども、一方で被災状況を見ると、温かい食事が圧倒的に足りていないというのもあります。そういうメニューの協議も引き続き必要ではないかと思うのですけれども、いかがか尋ねました。","respondent":"遠藤防災体制整備担当課長","answer":"まだ現在事業者と一定程度の相互理解というところなので、こちらについては引き続き協議を進めていって、今後も検討を進めていくといったところです。こちらについても引き続き事業者のほうと協議を重ねて…","id":"exchange-042"},{"speaker":"中塚委員","kind":"質問・要望","question":"事業者の方もそういう意気込みだと思いますけれども、ぜひそういうメニューに関しても工夫を引き続きお願いしたいと思います。どういう被害が起きるのか、ぜひ引き続きそういう姿勢で改善・改良していただきたいと要望して、終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-043"},{"speaker":"ゆきた委員","kind":"質問","question":"私からは、在宅避難について改めてお聞きしたいと思います。同時期にマンション防災訓練を行っていくということを今後考えていく必要があると思いますが、この辺についてお聞きできればと思います。","respondent":"羽鳥防災課長","answer":"それぞれマンションによって、マンション防災の対策の度合いというものが違いますので、３段階にレベルを分けて、それぞれ丁寧に支援をしています。そういった中で、また東京都からの支援も受けられるような良い循環が回りますので…","id":"exchange-044"},{"speaker":"ゆきた委員","kind":"質問・要望","question":"在宅避難の必要性については、さらに周知を行うとともに慎重に進めてほしいと求めました。今回は要望で終わりたいと思います。","respondent":"大友公園課長","answer":"すみません。先ほど２１０基とお答えさせていただいたところ、下水道直結の数はそのうちの約大体３分の１程度が下水道直結となっているところです。","id":"exchange-045"}]},{"id":"topic-07","title":"所管質問","agenda":"所管質問","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"質問したいのは、現在、品川区ですとか、あるいは２３区区長会などでどのような検討が行われているのか。区として反対などの意見を述べるべきだと思うのですけれども、いかがか尋ねました。","respondent":"篠田品川区清掃事務所長","answer":"ごみの有料化という話になりますと、現在２３区として、このごみの有料化について具体的な検討を進めているという状況にはございません。ただ、区民生活に大きな影響を及ぼすですので…","id":"exchange-046"},{"speaker":"安藤委員","kind":"質問・要望","question":"それと、ごみですから発生抑制をしないと、やはり必要なごみというのはどうしても出るわけです。ですから非常に良い答弁なのではないかと思うのですが、区長はいないのですけれども、それについてはご意見はいかがか尋ねました。","respondent":"篠田品川区清掃事務所長","answer":"いずれにしても今現時点でそういった形での検討の場があるわけではないので、そういったものに関しまして慎重な検討が必要であるという姿勢は、そういった検討の場が来れば。","id":"exchange-047"},{"speaker":"中塚委員","kind":"確認","question":"区の職員の方に伺っても分からないのだけれども、つまり東京都知事は、ごみの有料化など、そのような権限はあるのですか。自分の権限ではないだろうと報道を聞いていたのですけれども、ちょっとご意見・ご説明を伺いたいと思います。","respondent":"篠田品川区清掃事務所長","answer":"最初の分業体制について改めてご説明いたします。あくまで特別区の話ですけれどもという一言が都知事からありましたので、権限がないということは知事自身もご認識をされているのかなと思います。","id":"exchange-048"},{"speaker":"中塚委員","kind":"質問・要望","question":"もちろんやってはいけないことですけれども、やはり引き続きごみの減量のほうを中心に、清掃事業は引き続き進めてほしいと求めました。私もマンションですから、引き続きごみの減量を進めていただきたいと要望して、終わりたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-049"}]},{"id":"topic-08","title":"その他","agenda":"その他","exchanges":[{"speaker":"中塚委員","kind":"質問・要望","question":"この行動指針との序列、どういう関係の位置づけなのか、これを１点伺いたいと思います。そのとおりなのだけれども、町会・自治会に限定することはないのではないかと思うのですけれども、それぞれいかがか尋ねました。","respondent":"羽鳥防災課長","answer":"例えばスポーツのつながりですとか学校でのつながりというと、恐らく行動指針として示さなくても、事前に皆様つながりやすい環境ではないのか。なかなか参加する機会、きっかけづくりというところのハードルがまだまだあるのかなというところを課題として認識してございましたの…","id":"exchange-050","title":"町会・自治会支援"},{"speaker":"中塚委員","kind":"質問","question":"やはりマンションですから、今ある地域の様々なつながりを大事にしてこそ、災害のときにその力が発揮されますよと。でも、やはり社会の中ではそのつながりが薄くなっている現象が起きているわけですから、近所にお住まいなのですかとか。","respondent":"羽鳥防災課長","answer":"その挨拶するという部分に、行動指針としてあえて示すとなれば、そことつながってほしいというところであえて書かせていただいているところです。挨拶するという表現自体が、もう様々なつながりを包含した表現だと認識しています。","id":"exchange-051"},{"speaker":"安藤委員","kind":"質問","question":"というのは、自治会とか町会とかも大事な活動ですから、ここら辺の表現に関しては少し工夫があってもいいのかなと思いました。この行動指針の位置づけについて説明があったのですけれども、この行動指針のほうはどのように使われるのかというのはもう少し伺いたいと思います。","respondent":"羽鳥防災課長","answer":"はこちら、３月１１日にしながわ防災区民憲章を制定し、公表します。なるべく行動指針があったほうが、そこは状況に応じて併せて掲載できるように調整していきたいと考えています。","id":"exchange-052"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/680934?Template=document&Id=7325#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=8&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":63980,"voices":152}},{"id":"r08-20260225-9","meetingId":"r08-1t","date":"2026年2月25日","dateIso":"2026-02-25","committee":"文教委員会","time":"午前１０時００分～午後 ２時０８分","status":"正式会議録","sourceType":"formal","overview":"文教委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を57件整理しています。","topics":[{"id":"topic-01","title":"令和７年度品川区教育委員会事務事業の点検および評価の報告書","agenda":"令和７年度品川区教育委員会事務事業の点検および評価の報告書","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"修学旅行費無償化事業が総合評価でＣ、あと給食運営もＣとなっていますけれども、その理由、背景を伺います。今後の取組については、手法等の改善をしていくということで、どういったことをやっていくのか、今、考えられていることを伺います。","respondent":"石井学務課長、新井特別支援教育担当課長","answer":"そして実際に返金した分を各学校に補助金として支給し、各学校が旅行会社に支払うというスキームで実施をしてまいりました。無償化そのものは引き続き実施することですけれども、手法について、引き続き検討が必要であるという観点です。 私からはシート５番の発達障害教育支援員の配置の具体的な効果についてご説明いたします。よりきめ細かな支援ができるようになったですとか、校長が状況に応じて柔軟に配置をする、児童を変えたりとか柔軟な対応ができたということで。","id":"exchange-001"},{"speaker":"のだて委員","kind":"質問・要望","question":"実際、今後、どういった形で進めていくのかを伺います。区として実際、現状がどうなっているのか、この課題についてどう対応されていくのかを伺えればと思います。","respondent":"丸谷教育総合支援センター長、三ツ橋品川図書館長","answer":"１０番のいじめ防止対策についてです。より早期に児童・生徒の課題の発見と解決に向けた取組がスムーズに円滑にいくだろうということで、次年度、計画してまいります。 司書に関しましては、やはり学校の図書館運営サポートに関しては非常に大事ですので、引き続き運営についても実施していきたいと考えています。学校ボランティアをしたい方を募りまして…","id":"exchange-002"},{"speaker":"のだて委員","kind":"質問・要望","question":"そして４日、５日と増やしていただいて、ぜひ５日設置するように進めてほしいと求めました。何かあれば伺いたいと思います。","respondent":"丸谷教育総合支援センター長、三ツ橋品川図書館長","answer":"現在、教育総合支援センターの中にあるＨＥＡＲＴＳに所属している心理や福祉の専門家が学校に今後、移行していくイメージを考えております。学校に配置しているスクールカウンセラーやスクールソーシャルワーカーが… 委員のご要望につきましては、やはり区といたしましても図書館司書は学校図書館運営にも必要だと考えていますので、引き続きボランティアを工夫しながら、また週３日になれるように工夫しながら対応していきたいと思います。","id":"exchange-003"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"修学旅行無償化事業ですけれども、１人当たりの金額をもう１回確認したいです。それについて、学級だけではなく、ほかの要素も出てくると思うのですが、配置の増員についていかがか尋ねました。","respondent":"石井学務課長、新井特別支援教育担当課長、酒川指導課長、三ツ橋品川図書館長","answer":"今後、物価高騰への対応につきましては、予算の範囲内できちんと対応できるように進めていきたいと考えています。例えば列車を使う旅行ですと… 発達障害教育支援員の配置の増員についてのお尋ねと認識しています。はほかの支援員の見解、もう１人の支援員の見解も聞けるですとか… 品川オンライン英会話レッスンは品川学園１校で実施しております。…","id":"exchange-004"},{"speaker":"高橋（し）委員","kind":"質問","question":"発達障害教育支援員は拡大を検討ということですから、なかなか現状、令和７年度と変わらない認識でよろしいのでしょうかというのが１つ。品川オンライン英会話レッスンもやはり経年変化を見てということですから、まだ品川学園だけになってしまうのか尋ねました。","respondent":"三ツ橋品川図書館長、酒川指導課長、新井特別支援教育担当課長","answer":"いろいろ調べるというのはすごく大事だと考えていますので、中学校においても図書館の蔵書に関してもいろいろ工夫をしていきたいと思います。 品川オンライン英会話レッスンについては、令和８年度も品川学園１校です。 やはり、今後、ニーズの高い事業だと考えておりまして、こちらは拡充の方向で、また予算要求は検討していきたいと考えています。しかも早く求人ができる…","id":"exchange-005"},{"speaker":"高橋（し）委員","kind":"意見","question":"最後、１つだけ。発達障害教育支援員にいろいろ話ができないことがあって、そこのところの指導上のやり方については、どう配慮されていらっしゃいますかとの意見を述べました。","respondent":"新井特別支援教育担当課長","answer":"答弁漏れでございまして、基本的には校長が人材派遣の支援員に対してこの児童に支援をしてほしいといった指示ができるような形になってあります。","id":"exchange-006"},{"speaker":"まつざわ委員","kind":"質問","question":"何かそういった地域からこうやって子どもたちの修学旅行に関してもけちることなく学びを進めてほしいと言わせるような取組をぜひしてほしいのが１個…この貸出し冊数の減少をどう考えたらよいか説明を求めました。","respondent":"石井学務課長、三ツ橋品川図書館長","answer":"やはりもっと大きなもので、地域全体として子育てをしていく、子どもの学びを保障していくという観点があると思います。どのような形でできるかについては、まだこれからだとは思いますけれども… そのほか、ブックフェアなども実施して、何とか図書離れを防ごうと考えております。こちら、閉館時間というのは、特に問題にはなっていないと捉えております。","id":"exchange-007"},{"speaker":"横山委員","kind":"確認","question":"英語教育ですけれども、それに対してどういったことを考えていて、今後どう改善していく見通しを立てているのかを確認させてください。どういった経過があって、今、こういう形になっているのかを少し整理して確認させていただけたらと思います。","respondent":"丸谷教育総合支援センター長、酒川指導課長","answer":"相談があれば、学校に出向いたり、家庭に出向いたりということで、対応、支援させていただいているという現状があります。ですので、次年度からは学校の中で… それから令和４年度になりまして、９年生で実施。それから令和６年度に７年生も追加し、８年生、９年生、７年生と広げてきたものが今、６年生の１校で実施されているという経過です。","id":"exchange-008"},{"speaker":"横山委員","kind":"質問・要望","question":"この１年間をかけていろいろ整えていくということで、今、ＨＥＡＲＴＳ所属の専門家の方々が学校に行くという理解でよろしいでしょうか。６年生から７年生の接続も、全校実施にも期待しておりますので、引き続き進めてほしいと求めました。","respondent":"丸谷教育総合支援センター長","answer":"教育総合支援センターに所属しているスクールソーシャルワーカーが学校に配置になって、引き続き、次年度も関わっていただける方は。児童・生徒が支援対象になりますので、学年主任になったりということで、変わっていくと考えています。","id":"exchange-009"},{"speaker":"横山委員","kind":"質問・要望","question":"２５ページ、現在、教育委員会としてどのようなことを考えていらっしゃるのか確認させてください。どういった方が関わっていらっしゃるのか、少し詳細、現状を教えてほしいと求めました。","respondent":"丸谷教育総合支援センター長、酒川指導課長、三ツ橋品川図書館長","answer":"学校との連携ですけれども、現時点でもＨＥＡＲＴＳが関わっているケースについては、学校管理職とは連携を密にとりながら対応しております。… これについては、区長部局とも連携を重ねて、今後、どのような取組ができるか研究していきます。これで品川区立学校の部活動を１００％充足するといった考… ＰＴＡの方が中心となっているものでございまして、地域のやはり近い図書館などにボランティアをしていただいているところです。","id":"exchange-010"},{"speaker":"横山委員","kind":"質問・要望","question":"私が質問、要望させていただいていると思うのですが、ぜひよろしくお願いします。さらに地域、若者ですとかに広げていっていただけるような働きかけをぜひ行っていただきたいと思うのですけれども、その辺りいかがか尋ねました。","respondent":"三ツ橋品川図書館長","answer":"学校図書館ボランティアですけれども、主にＰＴＡの方、または小学校、中学校を卒業されたＰＴＡの方が主ですが、広く募集はしていまして、今後も工夫していきたいと考えています。","id":"exchange-011"},{"speaker":"若林委員","kind":"質問","question":"いわゆる現場にというお話がありましたけれども、そこら辺のお話はこの事業評価シートからは読み取れないのですけれども、これはどういう議論の経過なのか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"学校配置型を検討するということで、こちらでスクールカウンセラー全校配置、スクールソーシャルワーカーの全中学校配置という記載です。さらに具体的に話を進めていく中で、教育委員会内でそういうお話もいただきながら現在、計画を進めている段階です。","id":"exchange-012"},{"speaker":"若林委員","kind":"確認","question":"この教育委員からの意見は、そういう踏み込んだ形はあの中で議論されたのか、一定の説明があったのか。教育委員の皆様はそこをどのように今、認識をして、また理解をしているのか、していないのか、経過を少し確認したいです。","respondent":"丸谷教育総合支援センター長","answer":"より身近に感じられる仕組みづくりをしていただきたいとご意見をいただきまして、学校配置型にしていくという説明を先日も差し上げております。ですので、ＨＥＡＲＴＳの形が変わっていくことについて、一定程度、ご理解いただいているものと捉えております。","id":"exchange-013"},{"speaker":"若林委員","kind":"質問・要望","question":"ぜひ委員会への報告、こういったものを含めて、今後とも頑張ってほしいと求めました。それはなぜかという質問と、過去、この事務事業評価シートの中で、Ｄ評価のものは傾向性としてあるとか、ないとか、もし分かれば説明を求めました。","respondent":"舩木庶務課長","answer":"私が認識している中ではＤ評価、完全に事業そのものを廃止していることはここ数年ではないと認識しておりまして、評価をいただいているものと認識しております。","id":"exchange-014"},{"speaker":"若林委員","kind":"質問","question":"構造的に無理なのであればそれで結構ですし、何かもう少しフラットな評価の仕方、テーブルの上げ方があるのか。この辺、今後、毎年これをやられて、評価が義務づけられていますので、１回参考に少しお聞きしたいと思います。","respondent":"舩木庶務課長","answer":"この品川区教育委員会の事務事業評価の実施要領を教育委員会でお諮りをして、お預かりして、検討させていただきたいと思います。","id":"exchange-015"}]},{"id":"topic-02","title":"学校プール施設のあり方","agenda":"学校プール施設のあり方","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"そうしたところでは、優先順位をつけてということですけれども、基本的にはシェードを設置していくことでいいのか確認させていただきたい。その中で、今、源氏前小学校はまだ調整中で、現在の状況と何か課題になっていることがあれば伺いたいと思います。","respondent":"荒木学校施設担当課長","answer":"１点目の改築済みの学校および既存校の今後の改修の対応方針ですが、改修に当たっては日除けシェードを設置していく考えです。これに当たりましても、やはり距離がありますので、バスを利用する方向で検討を進めております。","id":"exchange-016"},{"speaker":"のだて委員","kind":"質問・要望","question":"源氏前小学校は、今、伊藤学園との調整中ということで、一番近いのが伊藤学園なのですか。８００ｍ圏内からはなかなか離れているので、調整は進めていただきたいと思うのですが、そうしたことは検討したのか伺います。","respondent":"荒木学校施設担当課長","answer":"１点目の設計段階で日除けシェードを盛り込んだ場合、やはりこちらも改修と同額程度はかかってくると見込んです。２点目の源氏前小学校の共同利用の利用先ですが、円滑に調整が進んでおりますので、こちらの利用を検討しております。","id":"exchange-017"},{"speaker":"のだて委員","kind":"質問・要望","question":"ぜひ子どもたちがプールの授業、水泳授業をしっかりできるように、今後も様々、取組を進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-018"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"それを設置するスペースをあの中に見つけるのはなかなか酷と思うので、どういった感覚でこういうお話があるのかを教えていただきたい。少し説明を求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-019"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"やはり人件費がかかるわけですから、バス代ではなくて、やはり歩いて行ける施設もあると思うのです。だからそこら辺は要望で、いろいろ子どもにいいものを考えていただけたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-020"},{"speaker":"高橋（し）委員","kind":"確認","question":"集約化の予定でない、中学校を中心にという内容だったとあるので、そこの確認です。温水ではないからどうしても八潮学園にしたのか、その点、お願いします。","respondent":"荒木学校施設担当課長","answer":"さらには屋内プール設置の場合は敷地の中を大分、やはり今後も各学校に整備して、各学校で水泳授業を実施してもらう考えで進めてまいります。３点目の鈴ケ森小学校や八潮学園を利用することに関しましては、教育委員会としても、バス利用などをあっ旋していこうと検討したもので…","id":"exchange-021"},{"speaker":"高橋（し）委員","kind":"意見","question":"屋外プールを原則としてというお話です。学校間でうまくやっていくところを、今回はバスですけれども、支援してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-022"},{"speaker":"筒井副委員長","kind":"確認","question":"プール共同利用についてですけれども、もう既に出ていた話かもしれないですが、確認として少しお聞きしたいと思います。それぞれ単独でやっていくのか、どういう授業になるのか説明を求めました。","respondent":"荒木学校施設担当課長","answer":"城南第二小学校の品川学園のプール共同利用に関するご質問ですが、こちらは、学校単位で実施するものです。４月下旬から５月の中旬ぐらいまでにかけまして、城南第二小学校単独でその時間は授業を実施する計画で今、検討しております。","id":"exchange-023"},{"speaker":"筒井副委員長","kind":"質問","question":"では、各学校単独で授業をそれぞれ行っていくと理解しました。では品川学園の時期は何月になるのか尋ねました。","respondent":"荒木学校施設担当課長","answer":"品川学園に関しましても、当然１年中、プール授業ができる温水プールの環境ですが、やはりコアの期間として、夏場から秋ぐらいにかけてということで伺っております。","id":"exchange-024"},{"speaker":"筒井副委員長","kind":"質問","question":"行き帰りで１時間ぐらい、その時間を消費する分、何か普通の授業に影響はあるのでしょうか。その影響があるのでしたら、それを補完するような対策、対応はどのようにお考えか尋ねました。","respondent":"荒木学校施設担当課長","answer":"特に今、副委員長ご指摘の移動時間が課題と認識しております。なので、学校で授業のカリキュラムを組む中で工夫して確保していただくということで、現在は考えてあります。","id":"exchange-025"}]},{"id":"topic-03","title":"学校改築の進捗","agenda":"学校改築の進捗","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"いろいろ検討していくということですけれども、３つの視点の中で５つ検討項目が出されていて、どういった手法が考えられるか現時点の状況を伺います。工事発注方法の検討で、今後、どういったことが考えられるかを伺いたいと思います。","respondent":"荒木学校施設担当課長","answer":"この学校改築を進めていくために必要な規模、機能の適性を検討して、工期と工事費を縮減できるだろうという検討を進めてまいりたいと考えています。学校敷地内での対応に加えまして、各関係と連携しながら…","id":"exchange-026"},{"speaker":"のだて委員","kind":"質問・要望","question":"仮設校舎用地はあるのかというのが少しあるのですけれども、今、考えられるところ、もしあれば伺います。全部、地域の意見をしっかりと聞いていただいて進めてほしいと求めましたけれども、いかがか尋ねました。","respondent":"荒木学校施設担当課長","answer":"２点目の仮設校舎の用地ですが、こちらにつきましては、本当に来年度の基本構想策定の中で様々、検討してまいりたいと考えています。今年度の検討結果の報告、それから来年度の基本構想の策定に向けた検討状況に関しましては、報告させていただきたいと考えています。","id":"exchange-027"},{"speaker":"まつざわ委員","kind":"意見","question":"こういう資料は、もうやってほしい地域はもうやるのだとなったときに、慎重にこういう情報の間違いがないようなやり方をやってほしいと思っています。そうすると全課程が２回転するほど、本当にご苦労なさっていますけれども、いろいろな視点で考えていただければいいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-028"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"そういう発想はこの検討の中で、高さ制限とかあるのかもしれませんけれどもそういうご意見、区の検討の中では出てきたのかお伺いします。どうすれば短くなるのかは私も非常に難しくて、専門的で分からないので、そういうご意見があったので、それはいかがか尋ねました。","respondent":"荒木学校施設担当課長","answer":"１点目の情報発信の仕方、説明の仕方は今後も留意して進めてまいります。当然、この周辺地域は道路が狭い状況ですので、建築的な制約、法的な制約があるのですけれども、あらゆる可能性は検討してまいりたいと思います。","id":"exchange-029"},{"speaker":"高橋（し）委員","kind":"提案","question":"私が提案したのではなくて、そういうのも１つの方法だと思うので、ぜひ専門的な見地から検討してほしいと求めました。そういう俎上に載ったときに考えればいいことで、それは後で２つの老朽化した学校をいかに早く改築できるかという方法をぜひ考えてくださいとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-030"},{"speaker":"横山委員","kind":"確認","question":"１点だけ確認ですけれども、例えば他区の事例とかですと、渋谷区で仮設校舎を共同で利用する手法があると思います。あくまでも令和８年度は三木小学校と大崎中学校のみを対象とした検討になるのか、また、その辺りを確認させてください。","respondent":"荒木学校施設担当課長","answer":"５番に記載がありますとおり、敷地測量の実施と新校舎基本プランの検討というのは、三木小学校と大崎中学校を中心に進めてまいるものです。そういったことは２校だけでなくて、また来年度の検討ではあるのですけれども、様々な角度から検討してまいりたいと考えています。","id":"exchange-031"},{"speaker":"横山委員","kind":"質問・要望","question":"出てくる課題に対して、どういったことができるのか、柔軟に検討を進めてほしいと求めました。あくまでも対象は今回は２校ですけれども、検討を進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"},{"speaker":"若林委員","kind":"質問・要望","question":"何点か確認と要望という形でお願いします。三木小学校と大崎中学校の竣工の目標、目安は、まずどこら辺に置いているか教えていただけますか。","respondent":"荒木学校施設担当課長","answer":"先ほどのご質疑にもあったのですけれども、それ以降に必ずしもこの２校のうち、いずれかの学校を改築することが決定したわけではございません。その上で仮にこの２校になった場合に関しましては、１１年をできる限り短縮して、竣工を目指していきたいと考えています。","id":"exchange-033"},{"speaker":"若林委員","kind":"質問・要望","question":"今の質問になったわけですけれども、具体的に言えないのはもう分かりましたので、今後の考え方をお聞きしたいのが１つ。早速、地元の町会等の方々に、アンサーをバックすることについてのお考えも併せてお聞きしたいと思います。","respondent":"荒木学校施設担当課長","answer":"これからも老朽度を第一として考えて、就学人口動向の３点でしっかりと検討して、次期着手校を決めて取り組んでまいりたいと考えています。この令和７年度の検討内容と、令和８年度の基本構想の策定に係る検討につきましても…","id":"exchange-034"}]},{"id":"topic-04","title":"令和８年度新入学、学校選択の希望申請理由に関する調査結果","agenda":"令和８年度新入学、学校選択の希望申請理由に関する調査結果","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"これを学校運営の改善につなげていく、どう活かされていくのかを伺いたいと思います。選択理由の中で、学校の教育活動に魅力があるというのが上位になっていますけれども、これはどういう教育活動なのか、伺います。","respondent":"石井学務課長","answer":"回答率が落ち込んでいる中で、一つ一つ工夫を重ねながら、回答率が少しずつ向上しています。なので、各学校がそれぞれの特色を活かして教育活動をしているという全体の傾向として受け止めております。","id":"exchange-035"},{"speaker":"まつざわ委員","kind":"質問","question":"今、回答率の合計が１５.７％で少し高くなったのか尋ねました。","respondent":"石井学務課長","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-036"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"これが総意というと何か少し難しいとは思いつつ、でも、回答率が上がるように引き続き努力してほしいと求めました。こういった課題を持ち出して、地域と一緒にキーパーソンの方がＰＤＣＡサイクルを回すような取組があるのか説明を求めました。","respondent":"石井学務課長","answer":"当然、各学校においては、そういった全体の傾向を押さえつつも固有の課題を恐らく各校長はご存じだと考えています。そういった中で、どうやったらより魅力ある学校づくりができるかは、各校において議論されているものと承知しております。","id":"exchange-037"},{"speaker":"まつざわ委員","kind":"確認","question":"新しい学校、新しくない学校、そこら辺の分析はどうしていくのか。電子黒板も含めてですが、そういった配慮がされていると思いますが、そこの確認をさせてください。","respondent":"石井学務課長","answer":"施設が新しいから選んだという回答はこの２年ぐらい少しずつ割合が増えています。そういったところで、教育の格差ができないよう、きちんと全校が魅力ある教育に取り組めるようなバックアップをしていきたいと考えております。","id":"exchange-038"},{"speaker":"高橋（し）委員","kind":"質問","question":"小学校５校ぐらいで２０人ぐらいです。もう小学校などはほぼ決まって、現状で分かっている範囲の、兄弟枠での待機した方が入れなかった現状についての分析はいかがか尋ねました。","respondent":"石井学務課長","answer":"回答については差し控えしますけれども、やはり例年同様、兄弟枠でも入れない方がいらっしゃることは課題として受け止めております。就学人口が増加することによって、制約があることについては引き続き、課題として受け止めております。","id":"exchange-039"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"９９％の可能性としてきちんと希望する兄弟枠については何らかの現状を少し変えるような方法を考えてほしいと求めました。これは意見です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-040"},{"speaker":"筒井副委員長","kind":"質問","question":"Ｂ型、どちらが多いのか、インフルエンザの傾向を少し説明を求めました。","respondent":"石井学務課長、染谷保育施設運営課長","answer":"なお、昨年度については、Ａ型のうちの別の型がはやっていたので、型については違うだろうと考えています。恐らく、学校ですとか、保育園や幼稚園においてもこういった全体の傾向に影響を受けているものと思われます。 型についての傾向は数字として持っているものでありませんけれども、一昨年と比較して増えているという状況を見ると、保育園・幼稚園においても同様の傾向にあると考えております。","id":"exchange-041"},{"speaker":"筒井副委員長","kind":"質問・要望","question":"インフルエンザについては、Ａ型にかかって治療したからといって、また今度、Ｂ型にかかるおそれもあるので、ぜひ、引き続き予防の呼びかけを行ってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-042"}]},{"id":"topic-05","title":"区立学校におけるいじめの重大事態の発生状況","agenda":"区立学校におけるいじめの重大事態の発生状況","exchanges":[{"speaker":"のだて委員","kind":"質問","question":"今、この予防プログラムは全校で実施しているのかを伺いたいのと、あといじめが起きた後の対策がきちんとできているのか伺いたいです。実際、今、どういった取組をされているのか伺います。","respondent":"丸谷教育総合支援センター長","answer":"年３回のいじめ予防授業を実施する中で、年に１回は学校で公開日を設けて、取組を行ってあります。対策を検討して、支援や指導に当たる、全校で併せてそういった取組を進めています。","id":"exchange-043"},{"speaker":"のだて委員","kind":"質問・要望","question":"１人だけではなかなか対応も大変になると思いますので、集団的に対応してほしいと求めましたが、具体的に各校でどう全校でやっているか伺います。それぞれで共有しながら、対応策をよりよくしていくことが必要と思うのですが、いかがか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"いじめ問題については、担任１人で抱え込むのではなく、学校の中でチームで対応していくのが原則となっております。担当の教員、スクールカウンセラー、こうしたメンバーで対応策を考えて支援・指導に当たっていくのが原則であります。","id":"exchange-044"},{"speaker":"のだて委員","kind":"意見","question":"学校がチームで対応するのが原則だということで、ぜひ、そうしたことを見つけた教員の人が、教員だけではないかもしれませんが、しっかりチームに相談できるような相談しやすい環境もつくってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-045"}]},{"id":"topic-06","title":"令和７年度市民科検討委員会報告","agenda":"令和７年度市民科検討委員会報告","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"この検討委員会は既に３回やられた中でどういった意見や議論があったのかを伺いたい。こうした子どもの権利条約を学んでいくのも、１つ重要だと思うのですが、いかがか尋ねました。","respondent":"唐澤教育施策推進担当課長","answer":"検討委員会での意見、議論ですが、こちらは現在も実施しており、やはり教員にとって分かりやすい市民科にしていただきたいという話。今後、検討委員会の中でも、実際進めていくような形で認識しております。","id":"exchange-046"},{"speaker":"のだて委員","kind":"質問・要望","question":"そこから脱却していくということですので、ぜひ、やはり自分で考えることができる子どもたちを育ててほしいと求めました。子どもたちが知らないのが１つ大きな課題だと思いますので、子どもたちが学べるようにしていただきたいと、要望いたします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-047"},{"speaker":"高橋（し）委員","kind":"質問","question":"この後、新たな形で変えていくと思うのですが、指導要領改訂に合わせた市民科の独自教材の改訂の見込みはどのような形になっているのでしょうか。指導案なども必要ですけれども、参観の助けみたいなものもあるといいと思うのですけれども、その辺りはいかがか尋ねました。","respondent":"唐澤教育施策推進担当課長","answer":"教科書については、一定の好意的な意見もありますので、ここも踏まえながら検討を進めてまいればと考えています。より分かりやすい形の指導案も含めまして、今後の検討材料として考えていければと思います。","id":"exchange-048"},{"speaker":"高橋（し）委員","kind":"質問","question":"特に通知表は両方とも文章で書くわけで、児童・生徒と保護者に分かりやすく表現できることも含めて検討していただけるとありがたいと思います。評価のところだけ、お願いします。","respondent":"唐澤教育施策推進担当課長","answer":"これはどういうことをやっているのかも含めまして、貴重な機会と捉えておりますので、丁寧に伝えるようにと考えています。現在、改訂に向けても、そういったことがスムーズにできるように考えていければと考えています。","id":"exchange-049"}]},{"id":"topic-07","title":"南品川児童センターの休館","agenda":"南品川児童センターの休館","exchanges":[{"speaker":"のだて委員","kind":"質問・要望","question":"休館期間が３年以上あるということで、ぜひ、利用者、子どもたちへのしっかりとした周知をしてほしいと求めました。いかがか尋ねました。","respondent":"上野子ども育成課長","answer":"東品川児童センターへの代替施設のご案内を進めてまいりますが、それから東品川児童センターに行き方の確認ですとか、館の体験も行う予定でおります。丁寧に子どもたちには代替施設のご案内をしてまいりたいと考えています。","id":"exchange-050"},{"speaker":"まつざわ委員","kind":"確認","question":"１点が、防災倉庫にもなっていたと思うのです。代替地の中で防災倉庫がなくなったときの位置づけ、計画、何かそこら辺が現状あるのか、４つ確認です。","respondent":"上野子ども育成課長","answer":"３年間閉館してしまうので、そういった好事例も活用しながら、検討してまいりたいと考えております。整備された暁には、防災倉庫を再度つくっていく予定でありますので、そこに戻す形で進めたいと考えております。","id":"exchange-051"}]},{"id":"topic-08","title":"所管質問","agenda":"所管質問","exchanges":[{"speaker":"高橋（し）委員","kind":"意見","question":"それは教員の働き方改善、改革につながるということ、ガイドラインによる効果をお尋ねします。３つ目は（仮称）品川区学校・家庭サポートセンターという、それぞれのトラブル解消の設定に関してどのような効果があるかをお尋ねしますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-052"},{"speaker":"横山委員","kind":"確認","question":"私からは同様に先ほどのガイドラインについて、地域ですとか議会や議員等への周知の部分をどのようにされるのかを確認させてください。","respondent":"丸谷教育総合支援センター長","answer":"もう１点、検討している段階ではありますけれども、教育総合支援センター内に組織を置くことを考えております。子どもを真ん中にした支援が大切だと考えておりまして、学校の対応もそうですけれども、保護者の理解も得られるように努めてまいります。","id":"exchange-053"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"それから、３つ目はガイドラインの１５ページに社会通念を超える要望に対して、こうですと。そういった点で、保護者向けのそういうチラシに関しては分かりやすく訴えていただけるとありがたいと思うのですが、その辺りいかがか尋ねました。","respondent":"丸谷教育総合支援センター長","answer":"東京都からの説明もそういった説明がなされると思いますので、まずはその部分を学校や保護者の方、地域の方にもご理解いただければと考えております。ルールがあることで…","id":"exchange-054"},{"speaker":"高橋（し）委員","kind":"質問・要望","question":"より学校にもいいし、保護者の方にもいいと思うので、これは要望で進めてください。それだけもう１回お尋ねします。","respondent":"丸谷教育総合支援センター長","answer":"そういった意見交流ができるような場面を設定することが１つ、お互い顔を見て人柄を知る、そういったものがまずは大事だと考えております。学校と地域、また保護者が連携して、子どもたちを大人みんなで育てていくという風土を醸成していくことが大事だと考えております。","id":"exchange-055"},{"speaker":"高橋（し）委員","kind":"意見","question":"トラブルがあって、初めて担任の先生と口をきいたなどとならないような状況がつくられていると思うので、ぜひ進めてくださいとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-056"},{"speaker":"のだて委員","kind":"質問・要望","question":"保護者をクレーマーとして扱うのではなくて、しっかり話を聞いていけば、なぜそういうことを言っているのか理解ができる。時間のかかることですけれども、ぜひそうしたお互いを理解し合って、一緒にこの学校をつくってほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-057"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/631298?Template=document&Id=7323#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=9&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":53634,"voices":194}},{"id":"r08-20260225-5","meetingId":"r08-1t","date":"2026年2月25日","dateIso":"2026-02-25","committee":"総務委員会","time":"午前１０時００分～午前１１時２７分","status":"正式会議録","sourceType":"formal","overview":"総務委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を32件整理しています。","topics":[{"id":"topic-01","title":"令和８年度 組織改正（案）","agenda":"令和８年度 組織改正（案）","exchanges":[{"speaker":"須貝委員","kind":"質問","question":"行政の仕事にマネジメントという言葉はあまりふさわしくないのかなと思うのです。経営効率化とか、そういうことを考えながら事業を推進するというやり方は何かおかしい気がするのですが、そこをどのようにお考えなのか尋ねました。","respondent":"崎村企画課長","answer":"昨日の議案審査の中でも、学校施設の建設工事経費が大分大きくなっているというご指摘もございました。効果的なのか、また経費も抑えられるのかというのをしっかり組織的に考えていかなければいけないという視点で、今回組織を新設させていただいたです。","id":"exchange-001"},{"speaker":"須貝委員","kind":"質問","question":"例えば２社なり３社の相見積りを取るというのも一つの方法だし、それを区内でやるというのは難しいと私は思うのですが、その辺をお聞かせください。在宅子育て支援係、保護児童支援担当、これも別の事業部でそのまま移管して事業を進めていくというふうに考えていていいのか尋ねました。","respondent":"崎村企画課長","answer":"説明が不十分だったかもしれませんが、在宅子育て支援係については、事業自体がなくなるということでございません。こちらも事務がなくなるということではなく、２つの係だったものを１つの係に統合して引き続き進めていくです。","id":"exchange-002"},{"speaker":"西本委員","kind":"質問・要望","question":"今年の施政方針を読むと、これはどこに入るのですかということと、この役割というのがかなり広がっていくという考えでいいのでしょうか。やはり役職定年は役職定年で、例外というのはないというのを確認したいのですが、。","respondent":"崎村企画課長","answer":"子どもの食の支援ですとか、そちらに移管して、きめ細かな対応を図っていくというようなことがあります。子ども育成課、子ども家庭支援センターでやっている事業は、こちらについては引き続き課題意識を持って考えていきたいと考えています。","id":"exchange-003"},{"speaker":"西本委員","kind":"質問","question":"今まで再任用でやっていただいていたところがあったのですけれども、それは今後、来年度はどうなってしまうのでしょうか。まだ大丈夫ですというのか、私は役職定年制が敷かれているという認識を持っているのですけれども、人事はどういうふうになっているのか尋ねました。","respondent":"崎村企画課長、宮尾人事課長","answer":"担当部長のご質問ですけれども、区長が施政方針でお示ししたとおり、担当部長を設置する方針というところは変わりございません。設置することが決まっているかどうかというところについては… 年度末で６０歳を迎える管理職につきましては、管理職以外の職に就くということが前提となりますので、それは部長級でも課長級でも同様です。一部例外はありますけれども、今…","id":"exchange-004"},{"speaker":"西本委員","kind":"質問","question":"今までの組織の中でやっていくということになるのですか、そこの組織は変わらず、担当が変われば名前も変わると思うのです。載っていないということは、その部署も名前を変えずにやっていくという認識でいいのかなと思うのですけれども、それでいいか尋ねました。","respondent":"崎村企画課長","answer":"部としては福祉部の中に担当部長を設置するです。障害者の部門については基本的には障害者施策推進課、障害者支援課という２課の体制で引き続き進めていくです。","id":"exchange-005"},{"speaker":"山本委員","kind":"質問・要望","question":"その中で教えていただきたいのですけれども、担当主査の配置の基準を確認させてください。人員配置とか、想定している定員や業務量等の考え方などがあれば、併せて教えてほしいと求めました。","respondent":"崎村企画課長","answer":"来年度の無償化を進めていくがん検診の仕事ですとか、アピアランスケアの仕事のほかに、母子保健の仕事についても行っているところです。複数配置することによって機動的に進めていけるようなところについては、複数の係長を配置して進めていくといったところです。","id":"exchange-006"},{"speaker":"山本委員","kind":"質問・要望","question":"個別の部分についてもお伺いしたいのですけれども、それは戸籍住民課に関わらず、それぞれ課の窓口にも共通することだと思うのです。この辺りは戸籍住民課に新設しながらも横串連携を図って取りまとめていくという位置づけなのかというのを確認させてほしいと求めました。","respondent":"崎村企画課長","answer":"こちらは戸籍住民課の窓口だけを検討していくということではなくて、各窓口所管課と連携しながら、効率的なのかというのを検討していくために。そういったところで、適切に事務を執行していくために体制の強化を図るといったところで…","id":"exchange-007"},{"speaker":"山本委員","kind":"質問・要望","question":"おっしゃっていただいているとおり横串連携をして、区民目線での使いやすい窓口になるようにぜひ進めてほしいと求めました。運用のほうもスムーズにいくように進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-008"},{"speaker":"塚本副委員長","kind":"質問","question":"今の山本委員の話にもちょっとつながる話なのですけれども、企画経営部のところでいうと、施設マネジメント支援担当主査制みたいなのを新設。人員を増やせばいいのではないかという話ではなくて、そこが組織体制になるのだという意味、そこをちょっと説明を求めました。","respondent":"崎村企画課長","answer":"説明が不十分なところがございましたけれども、区としてどう対応していくのかというところを検討、考えていかなければいけない仕事です。そういったことで仕事を進めていかなければいけないというところで、新設した、担当主査制に移行させていただきたいです。","id":"exchange-009"},{"speaker":"須貝委員","kind":"質問","question":"１点だけ、推進する課、またはそういう事業部というのは存在するのか尋ねました。","respondent":"崎村企画課長","answer":"今は企画経営部のデジタル推進課において、例えばＡＩによる業務効率化、業務改善というのを担って検討しているところです。","id":"exchange-010"},{"speaker":"須貝委員","kind":"質問・要望","question":"各事業部は統括して積極的に進めていくというのが社会の流れだと思うので、そういう方面もぜひ検討していただきたいと私は思います。組織改正の中にそういう一言が入っていないというのは、ちょっと遅れているのではないかと私は思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"}]},{"id":"topic-02","title":"令和８年度都区財政調整","agenda":"令和８年度都区財政調整","exchanges":[{"speaker":"石田（ち）委員","kind":"確認","question":"５ページなのですけれども、再調整のほうなのですが、追加するということなので、６項目が、品川区の場合は幾らになっているのか、それが追加されるということなので、最終補正になってくるのかなと思うのですけれども、その確認をお願いします。","respondent":"加島財政課長","answer":"おっしゃるとおり、最終補正予算のほうに今、反映させていただいておりまして、その額は約２３億円です。","id":"exchange-012"},{"speaker":"西本委員","kind":"質問","question":"この算定の方法というのはどうなのでしょうか、やらざるを得ない状況になってしまっていると、ちょっと弊害も出ているのかなという感じがするのです。ちょっと難しいかもしれないですけれども、どうなのか尋ねました。","respondent":"加島財政課長","answer":"社会経済情勢に合わせて、これはやる意義があると考えたのであれば、財調算定されていなくても実施することもあります。区としてどの事業を実施するかというのは、区民の利益に資するかどうかということを考えて事業を実施するかということを決めているところです。","id":"exchange-013"},{"speaker":"西本委員","kind":"質問","question":"５６％が今後どこまで伸びるのか、それとも６０％ぐらいはできるのかとか、そこら辺のめどはいかがでしょうか。区の中でいうと大体これぐらいは欲しいなどというところは、２３区のほかの区の同意というか、方向性とかという考えはあるのか尋ねました。","respondent":"加島財政課長","answer":"先ほど最後のほうで委員から区立児童相談所の話がございましたけれども、令和８年度にも２区の開設が予定されているところです。区立児童相談所につきましては、特別区としては役割分担の変更というところで受け止めて配分割合の変更がなされたというふうに考えております。","id":"exchange-014"},{"speaker":"西本委員","kind":"質問・要望","question":"そこはどういう配分になるのでしょうか。それから、在り方検討会は、確かに平成１２年の方針のままなのか尋ねました。","respondent":"加島財政課長、崎村企画課長","answer":"私のほうから児童相談所の関係についてお答えします。児童相談所を開設している区のみが算定されているので、開設していない区につきましては、児童相談所に関する経費は算定されておりません。 平成１９年１月から都区の在り方検討委員会ということで、都区の役割分担について検討してきたところです。平成２３年１月までに、特別区の区域の検討が必要といったところがございまして…","id":"exchange-015"}]},{"id":"topic-03","title":"品川区総合庁舎における東京ベイｅＳＧプロジェクト先行プロジェクト（ＤＡＣコート）の実証実験","agenda":"品川区総合庁舎における東京ベイｅＳＧプロジェクト先行プロジェクト（ＤＡＣコート）の実証実験","exchanges":[{"speaker":"澤田委員","kind":"質問・要望","question":"なぜここが選ばれたのか教えていただきたいということと、各エリアに設置されるのかというのを教えていただきたいということ、今後の区の施設などにもＤＡＣコートが塗布されていくのかというのを教えてほしいと求めました。","respondent":"佐藤経理課長","answer":"設置については、清水建設のほうにお願いして設置いただくことを予定しておりまして、なるべく目につくようにというところで調整中であります。具体的にはまだ特にありませんけれども、総合的に判断いたしまして、検討していくということになろうかと思います。","id":"exchange-016"},{"speaker":"西本委員","kind":"質問","question":"それから、検証とはどんなことやるのですか。どういう結果なのかというのは興味があると思うので、それの公表というのはどういう形になるのか、その進め方を説明を求めました。","respondent":"佐藤経理課長","answer":"もう一点、報告会というのが定期的に行われているようで、その場でホームページ等を通じて公表されるということが１つあります。清水建設のほうも新しい技術ということで積極的に自社のホームページ等で公表するというふうに聞いております。","id":"exchange-017"},{"speaker":"西本委員","kind":"質問","question":"いつまでやるのでしょうか。その期間で十分なのか尋ねました。","respondent":"佐藤経理課長","answer":"今後先方と話し合ってというところになろうかと思いますけれども、先方の希望としては、この庁舎が解体されるまでということで聞いております。なるべく長くデータを取りたいというふうに聞いております。","id":"exchange-018"},{"speaker":"西本委員","kind":"質問","question":"これは設置するだけなので、安全面とかは多分問題ないのかなとは思うのですけれども、そこら辺の業者とのやり取り、会社とのやり取りは、迅速に対応してくれる状況にあるのか、安全面について説明を求めました。","respondent":"佐藤経理課長","answer":"ＤＡＣコートを塗ることで、ＣＯ２の固定化が図られるのですが、コンクリートの中の鉄骨の腐食を抑える効果もあるというふうには聞いております。もちろん解体までの期間に大きく影響するものではないかとは思いますけれども、安全面については確認しております。","id":"exchange-019"},{"speaker":"須貝委員","kind":"質問","question":"その状況下で、今回ＤＡＣの実証実験をやるということは、ちょっとおかしい、不可解な気もするのですが、どうなのでしょうか。何で既存構造物、古い建物で劣化している状況の中でやらなければいけないのか、その辺について説明を求めました。","respondent":"佐藤経理課長","answer":"２番目の既存構造物になぜやるのかということです。ＣＯ２の吸収量なのですけれども、塗ることで１.５倍の吸収量があるというふうに、一定の効果はあるというふうに考えております。","id":"exchange-020"},{"speaker":"須貝委員","kind":"質問・要望","question":"もう一度繰り返しますけれども、まだ確立されていないような話も我々は聞いていますので、ぜひ確認してほしいと求めました。雨ざらしのところと雨ざらしではないところで確認するというのは、ちょっと不思議な気がしましたので、それだけは指摘します。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-021"},{"speaker":"石田（ち）委員","kind":"質問","question":"これから市場に出していくに当たって検証していくということなのですけれども、塗布されるのは品川区だけなのですか。ほかの区でも取り組まれるのか伺いたいです。","respondent":"佐藤経理課長","answer":"今回この技術に関しては品川区だけということで聞いております。","id":"exchange-022"},{"speaker":"松本委員","kind":"質問","question":"今のところなのですけれども、逆に言ったら、なぜ品川区なのかというのがよく分からなくて、似たような構造物だったら、これは東京都のプロジェクトなので、都側がやればいいのではないのかとぱっと浮かぶのですけれども、ここはなぜ品川区なのか尋ねました。","respondent":"佐藤経理課長","answer":"その調整の中で、例えば既存の建物を使うのであれば、総合庁舎を使ってできるのではないかという投げかけをしてやっているところです。東京都の取組は今後を見据えたところですので、広く言えば区民のためにもなるということもありますので、協力しているというところです。","id":"exchange-023"},{"speaker":"松本委員","kind":"確認","question":"今周りからもざわざわと出た、これは庁舎を取り壊す前提だから、それが理由であるということか、最後にそこだけ確認しておきます。","respondent":"久保田企画経営部長","answer":"経理課長からも説明がありましたように、実際形になったものとしては、垂直水耕栽培といったものがあります。今回庁舎を壊すことを前提でやるものではありませんので、その辺はご理解いただければと思います。","id":"exchange-024"},{"speaker":"松本委員","kind":"意見","question":"区として環境問題に取り組むために、当局でもこういうことをやっていただけるのはよいことかなと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-025"}]},{"id":"topic-04","title":"固定資産税および都市計画税の軽減措置の継続","agenda":"固定資産税および都市計画税の軽減措置の継続","exchanges":[{"speaker":"西本委員","kind":"確認","question":"軽減措置の内容は３つありますけれども、これは全く同じ、今までと変わらないという確認でよろしいでしょうか。そういうのは反映されなかったのか尋ねました。","respondent":"宮澤税務課長","answer":"２つ目の、毎年度継続しています。まず軽減措置が、２３区全域で約７００億円弱という形で軽減しているというところで、総合的に判断して毎年決めていくということを伺ってあります。","id":"exchange-026"},{"speaker":"須貝委員","kind":"質問・要望","question":"法人分ですか、これだけの金額が入っているにもかかわらず、いつまでここにこだわるのかというのが私は分からないのです。東京都は財源が豊かなのですから、大変でしょうけれども、毎年向こうに申し述べていただきたいと私は思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-027"}]},{"id":"topic-05","title":"被爆樹木二世の苗木の植樹","agenda":"被爆樹木二世の苗木の植樹","exchanges":[{"speaker":"澤田委員","kind":"質問","question":"近隣の小学生と一緒に植えたり、そういうのもあったらいいのかなどとふと思ったのですが、何かそういうイベント的な感じでやったりはしないのかというところをまず説明を求めました。","respondent":"藤村総務課長","answer":"長崎に毎年千羽鶴を持っていっているのですけれども、それを折ってくださった青少年がおりますので、その方に一緒に植樹していただこうかなと思っています。","id":"exchange-028"},{"speaker":"澤田委員","kind":"質問","question":"千羽鶴とか、平和に関係する皆さんで植樹されるということで、それはそれで素敵だなと思って今伺っていました。せっかく植えたので、これから育っていく経過なども時々報告されたらいいなと思っているのですが、いかがか尋ねました。","respondent":"藤村総務課長","answer":"発信方法としては、まず植樹しますというところをホームページ、ＳＮＳ等で発信したいと考えています。その後の経過等につきましても、適宜状況を見て、成長に合わせて何かお伝えするところがあれば、ＳＮＳ等で発信したいと思っています。","id":"exchange-029"},{"speaker":"西本委員","kind":"質問","question":"植樹した後、プレートか何かで説明文、看板を立てるとか、そういうのをやるのか尋ねました。","respondent":"藤村総務課長","answer":"今のところ、プレートというのが、この樹木自体は平和市長会議という団体経由で譲渡いただくので、譲渡いただいたときにプレートのほうも同時にいただけるということですので、そちらのプレートを設置しようかと考えているところです。","id":"exchange-030"},{"speaker":"石田（ち）委員","kind":"質問・要望","question":"苗木というのは、どのぐらいの大きさなのでしょうか。教えていただきたいのと、木の前に盾みたいなものがあると格好いいなと私は思ったのですけれども、それがどういうレベルなのかを伺いたいと思います。","respondent":"藤村総務課長","answer":"そういったことがないように、公園課とも協議して、しっかり育てていきたいと考えております。今回は取りあえずそちらのプレートを設置する形になりますが、プレートだけでなくというところについては検討していきたいと思います。","id":"exchange-031"},{"speaker":"須貝委員","kind":"意見","question":"特段異論はありませんけれども、１分でも２分でも子どもたちにお話ししていただけるような環境のところに植樹したほうがすごく有効だと私は思います。意見だけですとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-032"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/237549?Template=document&Id=7331#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=5&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":26837,"voices":92}},{"id":"r08-20260226-21","meetingId":"r08-1t","date":"2026年2月26日","dateIso":"2026-02-26","committee":"子ども若者支援・共生社会推進特別委員会","time":"午前１０時００分～午前１１時１２分","status":"正式会議録","sourceType":"formal","overview":"子ども若者支援・共生社会推進特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を30件整理しています。","topics":[{"id":"topic-01","title":"特定事件調査","agenda":"特定事件調査","exchanges":[{"speaker":"澤田委員","kind":"質問・要望","question":"なぜ子どもたちがご家族のケアをしなければいけない状況になったのか、そういう原因のところの質問項目はあったのかということと、内訳などご存じだったら教えていただきたいなと思います。","respondent":"吉野子ども家庭支援センター長","answer":"令和５年１１月２８日、あと、小さなお子さんに対してのケアが必要になっているというところになります。食事の用意や後片づけなどが一番多く３６.２％となっており、中学生、高校生も同じような形になっております。","id":"exchange-001"},{"speaker":"澤田委員","kind":"質問","question":"文教委員会の報告を拝見しておらず申し訳ありません。今教えていただいたことで、「大丈夫ですか」という声かけだったりとか、されているのか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"そうしたことによりまして、実際に自分が使いたい時間であったりとかそういったところがなかなかとれなくなってしまうというような状況になります。そういったところも少しずつ丁寧に、これは本当に寄り添いながら丁寧にやらないと大きな問題になってしまいますので…","id":"exchange-002"},{"speaker":"澤田委員","kind":"意見","question":"うまく伝えられていなくて申し訳ないのですけれども、お母さん方へのアプローチ、保護者へのアプローチというよりかは、そっちも大事だと思うのですが、そういうケアをしないといけない対象がいるお子さんたちのほうを見守っていく方法とかが何かあるといいなというところでしたとの意見を述べました。","respondent":"吉野子ども家庭支援センター長","answer":"お子さんに、今後どうしたいのか、今何が負担なのか、将来的に何がしたいのかといったところを丁寧にお聞きします。それによって何が足りないのかというところを洗い出しまして、そしてそれを親御さんにもお伝えしていくといった丁寧な対応をしております。","id":"exchange-003"},{"speaker":"澤田委員","kind":"質問・要望","question":"大丈夫かなという形で見守っていただけたらと要望して、次に移りますけれども、とてもすばらしいなと思いながら聞かせていただいていました。ピンポイントでここだということなのか、それとも広く募集されてなのか、教えてほしいと求めました。","respondent":"吉野子ども家庭支援センター長","answer":"今回資料に載せさせていただいたものは、会社のほうからお声をおかけいただきました。私どもからもいろいろな会社にお呼びかけして、こういった支援とか啓発活動を行っているところです。","id":"exchange-004"},{"speaker":"おぎの委員","kind":"質問・要望","question":"小学生で約７.５％、中高生で約５％というこの数字なのですけれども、この辺に関して何かご意見または分析しているものがあれば教えてほしいと求めました。","respondent":"吉野子ども家庭支援センター長","answer":"私どもなのですけれども、在宅介護支援センターや主任児童委員などの皆さんとか、地域の方々に対してアンケートを実施しようと考えています。実際には正直にお答えになられたかどうかというところだと思うのですけれども、小学生は純粋に…","id":"exchange-005"},{"speaker":"おぎの委員","kind":"質問","question":"なるほどと思いました。直接的支援のところでも配食支援が令和７年度は９家庭９１７件で、今、どんな感じでつなげているのか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"恐らく食事が一番入りやすいサービスだと考えています。委託事業者以外にも、私どもの職員が都度ケースワークをしていますので、そこで発見していきたいと考えています。","id":"exchange-006"},{"speaker":"おぎの委員","kind":"質問・要望","question":"私だけで長くなってしまいますので、あと１点だけ。お持ちになられている中でのお仕事なのかというのが１点と、こちらの２点、お願いします。","respondent":"吉野子ども家庭支援センター長","answer":"チャーム・ケア・コーポレーションに関しましては、委員のご認識のとおりでして、５つある介護老人ホームでこちらのほうは実施します。それからサンリオとの連携なのですけれども、こちらは引き続き実施していきたいと考えております。","id":"exchange-007"},{"speaker":"鈴木委員","kind":"質問","question":"支援が必要なのではないかというところに対してのフォローアップはどういうふうにされたのかということを伺いたいのと、私たち区議会としても。そういう体制というのがどの程度でされているのかという点についても伺いたいと思います。","respondent":"吉野子ども家庭支援センター長","answer":"配食支援であったりとか、訪問支援とか、そういったところの構築に結びついたと考えています。もし相談の数が多くなった場合には、もう一度体制のほうは考えていきたいと考えております。","id":"exchange-008"},{"speaker":"鈴木委員","kind":"質問","question":"高齢者福祉、障害者福祉、品川区ではそういう連携の仕組みというのがどういう状況になっているのかということも伺いたいと思います。家庭の状況を把握されている部分が見えてくるのではないかなと思うのですけれども、いかがでしょうかというところで、お願いしたいと思います。","respondent":"吉野子ども家庭支援センター長","answer":"先ほど言った申請フォームを活用して、そちらはご本人に対しての調査みたいな形で実施しようと考えています。重層的支援体制もありますし、私ども子ども家庭支援センターは、その都度対応しているところです。","id":"exchange-009"},{"speaker":"鈴木委員","kind":"質問","question":"１８歳までで終わるわけではないので、４０歳未満まで対象にするということになったのだと思うのですけれども、すごく大事なことだなと思います。それからさらに３９歳まで、そこでの支援というのは今の時点でどういうふうに考えられているのか、その点についても伺いたいと思います。","respondent":"吉野子ども家庭支援センター長","answer":"はご自身に丁寧にお話を聞いていくというところになります。今後どうしたいのか、そういったところをお聞きして、丁寧に寄り添いながら対応していきたいと考えています。","id":"exchange-010"},{"speaker":"鈴木委員","kind":"質問","question":"サポートプランをつくっていくということも書かれていたのですけれども、そのサポートプランに対しては、区としてどうなっているのかということ。さらに４０歳未満までこれから把握されるということになって、いろいろとこれだけ見えてきた段階で、その点はいかがか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"いわゆる児童相談であったり、そういったところは全てつくることになっておりますので、サポートプランは作成していくものになります。支援方針をつくるという点ですけれども、こちらは今、区のヤングケアラーの基本的な支援方針もつくっていくということではあります。","id":"exchange-011"},{"speaker":"鈴木委員","kind":"質問・要望","question":"実態が見えてくることで、支援につながり、それがさらにどんどん充実していけるように、ぜひとも取組を進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-012"},{"speaker":"西村委員","kind":"確認","question":"私も幾つか伺いたいのですけれども、多層的にしていただいているなというのを改めて今、確認させていただきました。令和７年９家庭で９１７件というと、これは１家庭で平均どれぐらいサポートに入っておられるのか、分かればまずお聞かせいただけますか。","respondent":"吉野子ども家庭支援センター長","answer":"基本的には、こちら、週２日程度入ることになっておりますが、ただ、状況によっては２日を超えても、必要な場合には臨機応変に対応しております。","id":"exchange-013"},{"speaker":"西村委員","kind":"質問","question":"特に支援が必要なご家庭だったら、週２回、食事を届けながら家事支援にも入っている。ばらばらだと思うのですが、そうしたイメージでよろしいか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"委員のご認識のとおりです。","id":"exchange-014"},{"speaker":"西村委員","kind":"質問","question":"いろいろなところと連携がどれだけ進んでいるのかなというのを伺いたくて、どういう対策とか改善策をとっておられるのか、実際の今の連携体制を伺えればと思います。","respondent":"吉野子ども家庭支援センター長","answer":"私どもなのですけれども、支援が途切れないように、定期的な訪問を行っております。ヤングケアラーの担当だけではなくて、子ども家庭支援センターの相談には福祉職が何人かおりますので、センターとして対応しています。","id":"exchange-015"},{"speaker":"西村委員","kind":"意見","question":"ぜひそこは引き続きお願いしたいなというのと、次に向けて強化していくべきだと思っておられるところがあれば、説明を求めました。","respondent":"吉野子ども家庭支援センター長","answer":"こういったところは保健センターと連携しながら、きちんとつなげていきたいと考えております。それから、私ども行政だけではとても見切れない部分もありますので、地域のネットワーク構築も図っていきたいと考えております。","id":"exchange-016"},{"speaker":"つる委員","kind":"質問","question":"先ほどヤングケアラーのパーセンテージとか人数についてはほかの委員から質疑がありましたが、過去の質疑でも幾つか言及はあるのですけれども、いわゆる子どもの貧困率の部分とヤングケアラーの重なる部分ですね、当然限らずというところもあるとは思うのですが、そこの関係性について説明を求めまし…","respondent":"吉野子ども家庭支援センター長","answer":"貧困率とヤングケアラーの関係なのですけれども、ご家庭の状況を見ますと、ひとり親であったりとか、経済的に困窮されている状況もやはり散見されますので、全くここの因果関係がないというわけではないと思うのですけれども、こちらはきちんとした分析を進めたいと思います。","id":"exchange-017"},{"speaker":"つる委員","kind":"質問・要望","question":"貧困の世帯があれば、そこについては先ほどご答弁いただいたとおりだと思いますので、ぜひ今後もしっかりと確認して教えてほしいと求めました。具体的な部分で幾つか伺いたいのですが、アクセスに伴走するような部分のサポートはどんな感じなのかということをまず説明を求めました。","respondent":"吉野子ども家庭支援センター長","answer":"アクセスの方法なのですけれども、実際には、相談自体が、ご本人から来る相談がとても少ない状況にあります。少しずつですけれども信頼関係を構築して、こういったサポート、支援につなげていくということにしております。","id":"exchange-018"},{"speaker":"つる委員","kind":"質問","question":"そこのところからのアクセス、もしくはこちら側からのアウトリーチとかアプローチみたいな部分というのはどういう形でやっているのか教えてください。在宅介護支援センターとか先ほどいろいろあったのですけれども、潜在化している部分へのアプローチのところを説明を求めました。","respondent":"吉野子ども家庭支援センター長","answer":"今困っていることは何ですかと、何回か行ってやっと聞き出せるような状況ですので、そういったところでのアクセスをしております。潜在的なところに関しましては、先ほどちょっとお伝えしたとおり、今後アンケート調査を実施したいと考えています。","id":"exchange-019"},{"speaker":"つる委員","kind":"質問・要望","question":"そのアンケート対象について教えていただきたいというのと、助けてと気軽に言える社会を品川区がつくっていくことがすごく大切なのかなと。全体に対する啓発というのでしょうか、ここも一緒なのだなと思ったのですけれども、ここではその対象だけ説明を求めました。","respondent":"吉野子ども家庭支援センター長","answer":"実施時期は調整中ですので、できるだけ多くの関係者を巻き込んでアンケート等を行いたいと考えております。それから、信頼関係を構築するためにそういった部分を見せてもいいというところを引き出せるように、丁寧に対応していきたいと考えております。","id":"exchange-020"},{"speaker":"つる委員","kind":"質問","question":"これは小中高生、表面の観音開きの裏側というのですか、小学生のものにもそこにＬＩＮＥのＱＲコードを載せていただいています。水・木・金の８時半から５時という時間帯だと思うのですが、これは３０代までとあるので、説明を求めました。","respondent":"吉野子ども家庭支援センター長","answer":"ＬＩＮＥ相談とかは２４時間可能でして、令和６年度から大分増えていまして、令和７年度に関しましては２,３７０件ほど来ております。ＬＩＮＥの回答に関しましては、翌日に回答できるような形にしております。","id":"exchange-021"},{"speaker":"つる委員","kind":"質問","question":"実態はどうかということと、２人という中で、今のニーズに合っているのかと。ＬＩＮＥでそれだけ二千何百件というのがありましたけれども、その辺りの見解についても併せて説明を求めました。","respondent":"吉野子ども家庭支援センター長","answer":"基本週３日とはなっているのですが、そういったときにも来ていただいたりとか、大分ご尽力いただいているような状況です。そういったところの面談等は、区民の方のニーズに合うような体制、対応をとっております。","id":"exchange-022"},{"speaker":"つる委員","kind":"質問","question":"当然予算との関係もあったりとか、あとは今まで大変ご苦労された方が、まさにケアとしていらっしゃる。学校に赴いてやるというようなことも可能なのかどうか、やるやらないは別にしても、可能なのかどうかを説明を求めました。","respondent":"吉野子ども家庭支援センター長","answer":"現在も、実は児童相談担当はスクールカウンセラーとお話をしております。こちらのヤングケアラーについても当然、もし必要であれば、スクールカウンセラーの方と相談しながら対応していきたいと思います。","id":"exchange-023"},{"speaker":"つる委員","kind":"質問・要望","question":"ダイレクトに子どもというのですか、面談を学校とか、もしくはさっき言ったような地域子ども家庭支援センターとかでのアクセスのやりやすさですね。そういった部分でのより一層の充実というのは必要なのかなと思いましたので、この辺りもぜひ今後、展開いただきたいなと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"鈴木委員","kind":"質問","question":"先ほどのサポートプランなのですけれども、ヤングケアラーのサポートプランというのは誰がつくることになるのか。それと、それが何件くらいあって、小学生・中学生・高校生それぞれ何件くらいあるのか教えていただけたらと思います。","respondent":"吉野子ども家庭支援センター長","answer":"サポートプランは、実際に赴いたケースワーカーが作成いたします。いわゆる終着点といいますか、実際に件数としましては、例えば配食支援でしたら７家庭であったら７つという形になります。","id":"exchange-025"},{"speaker":"鈴木委員","kind":"質問・要望","question":"はざまの中で支援につながらないというものはないのか、また、こんな支援が必要だということがあったら、その点についても伺いたいと思います。コーディネーターの方のお話を伺ったりとかして、改めて認識できる部分があると思うのです。","respondent":"吉野子ども家庭支援センター長","answer":"認識していくためのところに関しましては、先ほど普及啓発のほうでもお伝えさせていただいたのですけれども、年間２０回ほど研修を開催しています。この２０回は、例えば令和７年度でいきますと、あとは当然区の職員も行っております。","id":"exchange-026"},{"speaker":"ゆきた副委員長","kind":"確認","question":"確認させていただければと思うのですけれども、品川区で行われている食事支援の配送事業とか学習支援の事業というのは、国で定められている児童福祉法あるいは子ども・若者育成支援推進法に基づいて、区で言ういわゆる要綱とか条例に従って行われているという認識でよろしいか尋ねました。","respondent":"吉野子ども家庭支援センター長","answer":"委員のご認識のとおりです。","id":"exchange-027"},{"speaker":"ゆきた副委員長","kind":"質問","question":"その対象となるのかどうなのかというところは、発信の仕方というのはどういうふうに工夫されているのか、この辺についてお聞きできればと思います。","respondent":"吉野子ども家庭支援センター長","answer":"それによって、若者であれば勉強、それから就職準備の機会が妨げられるという方がヤングケアラーという形になります。私どもの子ども家庭支援センターにはそういった支援もありますので、どちらかを使っていくような対応をしております。","id":"exchange-028"},{"speaker":"ゆきた副委員長","kind":"質問","question":"受け手側が、このぐらいでも支援を受けられるのかなというのは、非常に難しいところだと思います。紹介というか、それであったとしても判断するのはなかなか難しいと思うので、その辺についてお聞きできればと思います。","respondent":"吉野子ども家庭支援センター長","answer":"はＬＩＮＥ相談であったりとか小学校のタブレットのほうでご相談いただくというところになります。支援が必要であれば支援するという形で、そのときにも、ご本人の意思をまずは尊重するような状況になります。","id":"exchange-029"}]},{"id":"topic-02","title":"議会閉会中継続審査調査事項","agenda":"議会閉会中継続審査調査事項","exchanges":[{"speaker":"西村委員","kind":"確認","question":"もうあと２回しかないのだなと改めて思っておりますが、テーマも限定的でありますので、まとめを作成していただき、皆さんとまた最後、確認する形でよいのではないかなと考えています。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-030"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/256558?Template=document&Id=7333#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=21&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":20937,"voices":69}},{"id":"r08-20260226-20","meetingId":"r08-1t","date":"2026年2月26日","dateIso":"2026-02-26","committee":"ＳＤＧｓ推進・行財政改革特別委員会","time":"午前１０時００分～午後 ２時４３分","status":"正式会議録","sourceType":"formal","overview":"ＳＤＧｓ推進・行財政改革特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を62件整理しています。","topics":[{"id":"topic-01","title":"特定事件調査","agenda":"特定事件調査","exchanges":[{"speaker":"安藤委員","kind":"確認","question":"その課題の内容、２ページに書かれている解決を目指す社会課題ということと思うのですが、どのような課題を発信したか教えてくださいというのが１つ。まだこれから続くわけですが、その実証期間後の各事業の流れはどのようになっていくのか、再確認させてください。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"しながわシティラボの事業の実施基準を定めてございまして、まずは、その後の継続の可否の判断についても基準の明記をしております。その後の継続の可否を判断するのですけれども、ＫＰＩ以外の部分でも、定量データや定性データを鑑みて総合的に判断をすることとしております。","id":"exchange-001"},{"speaker":"安藤委員","kind":"質問・要望","question":"少し具体的に資料に即して伺いたいのですが、２ページ目の課題解決型の１ですが、これはどういうことなのか分からなかったので教えていただきたい。これはＳＤＧｓで言うどのゴール達成を目指してのことになるのかを伺いたいのと、４については、もう少し具体的に教えてほしいと求めました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"実際に、この夏、実証を進める中で、目標を２０％削減としたのですけれども、月次ベースで約３０％オフの削減効果が出ているという進捗状況です。４番目のコンタクトセンター、区民の方に公開をして、実際の問合せに対応する。","id":"exchange-002"},{"speaker":"安藤委員","kind":"提案","question":"実証実験を重ねていって、働く人にとって、あるいは区民の利用者にとってプラスになるような方向で実践を積み上げてほしいと求めました。実証実験提案型、それとももともとあったものがしながわシティラボに登録したのか伺いたいのと、それぞれについて伺いますとの意見を述べました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"予算化して本格実施をする前に、そちらをトライアルすることによって、効果ですとか影響を確認するということが大きなメリットとして考えております。例えば子育ての分野とかで実施する場合に…","id":"exchange-003"},{"speaker":"安藤委員","kind":"提案","question":"双方のメリットについては分かりました。様々な提案を受ける中で、本当に社会的にどうなのかとか、そこら辺には気をつけてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-004"},{"speaker":"新妻委員","kind":"質問・要望","question":"今日の出されている資料の中の目的で、１点確認を最初にします。目的の中に、自律的取組みを促進するという表現があるのですが、この自律的取組みの解釈を教えてほしいと求めました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"目的にあります、最後の自律的取組みを促進するです。こちらは企業や団体、それぞれのＳＤＧｓの達成に向けた取組を、各自がそれぞれ自律をして取り組んでいただける姿を目指しているものです。","id":"exchange-005"},{"speaker":"新妻委員","kind":"提案","question":"このしながわシティラボの実証実験提案型と、区はどのように、それぞれ判断をされているのか。長期展望に立った、それぞれの団体・企業等のあり方、そこのお考えはどうかお聞きしたいと思いますとの意見を述べました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"この実証実験を進めているところですが、そこに対する、あとは今後の継続についても意見交換をさせていただいたりしております。どういうところで継続ができるのかとか、そこで終了ではなくて、長期的に課題解決を目指せる支援を伴走的にしています。","id":"exchange-006"},{"speaker":"新妻委員","kind":"提案","question":"最後に１点、都市計画課からの提案で、暑熱対策ソリューションの共創が課題として挙がっております。ここの中に、委託をするところがしながわシティラボに関わっている企業であったということで、そこと連携をしてやる考え方なのか尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"２月１０日から発信をしています都市計画課の品川区の夏を冷やす、委員のご指摘のとおり、来年度予算ですシェードポリシーと関連のある課題です。区が考え得る範囲のもの以外で、同じような課題に対して、広く提案を募集する意図で発信をさせていただいたものです。","id":"exchange-007"},{"speaker":"新妻委員","kind":"提案","question":"そうすると既に、数か所からの提案が区に入ってきて、このホームページを確認されたところから、区に、こういうことができるというような提案を受けている段階ということでよろしいか尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"こちらは品川区に限った課題ではなくて、ほかの自治体含めて横展開も見据えて、非常に大きな事業の可能性がある課題だとご提案やお問合せをいただいております。","id":"exchange-008"},{"speaker":"あくつ委員","kind":"提案","question":"提案事業がこれだけあるけれども、先ほどのエアコンの話でも３０％削減という話がありましたが、基本的には採用していく。提案する事業者の実証実験においてのメリットでは認知と信用力の２つある、品川区としては、その事業を本採用していくような流れになるのか尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"その後の継続と可否を判断するということで申し上げておりますが、そこで、ＫＰＩ等を基に判断をしていくということがまず１点です。実証実験を連携させていただきました提案事業者がいらっしゃいますが、地方自治法ですとか、公正な手続を進めていくという流れで考えています。","id":"exchange-009"},{"speaker":"あくつ委員","kind":"提案","question":"最後に１つだけ伺いたいのは、そのような事業を提案されて実証実験に臨む、そこにまず敬意を表したい。別に個別の事業ではなくてもいいのですが、そういう期待を持たれているのか、手応えを教えてほしいと求めました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"所管課と実証実験をマッチングして進めていく中で、環境課と話をする中で、かなり手応えがある事業だと捉えていると聞いております。そこを、電気料金の削減などにつながるようなところをこれから推し進めていくことによって、非常に希望を見いだしていると聞いているものです。","id":"exchange-010"},{"speaker":"あくつ委員","kind":"質問","question":"令和７年１１月から令和８年２月で、これは一応２月までになっていますけれども、もう少し詳しく教えてもらってもいいか尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"課題解決型の株式会社タンソーマンＧＸとの実証事業です。２月までの実証で、このアプリを設置することによって各中小企業の皆様にお試しいただくような内容でございまして、こちらについては。","id":"exchange-011"},{"speaker":"山本委員","kind":"質問・要望","question":"２回の交流会、それから専門部会を４回開催されているということなのですけれども、参加者の皆さんからのアンケートは取っているのでしょうか。取っておりましたら、回答率や満足度、それから改善等の要望などを説明を求めました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"顔の見える関係性を構築するような交流会を実施してまいりましたが、テーマを絞った議論などができるような会も検討してまいりたいと考えていまして。それからオール品川で、地域課題の解決は行政だけではなくて…","id":"exchange-012"},{"speaker":"山本委員","kind":"提案","question":"それから実証実験提案型、現在進んでいる状況を教えていただいたのですが、それぞれどれぐらいあったのでしょうか。なかなか難しいということで減っているのか、実態を確認させていただきたいという趣旨で、それぞれ応募数がどれぐらいだったのかをお伺いいたしますとの意見を述べました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"やはり実施基準にのっとりまして、区が目指している社会課題の解決と認識そごがあったりですとか、実証実験に実際につながったのは１０件になります。区としては、目標を上回るまで順調に推移していると考えていますし、質の高い実証実験につなげていきたいと考えているところで…","id":"exchange-013"},{"speaker":"山本委員","kind":"提案","question":"この辺りの状況について確認をさせてください。実証フィールドの提供だけにとどまらず、そのような２次要望だとか、効果的な資金支援も今後考えていくことがすごく有効と思いましたとの意見を述べました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"今年度から開始しました参加企業・団体からの１分ピッチも、企業・団体、社会課題の解決を目指してまいりたいと考えております。もちろん審査はありますが、そのような事業費の支援策もあることは、専用のホームページも含めてご案内をしています。","id":"exchange-014"},{"speaker":"山本委員","kind":"質問・要望","question":"要望をします。このＳＤＧｓ宣言企業にご参加いただいていることは確認をいたしましたが、今回、これは有効だと思いました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-015"},{"speaker":"あくつ委員","kind":"質問","question":"私からは、しながわシティラボ実証事業の、生成ＡＩを活用した予算編成・行政評価実施の実証実験について伺いたいと思います。もう１つ、つまり応募があったのかとか、その辺りを伺います。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"手を挙げていただけるのかを、まず見てみたいというのも１つ、課題を発信した理由としています。ご提案をいただいているような状況ですので、非常にこの分野と申しますか、生成ＡＩの分野の方には興味を抱いていただいているものと考えています。","id":"exchange-016"},{"speaker":"あくつ委員","kind":"質問・要望","question":"こうしたことを専門的にやる会社が、株式会社ＷｉｓｅＶｉｎｅ以外にもあるということで感心をいたしました。この株式会社ＷｉｓｅＶｉｎｅも今回の実証実験についての成果発表をぜひ行っていただきたいのですけれども、その辺りのご予定とかあるのか尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"当然、実証実験、令和８年９月までを予定しておりますので、そのときに、あらかじめ立てたＫＰＩに対する効果検証等は実施していくものです。一般公開をするような成果発表会は今のところ予定はしていないのですが、対外的にお伝えしていくかを検討してまいりたいと考えておりま…","id":"exchange-017"},{"speaker":"あくつ委員","kind":"質問","question":"当然、なるべく幅広くオープンに、そうした対外的な成果発表をお願いしたいと思います。プレス発表で新規の事業として発表されていると思うのですが、既に予算額がついているのですけれども、これはどのような理由か尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"令和８年度の本格的な検証に入るために、効果が出るものがあるのかを、この実証実験を通して見極めたいと区としては考えております。先ほどの答弁と重なってまいりますが、この事業者に限らずに、そこは広く進めてまいりたいと考えているところです。","id":"exchange-018"},{"speaker":"あくつ委員","kind":"質問","question":"この３番、４番、生成ＡＩ関係のものは、そもそも、この事業、ピンポイントではなくて、生成ＡＩを使った実証を、ざっくりと予算化しようと事前に考えていたから、今回、予算計上されているという理解でよろしいのか尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"委員、ご指摘のとおり、区として、この部分の実証を行うための予算をつけて実施を行うということがまずございまして、そのための前段階として広く民間提案を募って、概念実証をするためにしながわシティラボを活用したです。","id":"exchange-019"},{"speaker":"あくつ委員","kind":"質問","question":"株式会社ＷｉｓｅＶｉｎｅと株式会社ＳＨＩＦＴは、予算案が可決されてからになりますけれども、きちんと報酬、会社として自らの持ち出しはないと、しっかりとその対価を受け取って実証実験を行うということでよろしいのか尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"事業者の負担についてですが、このしながわシティラボの枠組みでの実証実験につきましては、提案事業者の負担でお願いをしておりますので、２月から９月の実証に関しましては、株式会社ＷｉｓｅＶｉｎｅと株式会社ＳＨＩＦＴに負担いただく形にます。","id":"exchange-020"},{"speaker":"あくつ委員","kind":"質問","question":"では、この予算案のお金は何に使うのですか。２,３６３万円。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"そちらは、この実証実験、いわゆる概念実証が終わった後に、区として本格的に実証をするための経費でございまして、そちらについて改めて事業者選定から進めてまいりたいと考えています。","id":"exchange-021"},{"speaker":"こしば委員","kind":"提案","question":"実証事業に当たっての課題解決型を４点取って、実証実験提案型は６点ございましたけれども、各部署で課題が出ていたのは事実なのか尋ねました。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"これまで区の各部署から課題を出してもらっておりまして、合計で１２の課題を出してもらっています。昨年度、ワークショップなども併せて実施しまして、どうしたら民間から提案を募りやすい課題の発信ができるのかも並行して研修を進めてまいりました。","id":"exchange-022"},{"speaker":"こしば委員","kind":"質問","question":"私も２回か３回ぐらい、腹落ちできていなくて、多世代交流という意味では分かります。この課題が出てきたのか、私には理解ができなかったので、その辺りを分かる範囲で教えていただけますか。","respondent":"井添ＳＤＧｓ推進担当課長","answer":"来年度以降、本格的に実施するのですが、そのような環境分野の先進的なプロジェクトとして東京都が進めているものです。そことの連携も含めて、環境だけではなくて地域に還元できるように取り組みたいということで、この実証実験をさせていただいているところです。","id":"exchange-023"},{"speaker":"こしば委員","kind":"質問・要望","question":"ＣＤの廃材をいろいろと様々なものに活用していく、すごくリサイクルで、そこからまた芸術作品を生んでいく取組があるのです。環境に向けた取組を学び、大きな発見をもらえるよう、区からまたさらに周知を展開してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"あくつ委員","kind":"確認","question":"だから今日、副委員長に確認もしたのですけれども、やるという。だから少しだけ時間を入れて、あと理事者のご都合もあると思うので、午後もいいのだったら、そのようにしたらいいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-025"},{"speaker":"安藤委員","kind":"質問・要望","question":"それで、実際廃止した事業は幾つあったのか、そして主なもの、どんなものを廃止したのかご紹介いただきたいのが１つです。健康推進部、都市環境部のそれぞれの主な削減要因は何だったのか、ご紹介ほしいと求めました。","respondent":"吉岡政策推進担当課長","answer":"一方で、事業の完了ですとか廃止に向けた検討が、それ以外になります。削減項目は非常に多岐にわたりますので、一部の紹介となりますけれども、ご了承いただければと思います。","id":"exchange-026"},{"speaker":"安藤委員","kind":"確認","question":"提出資料の2)が一部ということですけれども、削減されたのは全て一覧となって額と一緒に出てくるのか、確認させてください。具体的には、これは大丈夫なのか、どういうことをやるのか、もう少し伺いたいと思います。","respondent":"吉岡政策推進担当課長","answer":"令和６年度版という形になりまして、あるいは財務情報に関しては２年分持っているのですが、これを見つけていくです。当然ながら最終的な判断は区で行ってまいりますので、ある種、そのような判断材料となるものを抽出するというところが活用方法です。","id":"exchange-027"},{"speaker":"安藤委員","kind":"質問・要望","question":"住民福祉の増進なわけですから、どう整理するかとか、まだそういう段階だと私は思うのです。政策評価について伺いたいのですけれども、これはどのような提言だったのかもう少し伺いたいのと、その理由も伺います。","respondent":"吉岡政策推進担当課長","answer":"このような子ども料金無償化ということで区として検討したのが提案の考え方です。福祉部の予算も令和８年度予算、７年度予算に比べて増えておりますので、そのようなところに振り向けしています。","id":"exchange-028"},{"speaker":"安藤委員","kind":"質問・要望","question":"今年でやめるということなのですか。いい政策なわけですから、柔軟的な補正予算を組むなど、必要な予算をつけていただきたいと考えています。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-029"},{"speaker":"あくつ委員","kind":"質問","question":"３４だったのが１６になったということなので、先ほどＢが一番多い、いわゆる現状維持。これはどういう政策の方向性の転換なのか、転換ではないのでしょうけれども、そのような分析を教えてほしいと求めました。","respondent":"吉岡政策推進担当課長","answer":"３年続けていくことになりますと、新たに新規あるいは拡充した事業も、課題というのは少々出てくるようなところもあります。区の姿勢を示すという意味ではＣ評価とつけているようなこともありますので、そのような意味でＡ評価が少なくなってきていると考えております。","id":"exchange-030"},{"speaker":"あくつ委員","kind":"質問","question":"３回まで評価をしていくと、どうしても基準、何かこう守りに入っているようなイメージにも取られかねないように見える。どうしてもそのようになってしまうというところと、それでも、そのように感じることもあると思って伺ってみました。","respondent":"吉岡政策推進担当課長","answer":"令和６年度の予算事務事業ということで、新たに事業科目を創設するようなものになってくると、そのような部分の影響もあるとは考えてあります。事業評価、これはしっかりとそれぞれの事業を見定めた上で今後の方向性をやっていくので、引き続き力を入れながら進めてまいります。","id":"exchange-031"},{"speaker":"まつざわ委員","kind":"質問","question":"教えてほしいのですけれども、令和７年度の予算削除額、これは結局、去年から比べて５億円削れなかったということか尋ねました。","respondent":"吉岡政策推進担当課長","answer":"削減できなかったのかという質問に対する回答ではないかもしれないのですけれども、数字としては、昨年度は２０億円を超える削減額がありましたので、それよりも５億円少ない金額です。","id":"exchange-032"},{"speaker":"まつざわ委員","kind":"意見","question":"評価の事業数はあまり変わりがないと思っているのです。だからそこら辺で５億円という部分が削り切れなかったというのは少し失礼ですが、何かそのようなスクラップの思い、考え方を聞かせてくださいとの意見を述べました。","respondent":"吉岡政策推進担当課長","answer":"令和５年度から始めた事務事業評価ですけれども、この間、事務事業評価は行っておりませんので、久しぶりに取り組むものです。そのようなもので、削減だけではなくて、事業の効率化も含めて事務事業評価を進めていきたいと考えております。","id":"exchange-033"},{"speaker":"まつざわ委員","kind":"意見","question":"これは何か、素人ながら、なぜこういう財務の決裁の電子化が進まないのか。そうすると、決裁のそのようなもの自体を見直さなければいけないのかと思うのですけれども、そこら辺はとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-034"},{"speaker":"山本委員","kind":"質問","question":"２０億円をめどとしての削減を進めてきて、今年は１５億円にすぼまっている、削減し切れない状況だというご説明がありました。短期的にすぐに見直すべきものと、中長期的に見直していくべきものの色分けも、どう考えるかご意見ほしいと求めました。","respondent":"吉岡政策推進担当課長","answer":"その中で、方向性といたしまして、事業の廃止等に向けた検討の方向性の項目もあります。検討ということで、今後に向けた検討という形で中長期的な考え方を示すことで、少し色分けをしているようなところです。","id":"exchange-035"},{"speaker":"山本委員","kind":"質問・要望","question":"これがさらに４年、５年と続いていく中で、そのような検討を要望いたします。区のこの対応は、提言を受けて誰がどのように考えて、このように対応しようとなったのか確認をさせてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-036"},{"speaker":"こんの副委員長","kind":"質問","question":"個別の掘り下げの話ではなくて、ここに書いてある個別の政策についてではなく、事務事業評価シートそのものの表現の仕方だとか、運用の仕方だとか、そのような質問でお願いしたい。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-037"},{"speaker":"山本委員","kind":"質問","question":"時系列で表現するべきですとか、行政評価全体で外部機関の評価をするべきとか、その仕組みについてご質問やご提言をさせていただいていると見ます。これは、その中身については、今回触れないということなのか尋ねました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-038"},{"speaker":"山本委員","kind":"質問・要望","question":"予算特別委員会でお聞きするということですか。多分要望としては含まれていると思いますので、この政策評価委員会の方々、そのような声を聞いてお答えをいただきたいという思いです。","respondent":"吉岡政策推進担当課長","answer":"資料に書いてあります１１月１０日に、これは開始は事前検討会で８月以降、この事業に関係性が１つあります。中長期的な検討で考えた部分もありますけども、過去の政策評価でいただいた部分も、そのような形で反映させていくように今後とも努めてまいります。","id":"exchange-039"},{"speaker":"安藤委員","kind":"質問・要望","question":"資料の２ページ目の変更ですけれども、それは経費を抑えるという意味なのか、伺います。３つ目は、この事業で参入する企業というのは、どこで収益を上げると考えているのか伺います。","respondent":"吉岡政策推進担当課長","answer":"実施方針をさらに細分化いたしまして、それぞれの業務を細分化いたしまして、いわゆる仕様書に近いようなものが要求水準書です。変更内容につきまして、建設、どのような民間事業者が乗っていただけるような我々の提案をしていくかというのがキーになってくると思います。","id":"exchange-040"},{"speaker":"安藤委員","kind":"提案","question":"にわかに承服し難いのですが、これはなぜなのでしょうか。４つ目に行ってしまいますけれども、これも大きな変更だと思うのですが、そちらについても伺いますとの意見を述べました。","respondent":"吉岡政策推進担当課長","answer":"地域の説明会でも、同じような施設がここに存在するのはどうなのかというご指摘もいただいて、しっかりと検討を重ねたところです。あるいはダンスといったものに使えるように鏡を設置したりということで、幅広い年齢層の方にも使っていただけるような施設にするという変更内容で…","id":"exchange-041"},{"speaker":"安藤委員","kind":"質問・要望","question":"そういうのを想像してしまうものですから、私たちも一般質問で質問しましたけれども、当然そういうものを優先すべきだと思ってしまうのです。９ページですけれども、そこを実際に定期的に活用する団体の方々の代替地は、どのように考えておられるのか伺います。","respondent":"吉岡政策推進担当課長","answer":"それぞれの得意分野に応じた就労体験の場が提供できるといったところから、障害者就労支援というキーワードが出て検討してきたものです。ただ、それ以外の関係施設の空き状況なども提供させていただきながら、引き続き対応していきたいと考えております。","id":"exchange-042"},{"speaker":"安藤委員","kind":"質問・要望","question":"それで、冒頭に杉並区の施設の感想を述べさせていただきましたけれども、品川区のコンセプトの根底には区民の要望があるわけです。私は今からでもＰＦＩによる施設整備は取りやめて、区が責任を持って整備すべきだと思いますので、これは意見として述べします。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-043"},{"speaker":"新妻委員","kind":"質問・要望","question":"その辺りがどうなっているのか、もし屋根がないのであれば、そこはしっかりとつけていただきたいということを要望します。３ページの事業の全体像の中で、超短時間就労の位置づけがないのですけれども、ここのどこに入っていくのか教えてほしいと求めました。","respondent":"吉岡政策推進担当課長","answer":"今、前のリボンのところもまだ稼働して間もないので、そこでどうやってすみ分けができるかは引き続き検討してまいります。建築基準も含めながら、検討をさせていただければと思います。","id":"exchange-044"},{"speaker":"あくつ委員","kind":"提案","question":"幾つか具体的に伺っていくのですけれども、５室、複数の多目的ルームを整備する。前にも伺った図書館を中心にというところでの、ゆたか図書館は７万冊でしたか、そのまま持ってくるのかどうかとの意見を述べました。","respondent":"吉岡政策推進担当課長","answer":"そういったものは難しいという複数事業者の声もあったのを踏まえまして、事業者それぞれいろいろな提案、考えを持っていらっしゃいます。我々の考えにとらわれず、そういった事業者の提案を求めたいという形で、こういった変更内容にさせていただいたところです。","id":"exchange-045"},{"speaker":"あくつ委員","kind":"提案","question":"それは何かほかに、今回は図書館の、そういったところからの何か新しいご提案は求めないのかというのを１つ。そういった提案、これは質問等でも何回か上げていますけれども、そういったのはどこかその辺りを説明を求めました。","respondent":"吉岡政策推進担当課長","answer":"そういったものを、いわゆる外観・内観も考えております。先ほどらせん階段というお話もありましたけれども、少し似たようなところで言えば、吹き抜け等を用いました開放的な空間を求めています。","id":"exchange-046"},{"speaker":"あくつ委員","kind":"質問","question":"ありましたけれども、子どもたちの意見、それは理解いたしました。そういう方たちはそんなに経済的に豊かなわけではないですから、スタジオなどでも、そこはしっかりと考えてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-047"},{"speaker":"山本委員","kind":"質問・要望","question":"機能確認にもなるのですけれども、契約する期間は１５年ぐらいを想定しているので、金額的な部分でどういう示し方をしていくのか確認です。令和１４年から区が指定管理料を１５年間払うことを前提で考えていくことで、その辺り、事業者にどういった金額を求めていくのか確認させてください。","respondent":"吉岡政策推進担当課長","answer":"１５年間の総事業、こういったものをひっくるめて入札公告で金額を出させていただいて、その金額によって応募していただくことを検討しています。今後、ハードを含めてですけれども、ソフトの部分は検討していきたいと考えております。","id":"exchange-048"},{"speaker":"山本委員","kind":"質問・要望","question":"金額はどのようになっていくのかは、区としての負担がその後どうなっていくのかに関心がございましたので、ご質問させていただいた次第です。その事業者から得られるものを、ほかの図書館にも波及するようなことも考えて、進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-049"},{"speaker":"こしば委員","kind":"質問","question":"私からも、先ほど来質疑がありました多目的室の扱いについてお聞きしたいと思います。ホールとスタジオの２つがそれぞれあって、こちらはあくまでも５つの多目的室全てが、そして鏡が備えられている施設という認識でよろしいか尋ねました。","respondent":"吉岡政策推進担当課長","answer":"小さい部屋として２０m2ずつで、非常に少人数でも使いやすい部屋を計５室ということで整備を考えおります。防音整備、そしてガラス、あと、鏡を備えた施設です。","id":"exchange-050"},{"speaker":"こしば委員","kind":"意見","question":"であるならば、ある程度その定員が、いろいろ人数も差が出てくると思うので、使い勝手はそれほど悪くはないと思います。その辺りはうまく、分けられているのかもしれないですけれども、使い勝手のいいものとしてもらいたいと思いますとの意見を述べました。","respondent":"吉岡政策推進担当課長","answer":"この新しくできる施設につきましても、ＰＦＩ事業と申しながらも、区立施設になります。新しく備える機能だとか、そういったところで別途システムが必要であれば、そういった提案も事業者からいただくと考えております。","id":"exchange-051"},{"speaker":"こしば委員","kind":"質問","question":"スタジオですと、いろいろと持ち運びなどがあって、場合によってはトラックに積み込んで搬入しなければならないような大きなものがあるかもしれない。そういったこともある程度踏まえた上での計画なのか、教えてもらいたいです。","respondent":"吉岡政策推進担当課長","answer":"いわゆる備蓄倉庫といったものも設けて、実際の災害時には、ここから避難物資を各避難所に届けるように想定しています。運用でそれがどれだけ必要かというのはあるのですけれども、そういった使い方をいたしますので、大きな運ぶ車も一定出入りはできると捉えております。","id":"exchange-052"},{"speaker":"まつざわ委員","kind":"質問・要望","question":"１個に集約していくというか、点で施設は考えないで、面で考えていただきたいです。公有地の活用という部分ではすごくいい動きをしていくという期待感がすごくあるので、ぜひ力強い施設整備のこれからも考えていただけたらと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-053"}]},{"id":"topic-02","title":"なぎさ会館跡の暫定活用","agenda":"なぎさ会館跡の暫定活用","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"なぎさ会館の建物ですけれども、耐震化の状況ですとか、継続利用が可能なのかとか、そういった既存躯体の現況について伺いたいというのが２点目です。それと、跡地活用の検討状況はどうなっているのか、いつからどのように検討していくのか伺います。","respondent":"吉岡政策推進担当課長","answer":"令和８年４月１日で築３４年でございまして、直近５か年でも照明の工事ですとか、比較的活用できる施設です。本格活用に向けて検討していく、今の既存躯体あるいは設備の老朽具合を見ながら、本格活用の検討を進めていきます。","id":"exchange-054"},{"speaker":"安藤委員","kind":"質問・要望","question":"検討については、当然ですけれども、地域の方の声をしっかりと伺っていただきたいとお願いします。こちらをぜひやってほしいのですが、ぜひ考えていただきたいのですけれども、いかがか尋ねました。","respondent":"吉岡政策推進担当課長","answer":"品川区よりも遠方の自治体もありますので、そういったところと足並みをそろえて要望するものと考えております。令和６年度の利用率が２６％、令和７年度も９月末ですと１７.６％で、ずっと利用率が落ちている実情もございました。","id":"exchange-055"},{"speaker":"安藤委員","kind":"意見","question":"当時承知しているということでしたので、ぜひ他部署とも連携して、アクセスというのはここだけの話ではないのですけれども、ずっと課題になっていますので、利用等も含めて改善を改めてお願いしたいと思いますとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-056"},{"speaker":"新妻委員","kind":"質問・要望","question":"利用のここのプロセス、ここの備品を災害対策用に使うと決まっていったプロセスを、もう少し詳しく教えていただきたいと思っています。一般の方々も使えるようになっている用途があると思うのですが、今後そこの部分は残していただけるのか、確認をさせてほしいと求めました。","respondent":"吉岡政策推進担当課長","answer":"どのように活用できるかを検討するために、築３４年で、経済性が非常に悪いということがございました。そういった部分は、授乳室の話も含めて、検討していく必要があると考えています。","id":"exchange-057"},{"speaker":"新妻委員","kind":"質問・要望","question":"地元からも少し使いたいというお声もあったと伺っておりますので、その辺りはまたご検討ほしいと求めましたが、１点は無人になるということです。もう１点、最終的に判断がされて、ここの運用に落ち着いたということでよろしいのか尋ねました。","respondent":"吉岡政策推進担当課長","answer":"今の既存施設を含めながら、新しいサービスといったものも含めて、幅広く各庁内から意見を集めています。我々でも検討して、所管に持っていくこともございまして、それから全体調整の中での決定事項です。","id":"exchange-058"},{"speaker":"筒井委員","kind":"質問","question":"災害対策備蓄倉庫として暫定活用されるということで承知しました。先ほどのご質問とかご答弁にあったのですけれども、その雨水放流管事業は今どのような影響があるのか、具体的に説明を求めました。","respondent":"吉岡政策推進担当課長","answer":"そこの部分を今、なぎさ会館が駐車場として使用している、いわゆる土地の交換を行っている状況です。こういったことが解消されないと、なぎさ会館も含めて、区の敷地が一体化で活用できない状況です。","id":"exchange-059"},{"speaker":"筒井委員","kind":"質問","question":"備蓄倉庫として使われているということで、ここを地図で見ると明らかなように、運河に面しているのですけれども、災害時、運河を使って何か備蓄品を運搬するという使い方も想定されているのか尋ねました。","respondent":"吉岡政策推進担当課長","answer":"実際に活用は、地域内輸送拠点である大井競馬場が近くにある、まずは地域内輸送拠点の開設に使うという位置づけになると思います。多様な運搬方法、各輸送体制については、引き続き所管とともに検討していきたいと思います。","id":"exchange-060"},{"speaker":"筒井委員","kind":"質問・要望","question":"そうした水辺活動とかにも活用できないかというお話は私も伺っているので、水辺に面していることも踏まえた検討を行っていただきたいと存じます。これは意見です。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-061"}]},{"id":"topic-03","title":"ふるさと納税寄附金の受入状況および寄附額の見直し","agenda":"ふるさと納税寄附金の受入状況および寄附額の見直し","exchanges":[{"speaker":"安藤委員","kind":"質問","question":"寄附額の相当部分が返礼品の費用で消えてしまうなどの弊害が目立っている中で、この仕組みを見直すなどの制度の改善が必要だと思うのです。国にどんな意見をどのように言っているのかお伺いしたいのと、これまでのそういった働きかけでの一定の成果と捉えているのか伺いたいと思います。","respondent":"宮澤税務課長","answer":"控除額の上限を２割から１割に、募集経費の上限５割の縮小、または自治体への減収部分への財源措置を要望しています。まさに募集経費の上限５割の縮小部分、今回１９３万円が上限になりましたけれども、流出額に一定の抑制効果があるところは出ております。","id":"exchange-062"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/643711?Template=document&Id=7335#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=20&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":69324,"voices":179}},{"id":"r08-20260227-22","meetingId":"r08-1t","date":"2026年2月27日","dateIso":"2026-02-27","committee":"まちづくり・公共交通推進特別委員会","time":"午前１０時００分～午後 ０時０７分","status":"正式会議録","sourceType":"formal","overview":"まちづくり・公共交通推進特別委員会の会議録から、実質的な質問・確認・意見・要望と答弁・対応を35件整理しています。","topics":[{"id":"topic-01","title":"特定事件調査","agenda":"特定事件調査","exchanges":[{"speaker":"田中委員","kind":"確認","question":"特に３月２８日にＯＩＭＡＣＨＩ ＴＲＡＣＫＳが完成してオープンする。これまでの方針と変わるようなことが、考え方が、そこに生じるのかどうかということを確認したいと思います。","respondent":"泉広町事業調整担当課長","answer":"これまで庁舎跡地等活用検討委員会などで、区民ニーズの把握に努めてまいりました。具体の、来年度から策定に着手する予定としています活用プランを策定する中で、議論を進めていければと考えているところです。","id":"exchange-001"},{"speaker":"田中委員","kind":"確認","question":"要は今までの検討状況から大きく方向修正をする可能性もあるような、そこまでの修正というものが可能なのかどうかということはいかがでしょうか。今までの検討委員の方の意見に縛られてしまうのかどうかというところを確認したいと思います。","respondent":"泉広町事業調整担当課長","answer":"今のこの検討から大きく外れていくのかというところですが、やはりこれまで聞いてまいりました内容は、様々な形で集積してきた成果です。一定程度こちらも踏まえながら、今いただいたような広域的な視点も含めて検討を深めていくところです。","id":"exchange-002"},{"speaker":"田中委員","kind":"質問・要望","question":"創出する財源２００億円について、今回の財源、事業費として総額２００億円というようなご説明のように伺ったのです。そもそもの２００億円の金額の出どころや、その試算の根拠、２００億円の根拠というものはどのようなところなのか尋ねました。","respondent":"泉広町事業調整担当課長","answer":"創出を予定しています２００億円の根拠のお話です。この２００億円は、区として検討を進める中で、２００億円の実現性もあるのではないかとなったというところ。","id":"exchange-003"},{"speaker":"田中委員","kind":"質問","question":"この間の石田秀男副委員長のご質問にもあったように、例えば定期借地など、そのようなことも前提にして２００億円ということなのですか。要は、事業形態としては、そこはもう確定しているという前提で、今後プランを考えるものなのか尋ねました。","respondent":"泉広町事業調整担当課長","answer":"２００億円にあまり固執してしまいますと、様々そういった視点での指標を、これから深く検討してまいらないといけないと考えています。定期借地を一定想定しながら今後の検討を進めてまいりますが、今後検討を深める中でしっかり精査をしてまいりたいというところの表現です。","id":"exchange-004"},{"speaker":"田中委員","kind":"質問・要望","question":"私はこの大きな土地、将来最大限有効活用すべき跡地だと考えていますので、発展的な視点でプランをつくっていただきたい。場合によっては２００億円の根拠を区長に伺うということも、一般質問等々になるのか、ぜひ伺いたいなという感想を述べて質問を終わります。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-005"},{"speaker":"石田（秀）副委員長","kind":"提案","question":"一般質問もしたのですが、お聞きをしたいことを伺っていきます。どのような提案が来るか分からないけれども、そのような提案と比較して、どちらがいいですかということはやってもとの意見を述べました。","respondent":"泉広町事業調整担当課長","answer":"駅周辺を入れてまいりますと、今回の範囲につきましては、庁舎の跡地に限って検討を深めていきたいと考えています。しっかり周辺とも連携するというところ、相乗効果をもたらすというようなところにつきましては、今後も引き続き検討してまいりたいです。","id":"exchange-006"},{"speaker":"石田（秀）副委員長","kind":"提案","question":"そのようなことを含めて、私はそういう提案を１回やってもらってはどうかと。このようなことを考えるのであれば、その中で提案をしてもらうことは、７０年先のことを考えたら、私はそれぐらいはやるべきだとの意見を述べました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-007"},{"speaker":"藤原委員","kind":"確認","question":"今委員長、副委員長と理事者の方の質問、答弁を伺ってまいりました。でも、もう一般の方たちにはどのような説明をすればいいのですかということをはっきり教えていただけますか。","respondent":"泉広町事業調整担当課長","answer":"そういった官民連携の事業を進めていくというところ、また、定期借地権を設定しながら民間のほうを誘導していきたいと考えています。来年度から策定をする予定にしています活用プランを策定する中で、皆様とともに議論を進めてまいりたいですので、そういった状況です。","id":"exchange-008"},{"speaker":"藤原委員","kind":"提案","question":"私はきちんと提案をしていくべきだとまず思っていますし、あと「いや、何になるのですかね。その辺のことをきちんと示してくれないと、何かおかしいというか、そのような疑問が出てしまうのですけれども、その辺についてはいかがか尋ねました。","respondent":"泉広町事業調整担当課長","answer":"この間我々もサウンディング調査などを通しまして、民間事業者の方にこういった庁舎跡地の活用検討の状況の区民ニーズなどもお伝えしながら。一定程度、今回は定期借地権の設定を想定しながら、引き続き検討を深めていきたいといったお示しをさせていただきました。","id":"exchange-009"},{"speaker":"石田（秀）副委員長","kind":"提案","question":"２００億円、定期借地とすることを中心にとおっしゃるのであれば、タワーマンション以外どのような方法があるのですか。１,０００人、２,０００人規模ぐらいの、多分提案としては多いわけですとの意見を述べました。","respondent":"泉広町事業調整担当課長","answer":"そういった意見も踏まえまして、我々が今回想定するところは２００億円としながらも、経済効果なども考慮しながらと書かせていただいてあります。精査をしてまいりたいというところのお示しをしているというところでご理解いただければと思ってあります。","id":"exchange-010"},{"speaker":"石田（秀）副委員長","kind":"質問","question":"でも、私は本気で皆さんに考えてほしい。ぜひ。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-011"}]},{"id":"topic-02","title":"「東京における地域公共交通の基本方針」改定に向けた中間まとめ","agenda":"「東京における地域公共交通の基本方針」改定に向けた中間まとめ","exchanges":[{"speaker":"田中委員","kind":"質問","question":"これは基本的には都の施策なので、質問を考えながらお伺いをしたいのですが、最後のまとめのところの広域調整に係る取組の促進というところです。言えるのか、言おうとしているのか、その辺の状況をまずお伺いしたいと思います。","respondent":"櫻木地域交通政策課長","answer":"今回在り方検討会、先ほどご紹介させていただきましたが、構成メンバーとして、品川区も途中から参加させていただいておりましたので、その点から何点かご意見を申し上げたことはあります。","id":"exchange-012"},{"speaker":"田中委員","kind":"質問・要望","question":"いわゆるバス事業者に対しての規制緩和といいますか、理解を求めるということをぜひ東京都からバス事業者にしていただきたいなと。ひいては東京都から理解を求めるような対応をしていただきたいということをぜひ伝えてほしいと求めましたが、いかがか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"区が実施主体として調整に入るというか、もともとの趣旨として、需要を各会社が食い合わないようにするというところがあります。一定民間事業者は主立った路線に力を入れて、そういった文脈の中で、委員がご指摘いただいたようなことも少し話ができるのかなとは思っております。","id":"exchange-013"},{"speaker":"塚本委員","kind":"質問","question":"令和８年度に東京都としての基本方針が改定されたとして、令和２年に定めた基本方針でしたか、そういったものがある。ちょっとこれが定められた後の区としての動きというものがどのように想定されるのかを伺いたいと思います。","respondent":"櫻木地域交通政策課長","answer":"東京都のほうで広域的な交通の考え方を来年度改定するということを踏まえまして、一般質問等でもお答えさせていただいたこともございましたが、今後整理していくことになろうかと思っています。","id":"exchange-014"},{"speaker":"塚本委員","kind":"質問","question":"１０年でこうなります、品川区の現状というか、品川区の状況がきちんとデータとして入ってきているのか。区の実情というものは伝えていただいて、定められていくものということで大丈夫なのかなというところをちょっとお聞きしたいと思います。","respondent":"櫻木地域交通政策課長","answer":"今回の検討会につきまして、令和８年にまたこれの計画を具体的に検討していく会が立ち上がると聞いています。デマンド交通の実証実験をしたりという、参加することになった場合につきましては、そのような声も届けていきたいと思っています。","id":"exchange-015"},{"speaker":"塚本委員","kind":"質問・要望","question":"そのような流れにはなるということで、いずれにしても、しっかりと品川区の実情というものが反映された形にしてほしいと求めました。幾つかきちんとしたものが出るのか心配なところも少しあるので、人口推計の話も含めて、それはよろしくお願いしたいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-016"},{"speaker":"石田（秀）副委員長","kind":"質問・要望","question":"不勉強で教えていただきたいのですが、これはもう何度もお話を伺っていて、入ってくるものが５人しかいない。そして都バスについて、その辺ちょっと分からないのだけれども、その辺の実情をちょっと教えていただきたい。","respondent":"櫻木地域交通政策課長","answer":"運転士の考え方です。定年後の給料が減ることによって運転手の確保が難しくなっているという話は伺ったことがあります。","id":"exchange-017"},{"speaker":"石田（秀）副委員長","kind":"質問","question":"どうも都バスは、相手がお金出してくれるのにやらないとか、何か結構そのようなものが出てきているではないですか。そのようなものをもう少し解決するには、品川区の立場では難しいのかもしれないけれども、方法は何かないのかということをまず聞きたいです。","respondent":"櫻木地域交通政策課長","answer":"現状としては、地方の運転手が都心に来ているという、日本全国での奪い合いになっているような状況という話は聞いたことがあります。社会的な認知度の向上であったり、少しずつ地道な成果を重ねていくことで運転士確保につなげているのかなとは思っているところです。","id":"exchange-018"},{"speaker":"えのした委員","kind":"質問","question":"近隣区だとお隣の大田区が昨年の１月に、羽田イノベーションシティですか、循環バスなど、一般道でも実証運行されたという話も聞いております。２３区、他区、他の自治体でも、やはり自動運転進んでいるのか、品川区での考え、聞いているお話を説明を求めました。","respondent":"櫻木地域交通政策課長","answer":"品川区内で適地を探すとすると、まず広くて歩道が分離されているようなところを探していくのかなと。全く乗らないところに通してもということもありますので、その辺りは他区の状況等見ながら研究していく段階かなと考えています。","id":"exchange-019"},{"speaker":"えのした委員","kind":"意見","question":"そうですね。項番２、（２）のところでも、検討してほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-020"},{"speaker":"若林委員","kind":"質問","question":"２０本未満とか、９本未満とか、品川区としては何か試算をしたのでしょうか。着手しようとしているのか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"現時点で出してもらえないという回答をいただいております。それ以外のところは５０本未満という形で整備されるのかなと考えています。","id":"exchange-021"},{"speaker":"若林委員","kind":"質問・要望","question":"その背景には東京都も手がつけられない、民間バス会社と行政の関係性、本来は、いわゆる官民連携という言い方ですかね。なければ結構です。","respondent":"櫻木地域交通政策課長","answer":"民間事業者との関係というところで、民間事業者の需要を食うことで民間事業者が苦境に立つということを避けるという意味合い。なかなか、今後検討を進める際には、そのような視点もしっかり持って進めたいと考えています。","id":"exchange-022"}]},{"id":"topic-03","title":"令和８年度の地域交通の取り組み","agenda":"令和８年度の地域交通の取り組み","exchanges":[{"speaker":"えのした委員","kind":"提案","question":"荏原はご要望で８時に時間早まりましたけれども、やはりこれ運行９時からになっているので、そこがせっかくなら８時からやらないのかなというところ。アプリ等事業者の提案になるということで、決済方法も変わってしまったりなど、ちょっとその辺でややこしくなるというかとの意見を述べました。","respondent":"櫻木地域交通政策課長","answer":"この大崎地区については大きな病院はないということで、通院の需要があまり見込めないのかなということ。利用者の利便性という観点から、一定配慮して、検討していく点かなと考えています。","id":"exchange-023"},{"speaker":"えのした委員","kind":"確認","question":"確認が取れました。ああ、このようなものはほっとするなと思ったので、またそういったところも進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-024"},{"speaker":"塚本委員","kind":"質問","question":"今１台ですか。お聞きしたかったことは、運転手の稼働率というのか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"運転手の方につきましては、しなるんに従事していただく際は１日しなるんについていただくという形になっておりますので、運行自体が、もし仮に予約が入っていない時間帯は、荏原交通が営業所圏内にありますので、そこで待機していただいているような状況となります。","id":"exchange-025"},{"speaker":"塚本委員","kind":"質問","question":"分かりました。コミュニティバスとはあまり変わらないというように見るのか、やはりそれでも優位性のようなものはあるのかということを教えていただけますか。","respondent":"櫻木地域交通政策課長","answer":"効率性という意味ではなかなか比較が難しい側面もあろうかとは思いますが、基本的には、バスはバスなりの、やはり様々な設備、装置がありますので、その辺りをどう見るかということと、人件費につきましては、タクシー運転手とバス運転手の給与面の違いというところかと思います。","id":"exchange-026"},{"speaker":"塚本委員","kind":"質問・要望","question":"大崎地区についてはコミュニティバスを求める声も結構あったりして、しっかり根づかせていただきたいなとは思っております。説明の１つ、ＡＩオンデマンドを実証運行する上での１つの要素としてはあるかなとも思うので、しっかり進めてほしいと求めました。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-027"},{"speaker":"田中委員","kind":"質問・要望","question":"バス、しなバスに関してお伺いしますが、長年要望したことが実現されたことを高く評価をしたいと思います。要は、そもそも何がここまで実現できない要因だったのか、まず端的にお伺いしたいと思います。","respondent":"櫻木地域交通政策課長","answer":"そのようなところで、既存の路線があるところについて、当初コミュニティバスを運行させる際は、そこを避ける形で路線を設定したです。今回既存路線がなくなったということで、区として使うこと、路線を敷いたです。","id":"exchange-028"},{"speaker":"田中委員","kind":"質問・要望","question":"タイミングとしてはまさにそのとおりだと思っていますし、そうだろうなとは思っています。区から要望したけれども、忖度をしてそもそも要望しなかったのかと、そこはぜひお伺いしたいと思います。","respondent":"櫻木地域交通政策課長","answer":"当然区からは毎年要望して、ご検討いただきたいということを申入れをしてきたような経緯があります。なかなか色よいご返事をいただけなかったという状況であります。","id":"exchange-029"},{"speaker":"田中委員","kind":"質問・要望","question":"それこそ都民ファーストの都知事ですから、都民の要望に沿った路線ができるように、バス事業者に対しても理解を求めていただきたいという旨は。地元の方に喜んでいただいたとか、効率性のいい運行ができたとかという、その辺の結果は何かあるのか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"委員から今ご指摘いただいた、ＡＩの活用としましては最適なルーティング、ルート選定というところと、時間計算等で活用しています。効率的な配車が行われているということで、具体的な事例としてはちょっと挙げられませんが、そのように理解していただければと思います。","id":"exchange-030"},{"speaker":"田中委員","kind":"質問・要望","question":"二丁目、あるいは小山台など、そういった方面からの要望があったのかなかったのか。その辺はいかがか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"はその辺りで、交通利便性のようなところも含めて、どこまで広げるかということを考えていく形になっております。１台で回せる範囲として１.５から２km2という範囲なので、その辺りを勘案した結果、今回はこの形でとしています。","id":"exchange-031"},{"speaker":"田中委員","kind":"質問・要望","question":"それで、両者間の利用というものは可能なのでしょうか。今回が２.０とすると、２.５ぐらいで、いかがか尋ねました。","respondent":"櫻木地域交通政策課長","answer":"まず今回につきましては、物理的にも地理的にもつながっていないエリアになっておりますので、そのような形で運行させていただきたいと考えています。将来的に区全体の交通の在り方を考えていく上で、どのような使い方をしていくかということは１つの検討ポイントかとは思います。","id":"exchange-032"},{"speaker":"松本委員","kind":"質問","question":"１つＡＩの強みでもあるのかなと思うのですが、今後そうした発展的な考え方に至る可能性というものはあるのでしょうか。お願いします。","respondent":"櫻木地域交通政策課長","answer":"そのような一定の検討の中で、先ほど人件費の話がありましたけれども、コストがかなりかかってしまうというところがございました。今のところ夜間走ってほしいという声はほとんど届いていない状況でして、夕方の時間帯については現在の運行を維持するという判断で対応しています。","id":"exchange-033"},{"speaker":"松本委員","kind":"質問・要望","question":"きちんと需要と供給を見ながら、対応いただきたい。そこはこれから、来年度などというところではなく、今後の公共交通の在り方をぜひ研究していただきたいなと要望したいと思います。","respondent":"","answer":"この発言に対する個別の答弁・回答は、会議録に記録されていません。","id":"exchange-034"},{"speaker":"若林委員","kind":"確認","question":"いわゆる法令的な縛りなのかという確認と、それを前提にすると、これは今、想定エリアは円で１点、コンパスで１.５kmでぐるっとした形。現段階での考えをお聞きしたいということが１つと、あとは確認ですけれども、どのような設定になるのか説明を求めました。","respondent":"櫻木地域交通政策課長","answer":"ミーティングポイントの考え方ですが、この辺りを押さえてあげて、それは評価しますよというような形で選定を進めていこうと考えています。参考として、それを踏まえて、事業者が創意工夫を凝らした提案をしていただけると認識しております。","id":"exchange-035"}]}],"links":[{"type":"minutes","label":"公式の会議録を読む","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/931508?Template=document&Id=7337#one"},{"type":"official","label":"公式の会議録一覧","url":"https://kaigiroku.city.shinagawa.tokyo.jp/index.php/100000?QueryType=new&Template=list&Cabinet=22&TermStart=2026-01-01&TermEnd=2026-12-31"}],"sourceMeta":{"pages":0,"characters":39509,"voices":101}}]);
